import { useState, useEffect } from "react";

const EXAM_2024 = [{"n":1,"q":"A 34-year-old female with intellectual disability, hypothyroidism, and bipolar disorder presents for routine follow-up. Her case worker notes that she has been excessively thirsty and urinating more than usual over the past several months despite limiting her fluids. She also wakes at night to urinate. Laboratory studies prior to her visit reveal a therapeutic lithium level, as well as normal creatinine, electrolyte, and blood glucose levels. Which one of the following is most likely present in this patient\u2019s case?","o":[{"l":"A","t":"Diabetes insipidus"},{"l":"B","t":"Interstitial cystitis"},{"l":"C","t":"Overactive bladder"},{"l":"D","t":"Psychogenic polydipsia"},{"l":"E","t":"Syndrome of inappropriate antidiuretic hormone secretion"}],"a":"A","e":"This patient is at risk for both psychogenic polydipsia due to intellectual disability and\nnephrogenic diabetes insipidus due to lithium therapy. The combination of ongoing\npolydipsia, polyuria despite fluid restriction, and nocturia suggests diabetes insipidus\nrather than psychogenic polydipsia. Diabetes insipidus is a loss of free water in the\nurine due to a lack of antidiuretic hormone (central) or insensitivity to antidiuretic\nhormone in the kidney (nephrogenic). Interstitial cystitis and overactive bladder can\ncause urinary frequency but not polydipsia. Syndrome of inappropriate antidiuretic\nhormone secretion (SIADH) is associated with a low sodium level and does not cause\npolyuria.\nReference\nLevy M, Prentice M, Wass J. Diabetes insipidus. BMJ. 2019;364:l321."},{"n":2,"q":"A 70-year-old female sees you at the request of her surgeon to discuss anticoagulation management prior to a scheduled cholecystectomy. She has a past medical history of atrial fibrillation, stage 3a chronic kidney disease, hypertension, depression, and cerebrovascular disease. She had an ischemic stroke 1 year ago. Her current medications include the following: Amlodipine (Norvasc) Losartan (Cozaar) Metoprolol succinate (Toprol-XL) Sertraline (Zoloft) Warfarin Her vital signs include a blood pressure of 140/82 mm Hg, a heart rate of 90 beats/min, and an oxygen saturation of 96% on room air. A cardiovascular examination reveals an irregularly irregular rhythm. The remainder of the examination findings are unremarkable. An INR today is 2.2. Which one of the following would be the most appropriate perioperative anticoagulation therapy for this patient?","o":[{"l":"A","t":"Continuing warfarin with a goal INR of 1.4\u20131.6"},{"l":"B","t":"Discontinuing warfarin 5 days prior to surgery and bridging with aspirin"},{"l":"C","t":"Discontinuing warfarin 5 days prior to surgery and bridging with clopidogrel (Plavix)"},{"l":"D","t":"Discontinuing warfarin 5 days prior to surgery and bridging with low-molecular-weight heparin"},{"l":"E","t":"Discontinuing warfarin 5 days prior to surgery without bridging therapy"}],"a":"E","e":"Continuing warfarin is not recommended prior to elective procedures or surgeries in\npatients who are taking warfarin for stroke prevention secondary to atrial fibrillation.\nThe BRIDGE trial excluded patients who had an ischemic stroke within the previous 12\nweeks but included those with more distant strokes. For such patients, cessation of\nwarfarin without bridging with low-molecular-weight heparin or antiplatelet agents is\nthe appropriate management strategy. There is no evidence that using a lower target\nINR is appropriate.\nReference\nDouketis JD, Spyropoulos AC, Murad MH, et al. Perioperative management of\nantithrombotic therapy: an American College of Chest Physicians clinical practice\nguideline. Chest. 2022;162(5):e207-e243."},{"n":3,"q":"A 30-year-old female with obesity and tobacco use disorder presents for evaluation of a persistent painful lump in her axilla. After an appropriate evaluation you diagnose mild hidradenitis suppurativa. In addition to weight loss and smoking cessation counseling, which one of the following treatment options would be most appropriate?","o":[{"l":"A","t":"Topical clindamycin gel (Cleocin T)"},{"l":"B","t":"Topical diclofenac gel"},{"l":"C","t":"Topical triamcinolone cream"},{"l":"D","t":"Oral azithromycin (Zithromax)"},{"l":"E","t":"Oral meloxicam"}],"a":"A","e":"For patients with mild hidradenitis suppurativa, topical clindamycin is recommended as\nfirst-line treatment and often works well as monotherapy (SOR B). Patients with\nhidradenitis suppurativa who have overweight and smoke should be advised that weight\nloss and smoking cessation have been shown to decrease severity of disease and\nimprove treatment response (SOR A). For patients with moderate disease, oral\ntetracyclines in addition to topical clindamycin are recommended as first-line therapy.\nAlthough intralesional triamcinolone may be considered for procedural management of\nmild hidradenitis suppurativa, topical triamcinolone is not recommended. Other oral\nantibiotics that have shown benefit include clindamycin and rifampin, although\nazithromycin is not a recommended treatment option. While NSAIDs such as topical\ndiclofenac and oral meloxicam may help to alleviate discomfort associated with active\nlesions, they are not part of the routine management of hidradenitis suppurativa.\nReference\nWipperman J, Bragg DA, Litzner B. Hidradenitis suppurativa: rapid evidence review. Am\nFam Physician. 2019;100(9):562-569."},{"n":4,"q":"A 48-year-old female with a history of ductal carcinoma in situ diagnosed in her early 40s presents to the urgent care clinic because of heavy vaginal bleeding. The bleeding started 8 days ago as a regular menstrual period, but it has worsened and today she started passing clots. She does not take any medications. You estimate her blood loss to be >100 mL today. On examination she has a blood pressure of 114/65 mm Hg and a pulse rate of 84 beats/min. The uterus is slightly enlarged with red blood in the os, but the examination findings are otherwise normal. A CBC is significant for a hemoglobin level of 8.2 g/dL (N 12.0\u201316.0) and a normal platelet count. An hCG test is negative. Which one of the following would be the most appropriate therapy at this time?","o":[{"l":"A","t":"Oral high-dose progestins"},{"l":"B","t":"Depot medroxyprogesterone acetate (Depo-Provera CI)"},{"l":"C","t":"Intravenous conjugated estrogen"},{"l":"D","t":"Intravenous ketorolac"},{"l":"E","t":"Intravenous tranexamic acid"}],"a":"E","e":"Intravenous tranexamic acid is an appropriate therapeutic option to manage acute\nbleeding in this hemodynamically stable patient with acute severe uterine bleeding.\nIntravenous conjugated estrogen is recommended in patients who are hemodynamically\nunstable. Depot medroxyprogesterone acetate and NSAID therapies are recommended\nfor chronic management. A history of ductal carcinoma in situ is a contraindication for\nboth progestin and estrogen therapy. Estrogens or tranexamic acid should be avoided\nin patients with a high thrombosis risk.\nReference\nWouk N, Helton M. Abnormal uterine bleeding in premenopausal women. Am Fam\nPhysician. 2019;99(7):435-443."},{"n":5,"q":"A 30-year-old female with a medical history of anxiety and seasonal allergies presents for evaluation of palpitations and a racing heartbeat that has worsened over the last 3\u20134 days. Recently, her escitalopram (Lexapro) dosage was increased to 20 mg daily and she started using fluticasone propionate nasal spray (Flonase) and oral cetirizine (Zyrtec), 10 mg daily. A CBC, comprehensive metabolic panel, and TSH level are normal. A urine pregnancy test is negative. An EKG today shows a heart rate of 85 beats/min and a QTc interval of 500 milliseconds. Which one of the following would be the most appropriate next step?","o":[{"l":"A","t":"Reassurance only"},{"l":"B","t":"Discontinuing cetirizine"},{"l":"C","t":"Discontinuing escitalopram"},{"l":"D","t":"Discontinuing fluticasone"},{"l":"E","t":"Echocardiography"}],"a":"C","e":"This patient\u2019s EKG shows a prolonged QTc interval (>460 milliseconds for women). QT\nprolongation can indicate polymorphic ventricular tachycardia characterized by\npalpitations. QT prolongation can be congenital or acquired. Escitalopram and other\nantidepressants are associated with QT prolongation. Any QT-prolonging medications\nshould be discontinued, and a subsequent EKG should be obtained once the drug levels\nare expected to be minimal.\nReassurance only would not be the most appropriate next step as QT prolongation can\nlead to torsades de pointes, a potentially fatal arrhythmia (SOR C). Cetirizine and\nfluticasone are not known to prolong the QT interval. Echocardiography would not be\nthe next step in management.\nReferences\nKandiah JW, Blumberger DM, Rabkin SW. The fundamental basis of palpitations: a\nneurocardiology approach. Curr Cardiol Rev. 2022;18(3):e090921196306.\nKhatib R, Sabir FRN, Omari C, Pepper C, Tayebjee MH. Managing drug-induced QT\nprolongation in clinical practice. Postgrad Med J. 2021;97(1149):452-458.\nRunser LA, Gauer RL, Houser A. Syncope: evaluation and differential diagnosis. Am Fam\nPhysician. 2017;95(5):303-312.\nWexler RK, Pleister A, Raman SV. Palpitations: evaluation in the primary care setting.\nAm Fam Physician. 2017;96(12):784-789."},{"n":6,"q":"Which one of the following medications has been shown to increase the resolution of metabolic dysfunction\u2013associated steatotic liver disease (MASLD), formerly known as nonalcoholic fatty liver disease?","o":[{"l":"A","t":"Glyburide"},{"l":"B","t":"Metformin"},{"l":"C","t":"Pioglitazone (Actos)"},{"l":"D","t":"Repaglinide"},{"l":"E","t":"Vitamin D (cholecalciferol)"}],"a":"C","e":"Although lifestyle modification remains the first-line treatment of metabolic dysfunction\u2013\nassociated steatotic liver disease (formerly known as nonalcoholic fatty liver disease),\npioglitazone increases the resolution of nonalcoholic steatohepatitis, especially in\npatients with advanced fibrosis. Pioglitazone may cause weight gain and should be\navoided in patients with heart failure, and it carries a small risk for bladder cancer.\nGlyburide, metformin, repaglinide, and vitamin D (cholecalciferol) do not improve\nsteatohepatitis or fibrosis.\nReference\nArnold MJ. Nonalcoholic fatty liver disease: diagnosis and management guidelines from\nthe AACE. Am Fam Physician. 2023;107(5):554-556."},{"n":7,"q":"A 45-year-old male presents for a health maintenance examination. He has a history of hypertension that is well controlled on lisinopril (Zestril). Based on guidelines from the U.S. Preventive Services Task Force, this patient should be screened for which one of the following?","o":[{"l":"A","t":"Cardiovascular disease with EKG"},{"l":"B","t":"Carotid artery disease with carotid ultrasonography"},{"l":"C","t":"Colon cancer with colonoscopy"},{"l":"D","t":"Prostate cancer with a prostate-specific antigen level"},{"l":"E","t":"Vitamin D deficiency with a vitamin D level"}],"a":"C","e":"The U.S. Preventive Services Task Force recommends screening for colon cancer in\nadults ages 45\u201349 (B recommendation) and ages 50\u201375 (A recommendation). Neither\nscreening for cardiovascular disease with an EKG nor screening for carotid artery\ndisease with carotid ultrasonography in individuals without symptoms is recommended.\nProstate cancer screening with a prostate-specific antigen level can be considered in\nmen ages 55\u201369 after discussion of potential benefits and possible harms (C\nrecommendation) with shared decision-making. There is insufficient evidence to\nrecommend screening for vitamin D deficiency (I recommendation).\nReferences\nUS Preventive Services Task Force. Final recommendation statement: asymptomatic\ncarotid artery stenosis: screening. Updated February 2, 2021.\nUS Preventive Services Task Force. Final recommendation statement: cardiovascular\ndisease risk: screening with electrocardiography. Updated June 12, 2018.\nUS Preventive Services Task Force. Final recommendation statement: colorectal cancer:\nscreening. Updated May 18, 2021.\nUS Preventive Services Task Force. Final recommendation statement: prostate cancer:\nscreening. Updated May 8, 2018.\nUS Preventive Services Task Force. Final recommendation statement: vitamin D\ndeficiency in adults: screening. Updated April 13, 2021."},{"n":8,"q":"Laser-assisted in-situ keratomileusis (LASIK) surgery is performed to treat","o":[{"l":"A","t":"cataracts"},{"l":"B","t":"closed-angle glaucoma"},{"l":"C","t":"myopia"},{"l":"D","t":"presbyopia"},{"l":"E","t":"retinal detachment"}],"a":"C","e":"Laser-assisted in-situ keratomileusis (LASIK) surgery involves the surgical removal of an\nanterior corneal flap, stromal ablation, and replacement of the flap. LASIK and\nphotorefractive keratectomy (PRK) are considered the standard surgical procedures for\nthe correction of myopia and other refractive errors, such as hyperopia and\nastigmatism. Ninety-eight percent of patients achieve a visual acuity of 20/40 or better.\nCommon complications include glare symptoms, dry eye, undercorrection, and\novercorrection. Significant serious complications include keratitis, epithelial ingrowth, or\nflap dissection. Refractive surgery does not correct age-related farsightedness\n(presbyopia), which is due to loss of lens elasticity, rather than a corneal problem.\nLASIK is not used to treat cataracts, closed-angle glaucoma, or retinal detachment.\n\nReference\nWilkinson JM, Cozine EW, Kahn AR. Refractive eye surgery: helping patients make\ninformed decisions about LASIK. Am Fam Physician. 2017;95(10):637-644."},{"n":9,"q":"A 65-year-old female is found to have a T-score of \u20133.3 on a DEXA scan that is performed as part of her Welcome to Medicare evaluation. She has a 30-pack-year smoking history but quit smoking 5 years ago. An examination reveals a thin female but is otherwise unremarkable. A CBC, a comprehensive metabolic panel, and thyroid studies are unremarkable. X-rays reveal evidence of an old compression fracture of the thoracic spine. Which one of the following would be the most appropriate initial treatment?","o":[{"l":"A","t":"Oral alendronate (Fosamax)"},{"l":"B","t":"Oral raloxifene (Evista)"},{"l":"C","t":"Subcutaneous denosumab (Prolia)"},{"l":"D","t":"Subcutaneous teriparatide (Forteo)"},{"l":"E","t":"Intravenous zoledronic acid (Reclast)"}],"a":"D","e":"The diagnosis of osteoporosis can be made with a prior fracture of the hip or spine, or a\nT-score \u2264\u20132.5. A FRAX score \u22653% for hip fracture or \u226520% for major osteoporotic\nfracture is also diagnostic. The usual first-line treatment is an oral bisphosphonate such\nas alendronate or intravenous zoledronic acid. Denosumab would be preferred if the\ncreatinine clearance were less than 30\u201335 mL/min/1.73 m\u00b2.\nPatients such as this one would be considered at very high fracture risk. Diagnostic\ncriteria for this risk category include a T-score <\u20133.0, a FRAX score \u22654.5% for hip\nfracture or \u226530% for major osteoporotic fracture, multiple fractures, fracture within 12\nmonths, or fracture during treatment for osteoporosis. The initial treatment\nrecommendation would be a parathyroid hormone analogue such as teriparatide daily\nfor 2 years.\nRaloxifene is indicated for the prevention of vertebral fractures only. It is useful in\npatients with a history of breast cancer to help decrease the risk for recurrence.\nReference\nHarris K, Zagar CA, Lawrence KV. Osteoporosis: common questions and answers. Am\nFam Physician. 2023;107(3):238-246."},{"n":10,"q":"A 48-year-old female presents to the urgent care clinic approximately 1 hour after spilling hot water on her left forearm while draining pasta. She has a past medical history of type 2 diabetes, hypertension, and major depression. She is not allergic to any antibiotics and is up to date on tetanus vaccination. On examination her vital signs are normal. You determine that she has a partial-thickness (second- degree) burn involving approximately a 4 \u00d7 5-cm area on the posterior and lateral aspects of the left forearm. In addition to oral medications for pain management and topical antiseptics, you should prescribe which one of the following?","o":[{"l":"A","t":"No additional medications"},{"l":"B","t":"Amoxicillin/clavulanate (Augmentin)"},{"l":"C","t":"Clindamycin (Cleocin)"},{"l":"D","t":"Levofloxacin"},{"l":"E","t":"Sulfamethoxazole/trimethoprim (Bactrim)"}],"a":"A","e":"First-degree (superficial) and second-degree (partial-thickness) burns in adults can\nusually be managed in the outpatient setting. Management options include analgesia\nwith anti-inflammatories or opioids if necessary, and topical agents to keep the burn\narea moist. Multiple agents can be used as a topical antiseptic, including silver\nsulfadiazine, honey, and aloe vera. Oral antibiotics are not indicated in the initial\nmanagement unless there are obvious signs of infection.\n\nReferences\nLanham JS, Nelson NK, Hendren B, Jordan TS. Outpatient burn care: prevention and\ntreatment. Am Fam Physician. 2020;101(8):463-470.\nNorman G, Christie J, Liu Z, et al. Antiseptics for burns. Cochrane Database Syst Rev.\n2017;7(7):CD011821."},{"n":11,"q":"Which one of the following medications is most likely to interfere with the results of screening for primary hyperaldosteronism?","o":[{"l":"A","t":"Amlodipine (Norvasc)"},{"l":"B","t":"Hydrochlorothiazide"},{"l":"C","t":"Lisinopril (Zestril)"},{"l":"D","t":"Metoprolol"},{"l":"E","t":"Spironolactone (Aldactone)"}],"a":"E","e":"Primary aldosteronism is a common cause of resistant hypertension, although it is\nlargely underrecognized. Initial screening is accomplished through simultaneous\nmeasurement of plasma aldosterone and renin levels. An elevated plasma aldosterone\nto renin ratio identifies patients with probable aldosteronism who may then undergo\nconfirmatory testing if clinically indicated; in some cases, additional testing is not\nneeded to reach a diagnosis. Medications that most significantly impact the reninangiotensin-aldosterone system, particularly mineralocorticoid receptor antagonists such\nas spironolactone, ideally should be withheld for a minimum of 4 weeks prior to testing\nfor primary aldosteronism. Other antihypertensive medication classes, including ACE\ninhibitors, angiotensin receptor blockers, diuretics, \u03b2-blockers, and dihydropyridine\ncalcium channel blockers, also may interfere with test results, although less significantly\nthan mineralocorticoid receptor antagonists.\nReferences\nHundemer GL, Vaidya A. Primary aldosteronism diagnosis and management: a clinical\napproach. Endocrinol Metab Clin North Am. 2019;48(4):681-700.\nQuencer KB, Rugge JB, Senashova O. Primary aldosteronism. Am Fam Physician.\n2023;108(3):273-277."},{"n":12,"q":"An 80-year-old female presents for follow-up of urge urinary incontinence after having completed a course of pelvic floor physical therapy with minimal improvement. Her medical history includes hyperlipidemia controlled with atorvastatin (Lipitor) and chronic insomnia treated with doxepin (Silenor). A physical examination, basic metabolic panel, and urinalysis are all normal. She requests a trial of a medication for her overactive bladder. Which one of the following would be most likely to improve her symptoms, while minimizing the risk for adverse side effects?","o":[{"l":"A","t":"Conjugated estrogens (Premarin)"},{"l":"B","t":"Duloxetine (Cymbalta)"},{"l":"C","t":"Mirabegron (Myrbetriq)"},{"l":"D","t":"Oxybutynin"},{"l":"E","t":"Tolterodine (Detrol)"}],"a":"C","e":"Pharmacologic options for the treatment of urge incontinence, or overactive bladder\n(OAB), include antimuscarinic medications such as tolterodine and oxybutynin, and \u03b2adrenergic agonists such as mirabegron and vibegron. Antimuscarinic medications\nshould be used with caution in older patients due to high risk for anticholinergic side\neffects such as tachycardia, confusion, constipation, dry mouth, and blurry vision.\nSelective antimuscarinics such as darifenacin and solifenacin are preferred to their\nnonselective counterparts such as oxybutynin and tolterodine due to a lower risk for\ncognitive adverse effects. The risk for anticholinergic side effects also increases for\npatients who are already taking medications with anticholinergic potential such as\ndoxepin, a tricyclic antidepressant that is also used in the treatment of insomnia. \u03b2Agonist\u2013related side effects may include gastrointestinal upset, dizziness, and\nheadache; mirabegron but not vibegron has also been associated with elevated blood\npressure. In general, however, \u03b2-agonists introduce a lower risk for adverse effects\nthan antimuscarinic medications and are preferred for older patients who are at\nincreased risk for anticholinergic side effects.\nIntravaginal estrogen may improve OAB symptoms, but it is not FDA approved for this\nindication. Oral estrogen worsens incontinence and introduces a risk for adverse effects\nrelated to systemic hormone therapy. Duloxetine, an SNRI, has low-level evidence of\nbenefit for stress incontinence but not for urge incontinence.\nReferences\nChapple CR, Cruz F, Cardozo L, et al. Safety and efficacy of mirabegron: analysis of a\nlarge integrated clinical trial database of patients with overactive bladder receiving\nmirabegron, antimuscarinics, or placebo. Eur Urol. 2020;77(1):119-128.\nGemtesa (vibegron) tablets. Prescribing information. US Food and Drug Administration;\nrevised December 2020.\nHu JS, Pierre EF. Urinary incontinence in women: evaluation and management. Am Fam\nPhysician. 2019;100(6):339-348.\nLozano-Ortega G, Walker DR, Johnston K, et al. Comparative safety and efficacy of\ntreatments for overactive bladder among older adults: a network meta-analysis. Drugs\nAging. 2020;37(11):801-816."},{"n":13,"q":"A 63-year-old female with a medical history of hypertension, depression, fibromyalgia, and giant cell arteritis presents with a 3-week history of progressive cough and shortness of breath. She has been taking prednisone for the last 3 months and is tapering the dosage. Her current dosage is 25 mg daily. The patient\u2019s vital signs include a temperature of 38.1 \u00b0C (100.6 \u00b0F), an oxygen saturation of 88% on room air, and a respiratory rate of 28/min. On examination, her lungs are clear, and a chest radiograph shows bilateral perihilar interstitial pulmonary infiltrates. You recommend hospital admission and intravenous antibiotics. Cultures are pending. Which one of the following antibiotic combinations would be the most appropriate initial treatment?","o":[{"l":"A","t":"Azithromycin (Zithromax) and ceftriaxone"},{"l":"B","t":"Levofloxacin and metronidazole"},{"l":"C","t":"Piperacillin/tazobactam (Zosyn) and vancomycin"},{"l":"D","t":"Azithromycin, cefepime, and vancomycin"},{"l":"E","t":"Ceftriaxone, doxycycline, and sulfamethoxazole/trimethoprim"}],"a":"E","e":"Pneumocystis jirovecii pneumonia (PJP), previously known as Pneumocystis carinii\n\npneumonia, is a fungus that causes severe pneumonia in immunosuppressed\nindividuals. It is a classic AIDS-defining illness but can also affect those on prolonged\ncourses of corticosteroids or other forms of immunosuppression. This patient\u2019s\npresentation of notable dyspnea, hypoxia, no focal lung sounds, and bilateral interstitial\ninfiltrates on radiography is consistent with PJP.\nThis patient may also have community-acquired bacterial pneumonia. Antibiotic\ntreatment with sulfamethoxazole/trimethoprim for PJP along with standard antibiotics\nfor bacterial pneumonia should be initiated while additional tests are pending. An\nelevated serum lactate dehydrogenase level has a correlation with PJP, although it has\npoor specificity, especially in those without HIV. Serum \u03b2-glucan is indicative of a fungal\ninfection and can be supportive of a diagnosis of PJP.\nReference\nMorris A, Masur H. Pneumocystis infections. In: Loscalzo J, Fauci AS, Kasper DL, Hauser\nSL, Longo DL, Jameson JL, eds. Harrison's Principles of Internal Medicine. Vol 1. 21st\ned. McGraw-Hill; 2022:1691-1695."},{"n":14,"q":"A 32-year-old female comes to your office with her husband after a recent weeklong episode of elevated mood and energy that meets the diagnostic criteria for a manic episode. They both say that she has never had any episodes of depression, low mood, or anhedonia. This patient\u2019s presentation is most consistent with which one of the following disorders?","o":[{"l":"A","t":"Bipolar I"},{"l":"B","t":"Bipolar II"},{"l":"C","t":"Borderline personality"},{"l":"D","t":"Cyclothymic"},{"l":"E","t":"Disruptive mood dysregulation"}],"a":"A","e":"Bipolar I disorder does not require a history of a major depressive episode and may be\ndiagnosed and treated based on just 1 manic episode. The diagnosis of bipolar II\ndisorder requires at least 1 hypomanic and 1 major depressive episode. Borderline\npersonality disorder may coexist with bipolar I disorder but the diagnosis is based on\nthe presence of unstable personal relationships and severe impulsivity. Cyclothymic\ndisorder presents with a history of both hypomanic and depressive symptoms that do\nnot meet the full criteria for hypomanic or major depressive episodes. Disruptive mood\ndysregulation disorder is a condition diagnosed between the ages of 6 and 18,\ncharacterized by severe recurrent outbursts of temper.\nReference\nAmerican Psychiatric Association. Bipolar and related disorders. In: Diagnostic and\nStatistical Manual of Mental Disorders. 5th ed, text revision. American Psychiatric\nAssociation; 2022:123-154."},{"n":15,"q":"A 35-year-old female presents for evaluation of bilateral breast pain that varies in intensity with her menstrual cycle. She drinks 2 cups of caffeinated coffee per day and does not take any regular medications. Her past medical history is unremarkable and she does not have any family history of breast cancer. A physical examination, including a clinical breast examination, is normal. A urine hCG test is negative. Which one of the following would be the most appropriate next step?","o":[{"l":"A","t":"A trial of dietary caffeine elimination"},{"l":"B","t":"A trial of topical diclofenac"},{"l":"C","t":"Prolactin and TSH levels"},{"l":"D","t":"Ultrasonography"},{"l":"E","t":"Diagnostic mammography"}],"a":"B","e":"Evidence supports the use of topical NSAIDs such as diclofenac for first-line\npharmacologic treatment of both cyclic and noncyclic mastalgia (SOR B). Topical\nNSAIDs are preferred over oral NSAIDs due to lower risk for adverse effects. Although\ncaffeine is commonly cited as a contributing cause of breast pain, randomized,\ncontrolled trials have not demonstrated clear evidence that caffeine avoidance reduces\npain. Patients with galactorrhea should undergo hormone evaluation with measurement\nof prolactin and TSH levels, although hormone evaluation is not indicated for patients\nwith breast pain who present without associated nipple discharge. Patients without a\npalpable mass who present with cyclic breast pain, such as the patient in this scenario,\nare at low risk for breast cancer and do not require imaging.\nReference\nSalzman B, Collins E, Hersh L. Common breast problems. Am Fam Physician.\n2019;99(8):505-514."},{"n":16,"q":"Which one of the following is a possible adverse effect of short-term systemic corticosteroids?","o":[{"l":"A","t":"Hair loss"},{"l":"B","t":"Hyperkalemia"},{"l":"C","t":"Hypoglycemia"},{"l":"D","t":"Hypotension"},{"l":"E","t":"Mood disturbance"}],"a":"E","e":"Even short courses of systemic corticosteroids are associated with many possible\nadverse effects, including mood and sleep disturbance, hyperglycemia, elevated blood\npressure, sepsis, fracture, and venous thromboembolism. Hair loss, hyperkalemia,\nhypoglycemia, and hypotension are not among the side effects of short-term\ncorticosteroid use.\nReference\nDvorin EL, Ebell MH. Short-term systemic corticosteroids: appropriate use in primary\ncare. Am Fam Physician. 2020;101(2):89-94."},{"n":17,"q":"A 32-year-old male comes to your office because of a gradual onset of right ankle pain. He works in a warehouse and walks extensively during his 12-hour shifts. The pain is located on the medial side of the ankle and worsens throughout his shift. His medical history is notable for well-controlled hypertension and a BMI of 39 kg/m2. On examination the patient has difficulty performing the single-limb heel raise test. You note a positive \u201ctoo many toes\u201d sign, as well as pes planus. You diagnose posterior tibial tendinopathy. In addition to arch supports, which one of the following should you recommend next?","o":[{"l":"A","t":"A stretching program"},{"l":"B","t":"Eccentric exercises"},{"l":"C","t":"Oral corticosteroids"},{"l":"D","t":"Corticosteroid injection"},{"l":"E","t":"Percutaneous needle tenotomy"}],"a":"B","e":"Eccentric exercise is recommended over concentric exercise to treat posterior tibial\ntendinopathy. Because tendinopathy is not an inflammatory process, oral corticosteroids\nare not indicated. Corticosteroids injected into the tendon can provide some short-term\nrelief of pain but have the potential to cause tendon rupture. Needle tenotomy is not a\nrecommended treatment for posterior tibial tendinopathy. If the pain persists 3\u20136\nmonths after appropriate conservative management, surgical debridement of the\ntendon may be considered.\n\nReference\nDeu RS, Coslick AM, Dreher G. Tendinopathies of the foot and ankle. Am Fam Physician.\n2022;105(5):479-486."},{"n":18,"q":"A 35-year-old female presents to your clinic with a 5-day history of sinus congestion, postnasal drainage, and a productive cough with clear sputum. She has a history of depression, for which she takes sertraline (Zoloft), and no previous history of respiratory symptoms or diagnoses. She smokes socially. Her vital signs include a blood pressure of 120/70 mm Hg, a heart rate of 87 beats/min, a respiratory rate of 16/min, and an oxygen saturation of 99% on room air. On examination the patient has clear rhinorrhea, posterior pharynx erythema, frontal sinus tenderness to palpation, and clear lung fields. She has recurrent coughing episodes but does not show any signs of respiratory distress. Which one of the following would be the most appropriate treatment?","o":[{"l":"A","t":"Honey"},{"l":"B","t":"Amoxicillin/clavulanate (Augmentin)"},{"l":"C","t":"Dextromethorphan"},{"l":"D","t":"Hydrocodone/homatropine (Hycodan)"},{"l":"E","t":"Prednisone"}],"a":"A","e":"An acute cough is a cough of <3 weeks\u2019 duration in people without asthma and no redflag symptoms of dyspnea or hemoptysis, or systemic symptoms such as fever, weight\nloss, or peripheral edema. Although there is significant use of prescribed and over-thecounter medications by patients, there is limited evidence to support pharmacotherapy\nfor the symptomatic treatment of acute cough. The majority (90%\u201398%) of cases of\nacute cough are viral upper respiratory tract symptoms that resolve within 7\u201310 days.\nSeveral studies have validated the benefits of honey in patients >1 year of age for\nacute viral upper respiratory tract symptoms. Honey has antibacterial and antiviral\nproperties in addition to decreasing mucus production and cough without the potential\nside effects of prescription or over-the-counter cough medications.\nAcute cough is typically caused by viruses and antibiotics are not indicated.\nAntitussives, opioids such as codeine or hydrocodone, inhaled or oral corticosteroids,\ninhaled \u03b2-agonists or anticholinergics, mucolytics, NSAIDs, first-generation\nantihistamines, decongestants, and guaifenesin have significant side-effect profiles and\ndo not decrease illness duration or symptoms in most patients. Dextromethorphan in\nparticular can increase the serotonin effect in patients taking SSRIs, and this patient is\ntaking sertraline.\nReferences\nAbuelgasim H, Albury C, Lee J. Effectiveness of honey for symptomatic relief in upper\nrespiratory tract infections: a systematic review and meta-analysis. BMJ Evid Based\nMed. 2021;26(2):57-64.\nHay AD, Little P, Harnden A, et al. Effect of oral prednisolone on symptom duration and\nseverity in nonasthmatic adults with acute lower respiratory tract infection: a\nrandomized clinical trial. JAMA. 2017;318(8):721-730.\nLarsen P, Ahmed M. Evaluation of biological activities and medicinal properties of honey\ndrops and honey lozenges. Nutrients. 2022;14(22):4738.\n\nMurgia V, Manti S, Licari A, De Filippo M, Ciprandi G, Marseglia GL. Upper respiratory\ntract infection-associated acute cough and the urge to cough: new insights for clinical\npractice. Pediatr Allergy Immunol Pulmonol. 2020;33(1):3-11.\nSmith MP, Lown M, Singh S, et al. Acute cough due to acute bronchitis in\nimmunocompetent adult outpatients: CHEST Expert Panel report. Chest.\n2020;157(5):1256-1265."},{"n":19,"q":"A 44-year-old male with a history of hypertension presents to the urgent care clinic after he was noted to have a blood pressure of 175/105 mm Hg at a workplace screening event. He has not established medical care since relocating last year and has not been taking his previously prescribed medications. His blood pressure in the clinic is 189/119 mm Hg after sitting for 10 minutes and being positioned appropriately. He does not have chest pain, shortness of breath, headache, or vision changes. Physical examination findings are unremarkable. Which one of the following would be the most appropriate next step in management?","o":[{"l":"A","t":"A urine drug screen"},{"l":"B","t":"A stat troponin level"},{"l":"C","t":"Reinitiation of his antihypertensive medication"},{"l":"D","t":"Clonidine, 0.3 mg orally"},{"l":"E","t":"Transfer to the emergency department"}],"a":"C","e":"This patient has severe asymptomatic hypertension, also known as hypertensive\nurgency. This condition is characterized by a systolic blood pressure of >180 mm Hg\nand a diastolic blood pressure of >110 mm Hg, with no evidence of end-organ damage.\nPatients with this condition are often nonadherent to their routine blood pressure\nmedications, and resuming the regimen with close follow-up is the best treatment.\nWhile alcohol, amphetamines, and cocaine can elevate blood pressure, ruling out\nsubstance abuse is not the first step in management. It is extremely rare to find\nabnormalities on an EKG, a chest x-ray, or cardiac markers in asymptomatic patients\nand these diagnostic tests are not recommended. Acute treatment with clonidine or\nother oral agents to lower blood pressure prior to discharge does not improve\noutcomes. Hypertensive urgency does not require the intensive monitoring, intravenous\ntherapy, or advanced testing available at an emergency department.\nReferences\nGauer R. Severe asymptomatic hypertension: evaluation and treatment. Am Fam\nPhysician. 2017;95(8):492-500.\nHanna J, Ghazi L, Yamamoto Y, et al. Excessive blood pressure response to clonidine in\nhospitalized patients with asymptomatic severe hypertension. Am J Hypertens.\n2022;35(5):433-440.\nPatel KK, Young L, Howell EH, et al. Characteristics and outcomes of patients presenting\nwith hypertensive urgency in the office setting. JAMA Intern Med. 2016;176(7):981988.\nViera AJ. Hypertension update: hypertensive emergency and asymptomatic severe\nhypertension. FP Essent. 2018;469:16-19."},{"n":20,"q":"An otherwise healthy 12-year-old is brought to your office by a parent because the child has had an itchy scalp for the last 2 months. The patient has tried multiple dandruff shampoos and is now using tea tree oil without relief. On examination you note several 1- to 2-cm annular lesions on the scalp with small black dots and scale. There is tender lymphadenopathy of the occipital scalp. Which one of the following would be the most appropriate next step?","o":[{"l":"A","t":"Obtaining a scraping for culture"},{"l":"B","t":"Initiating topical fluocinonide solution"},{"l":"C","t":"Initiating topical ketoconazole shampoo"},{"l":"D","t":"Initiating oral itraconazole (Sporanox)"},{"l":"E","t":"Initiating oral terbinafine"}],"a":"E","e":"Pruritic annular scalp lesions with hair loss, scale, and tender lymphadenopathy should\nprompt a diagnosis of tinea capitis, a relatively common pediatric fungal infection with a\nprevalence of 0%\u201319% in school-aged children.\nThe preferred therapy for tinea capitis is oral terbinafine or griseofulvin (SOR B). The\nshortest course is terbinafine at 2 weeks and it is effective for most causes of tinea\ncapitis. Griseofulvin is more expensive and requires a longer course of treatment.\nSecond-line therapies include fluconazole and itraconazole. Depending on the\nformulation, these can require 3\u201312 weeks of treatment.\nFungal cultures can be negative if patients have used emollients or oils in the week\nprior to testing, and waiting for a culture to return will delay treatment. Fluocinonide\nsolution is a treatment for seborrheic dermatitis, eczema, or psoriasis but is ineffective\nin tinea capitis. Treatment with topical antifungals alone is ineffective because topical\ntreatments do not penetrate the hair shafts where the dermatophyte infection occurs.\nHowever, the use of topical antifungals in conjunction with the oral antifungal can\nspeed resolution.\nReferences\nChen X, Jiang X, Yang M, et al. Systemic antifungal therapy for tinea capitis in children.\nCochrane Database Syst Rev. 2016;2016(5):CD004685.\nChoosing wisely recommendations: don't treat tinea capitis with topical medications\nonly. American Family Physician. 2021.\nHeath CR, Usatine RP. Dx across the skin color spectrum: tinea capitis. J Fam Pract.\n2022;71(8):370-371.\nNguyen CV, Collier S, Merten AH, Maguiness SM, Hook KP. Tinea capitis: a singleinstitution retrospective review from 2010 to 2015. Pediatr Dermatol. 2020;37(2):305310."},{"n":21,"q":"Which one of the following is associated with at least 6 months of exclusive breastfeeding in infants?","o":[{"l":"A","t":"Higher incidence of infant peanut allergy"},{"l":"B","t":"Higher infant HDL-cholesterol levels"},{"l":"C","t":"Lower risk for infant atopic dermatitis"},{"l":"D","t":"Lower maternal incidence of endometrial cancer"},{"l":"E","t":"Lower maternal incidence of hypothyroidism"}],"a":"C","e":"Exclusively breastfeeding infants for at least 6 months confers multiple health benefits\nto both the mother and the infant. Breastfeeding persons have decreased risks for\nbreast and ovarian cancers, postpartum depression, hypertension, cardiovascular\ndisease, and type 2 diabetes. Breastfed infants have decreased risks for atopic\ndermatitis and gastroenteritis. Other potential infant benefits, based on observational\nstudies, include lower risks for childhood leukemia, hypertension, obesity, otitis media,\nsudden infant death syndrome, and type 1 and 2 diabetes.\nReference\nWesterfield KL, Koenig K, Oh R. Breastfeeding: common questions and answers. Am\nFam Physician. 2018;98(6):368-376."},{"n":22,"q":"A 30-year-old male comes to your office because of a nonpainful lump in his genitalia that has been present for a few years. He shares that he and his partner have been trying to conceive for 2 years. On examination you note a nontender \u201cbag of worms\u201d mass in the left scrotum. This patient\u2019s condition is concerning for which one of the following reasons?","o":[{"l":"A","t":"It may become painful"},{"l":"B","t":"It may be contributing to his infertility"},{"l":"C","t":"It is associated with a higher risk for testicular cancer"},{"l":"D","t":"It is indicative of an inguinal hernia"},{"l":"E","t":"It requires treatment with antibiotics"}],"a":"B","e":"Varicoceles appear and feel like a \u201cbag of worms\u201d on palpation and are usually located\nin the left scrotum. This condition is benign and does not require treatment. However,\nvaricoceles can cause low sperm count and contribute to infertility. The differential\ndiagnosis of scrotal mass includes varicocele, testicular cancer, epididymitis, inguinal\nhernia, hydrocele, and epidermoid cyst.\nReferences\nButani VRJ. Enlarging scrotal mass. Am Fam Physician. 2022;106(5):571-572.\nLangan RC, Puente MEE. Scrotal masses. Am Fam Physician. 2022;106(2):184-189."},{"n":23,"q":"A previously healthy 38-year-old female presents with an acute onset of near-syncope and shortness of breath. An examination reveals a BMI of 34 kg/m2, a temperature of 36.9 \u00b0C (98.4 \u00b0F), an oxygen saturation of 92% on room air, a respiratory rate of 24/min, a heart rate of 105 beats/min, and a blood pressure of 118/70 mm Hg. She has some tenderness and swelling of her left lower leg. Which one of the following is the most appropriate next step in diagnosis?","o":[{"l":"A","t":"An arterial blood gas measurement"},{"l":"B","t":"A D-dimer level"},{"l":"C","t":"Echocardiography"},{"l":"D","t":"CT angiography of the chest"},{"l":"E","t":"A ventilation-perfusion (V/Q) scan"}],"a":"D","e":"This patient\u2019s case is highly concerning for acute pulmonary embolism. She has a high\n(>50%) pretest probability of a pulmonary embolus based on both the Wells criteria\nand Geneva score. Patients with a high pretest probability of pulmonary embolism\nshould have CT angiography (CTA) as the initial test, while patients with a low to\nintermediate risk should start with a D-dimer level. An arterial blood gas measurement\nmay be helpful but is less likely to yield the specific diagnosis. Echocardiography may be\npart of the evaluation of pulmonary embolus if there are signs of heart strain, but it is\nnot the most appropriate next step. A ventilation-perfusion (V/Q) scan is less sensitive\nand specific than CTA and takes longer to perform, but it would be indicated if CTA is\ncontraindicated or not available.\nReference\nLim W, Le Gal G, Bates SM, et al. American Society of Hematology 2018 guidelines for\nmanagement of venous thromboembolism: diagnosis of venous thromboembolism.\nBlood Adv. 2018;2(22):3226-3256."},{"n":24,"q":"A 64-year-old male with obesity sees you for follow-up. He started semaglutide (Wegovy) 6 months ago and has lost 6% of his starting weight. He has a 1-month history of worsening dizziness upon standing. In addition to semaglutide, his current medications include atorvastatin (Lipitor), escitalopram (Lexapro), and lisinopril (Zestril). You note a fine tremor in his hand when he holds up his phone to show you his home blood pressure readings. On examination his blood pressure while sitting is 112/64 mm Hg. Three minutes after standing, his systolic blood pressure drops by 25 mm Hg and his pulse rate increases by 15 beats/min. A CBC is normal and an EKG shows sinus rhythm. Which one of the following would be the most appropriate next step?","o":[{"l":"A","t":"Discontinuing escitalopram"},{"l":"B","t":"Discontinuing lisinopril"},{"l":"C","t":"Discontinuing semaglutide"},{"l":"D","t":"Adding carbidopa/levodopa (Sinemet)"},{"l":"E","t":"Adding midodrine"}],"a":"B","e":"A >20 mm Hg decrease in systolic blood pressure 3 minutes after moving from supine\nto standing indicates orthostatic hypotension, whereas an increase in pulse rate >0.5\nbpm/mm Hg is consistent with a nonneurogenic cause. This patient has lost a\nconsiderable amount of weight and anti-obesity medications are a common etiology of\nhypotension in this setting. When this occurs, treatments for other comorbidities may\nneed to be adjusted. While midodrine is appropriate to alleviate the symptoms of\northostatic hypotension if no other causes can be found, discontinuing this patient\u2019s\nantihypertensive is a more appropriate first step. Escitalopram is not a common cause\nof orthostatic hypotension. The patient is tolerating semaglutide and losing an\nappropriate amount of weight, so discontinuing it is not an appropriate step. GLP-1\nreceptor agonists can rarely cause a slight increase in heart rate, but not to the degree\nseen here. This patient\u2019s intention tremor is not consistent with Parkinson disease, and\nbeginning carbidopa/levodopa is not appropriate.\nReference\nKim MJ, Farrell J. Orthostatic hypotension: a practical approach. Am Fam Physician.\n2022;105(1):39-49."},{"n":25,"q":"A 69-year-old female comes to your office for a routine health maintenance visit. She drinks 1 glass of wine every night with dinner, walks 30 minutes per day, and does not smoke. Her medical history is significant for knee osteoarthritis. She has never had surgery and does not take any medications except as-needed ibuprofen. On examination she has a BMI of 28 kg/m2, a blood pressure of 112/78 mm Hg, and a heart rate of 82 beats/min. Other than bilateral knee crepitus, the physical examination findings are unremarkable. Laboratory findings include: Total cholesterol 165 mg/dL HDL-cholesterol 32 mg/dL LDL-cholesterol 109 mg/dL Triglycerides 120 mg/dL Hemoglobin A 7.5% 1c Her calculated 10-year risk of cardiovascular disease is 13.2%. In addition to appropriately treating her diabetes mellitus, which one of the following is recommended by the U.S. Preventive Services Task Force regarding statin use in this patient?","o":[{"l":"A","t":"No statin at this time"},{"l":"B","t":"A low-intensity statin"},{"l":"C","t":"A moderate-intensity statin"},{"l":"D","t":"A high-intensity statin"}],"a":"C","e":"According to the U.S. Preventive Services Task Force, statin therapy with a moderateintensity dosage is recommended for primary prevention of cardiovascular disease\n(CVD) in adults 40\u201375 years of age with a CVD risk of \u226510% with 1 or more CVD risk\nfactors such as diabetes mellitus, hypertension, dyslipidemia, or smoking tobacco (B\nrecommendation). Not initiating statin therapy increases the cardiovascular risk for this\npatient with identified CVD risk factors. Initiating low-intensity statin therapy is not\nsufficient. This patient does not have any additional risk factors that would require a\nhigh-intensity statin and her calculated 10-year risk of CVD is <20%.\nReference\nUS Preventive Services Task Force. Final recommendation statement: statin use for the\nprimary prevention of cardiovascular disease in adults: preventive medication. August\n23, 2022."},{"n":26,"q":"A 53-year-old female sees you for follow-up of an emergency department (E visit for abdominal pain. CT of the abdomen in the ED did not identify the cause of her pain but did reveal a 3-cm homogeneous right adrenal mass. Her abdominal pain has since resolved. Her medical history includes stage 2 hypertension, prediabetes, menopause, and moderate obesity with a BMI of 35 kg/m2. She does not have any history of malignancy and is up to date on mammography and colon cancer screenings. According to the American College of Radiology and the American Association of Clinical Endocrinology, which one of the following would be the most appropriate next step regarding this patient\u2019s adrenal mass?","o":[{"l":"A","t":"Reassurance and no further evaluation unless symptoms develop"},{"l":"B","t":"Repeating CT with adrenal protocol in 1 year"},{"l":"C","t":"Ordering a 1-g dexamethasone suppression test and, if normal, repeating CT imaging in 6 months"},{"l":"D","t":"Ordering urine metanephrines and, if normal, recommending CT-guided biopsy"},{"l":"E","t":"Ordering adrenal MRI and biochemical testing for evidence of adrenal hyperfunctioning"}],"a":"E","e":"As the number of cross-sectional imaging studies has increased, so have incidental\nfindings. This often creates a dilemma for primary care physicians as they guide their\npatients toward the most appropriate follow-up of these findings. Adrenal gland\nincidentalomas are particularly common and concerning as even benign lesions may\nhave hormonal activity. The most current recommendations from the American\nAssociation of Clinical Endocrinology and the American College of Radiology suggest\nthat all patients with masses >1 cm should be tested for autonomous cortisol secretion\nand that patients without a history of malignancy who have lesions >2 cm and <4 cm\non initial imaging should have adrenal-specific imaging via either CT or MRI. This\npatient\u2019s history of hypertension, obesity, and prediabetes would also result in a\nrecommendation for testing to rule out hyperaldosteronism.\nReassurance or repeating the study in 1 year would not be appropriate for this\nparticular lesion. Biochemical studies for pheochromocytoma are unnecessary in this\npatient unless there is clinical suspicion or the dedicated study demonstrates\ncharacteristics that make the condition likely. Biopsy of the gland would be appropriate\nonly if suspicious characteristics were identified on adrenal-specific imaging and would\ngenerally be done as a surgical procedure, not a needle biopsy.\n\nReferences\nExpert Panel on Urological Imaging; Mody RN, Remer EM, et al. ACR appropriateness\ncriteria adrenal mass evaluation: 2021 update. J Am Coll Radiol. 2021;18(11S):S251S267.\nVaidya A, Hamrahian A, Bancos I, Fleseriu M, Ghayee HK. The evaluation of incidentally\ndiscovered adrenal masses. Endocr Pract. 2019;25(2):178-192."},{"n":27,"q":"A 30-year-old soccer player presents with a hyperextension injury of his right wrist after falling and landing on his outstretched hand. On examination the wrist is swollen and tender over the anatomic snuffbox. A plain radiograph shows soft tissue swelling. In addition to ice and elevation, which one of the following is the most appropriate initial treatment?","o":[{"l":"A","t":"Gutter splint"},{"l":"B","t":"Thumb spica splint"},{"l":"C","t":"Volar splint"},{"l":"D","t":"Short arm cast"},{"l":"E","t":"Long arm cast"}],"a":"B","e":"The patient should be presumed to have a scaphoid fracture and treated with a thumb\nspica splint for up to 8 weeks. An initial plain radiograph may be normal in up to 20%\nof scaphoid fractures. Radiography can be repeated in 2 weeks if the wrist remains\ntender. A gutter splint, volar splint, short arm cast, and long arm cast would not be\nappropriate for treatment of a scaphoid fracture.\nReference\nEiff MP, Hatch R. Fracture Management for Primary Care. 3rd ed. Elsevier Saunders;\n2018:84-90."},{"n":28,"q":"A 33-year-old gravida 1 para 1 presents to your office requesting contraceptive management. She recently experienced an acute stroke due to a hypertensive emergency. She is not interested in permanent sterilization at this time and asks your advice regarding the most appropriate contraception given her medical history. Which one of the following contraceptive options would be safest for this patient?","o":[{"l":"A","t":"A combined oral contraceptive"},{"l":"B","t":"A progestin-only oral contraceptive"},{"l":"C","t":"Depot medroxyprogesterone acetate (Depo-Provera CI)"},{"l":"D","t":"A copper IUD (Paragard)"},{"l":"E","t":"A levonorgestrel IUD (Mirena)"}],"a":"D","e":"The 2016 U.S Medical Eligibility Criteria for Contraceptive Use was developed to assist\nproviders in determining the safest forms of contraception for patients with certain\nhealth conditions and characteristics, and was updated in 2020 to address\ncontraception use for women at high risk for HIV. In this case, a woman in her 30s\ndesires reversible contraception following an acute stroke in the setting of hypertension.\nFor a person with a history of stroke, combined hormonal contraception carries\nunacceptable health risks and should not be used. Use of a progestin-containing pill,\ninjection, or subdermal implant carries risks that usually outweigh the benefits. Use of a\nlevonorgestrel IUD carries risks, but the benefit outweighs the risk. However, only a\ncopper IUD has no restriction on use and is considered the safest contraceptive option.\nReference\nReproductive health: US Medical Eligibility Criteria for contraceptive use, 2016 (US\nMEC). Centers for Disease Control and Prevention. Last reviewed March 27, 2023."},{"n":29,"q":"A 60-year-old female presents to your office with a 5-day history of pain inside her mouth. She has a medical history of hypertension, dyslipidemia, asthma, and hypothyroidism. A physical examination reveals several patches of white plaques in her mouth. You scrape the plaques off with a tongue depressor and find inflamed, erythematous tissue under them. Which one of the following medications, if included in this patient\u2019s regimen, may have contributed to the development of this condition?","o":[{"l":"A","t":"Atorvastatin (Lipitor)"},{"l":"B","t":"Beclomethasone dipropionate (Qvar RediHaler)"},{"l":"C","t":"Ipratropium bromide (Atrovent)"},{"l":"D","t":"Isosorbide mononitrate"},{"l":"E","t":"Losartan/hydrochlorothiazide (Hyzaar)"}],"a":"B","e":"This patient has oral candidiasis and requires treatment with an antifungal. Medications\nassociated with this diagnosis include antibiotics and inhaled corticosteroids. Additional\nrisk factors include immunocompromise, diabetes mellitus, malnourishment, and use of\ndentures. If the lesions do not resolve with 2\u20133 weeks of treatment, a biopsy should be\nperformed to rule out precancerous or cancerous findings.\nReference\nRandall DA, Wilson Westmark NL, Neville BW. Common oral lesions. Am Fam Physician.\n2022;105(4):369-376."},{"n":30,"q":"A 65-year-old male presents to the emergency department with a large amount of painful hematochezia over the last 24 hours. His medical history is significant for chronic, generalized osteoarthritis, for which he takes the maximum daily dosage of ibuprofen. The patient is noticeably pale. On examination he has a blood pressure of 80/40 mm Hg and a pulse rate that is 135 beats/min and regular. An abdominal examination is remarkable for diffuse tenderness over the umbilical area. Bowel sounds are hyperactive. There is no significant abdominal distention. Aggressive fluid resuscitation and transfusions are initiated. The gastroenterologist thinks that it is unsafe to proceed with endoscopy, given the patient's current medical instability. Which one of the following would be most appropriate to perform instead of endoscopy?","o":[{"l":"A","t":"Radiography of the abdomen"},{"l":"B","t":"Ultrasonography of the abdomen"},{"l":"C","t":"CT angiography of the abdomen and pelvis"},{"l":"D","t":"Technetium Tc 99m\u2013labeled red blood cell scintigraphy"},{"l":"E","t":"Laparoscopy"}],"a":"C","e":"Colonoscopy is the gold standard for isolating the source of gastrointestinal bleeding.\nHowever, this patient is too unstable to tolerate the risk of colonoscopy. The most\nappropriate option is CT angiography of the abdomen and pelvis to determine the\nsource of bleeding.\nBoth radiography and ultrasonography of the abdomen would be nonspecific and\nnondiagnostic. Compared to CT angiography, technetium Tc 99m\u2013labeled red blood cell\nscintigraphy is less preferred to isolate the source of bleeding. Laparoscopy would be\ntoo invasive and risky in this patient, and would likely not isolate the source of bleeding.\nReferences\nHawks MK, Svarverud JE. Acute lower gastrointestinal bleeding: evaluation and\nmanagement. Am Fam Physician. 2020;101(4):206-212.\nSengupta N, Feuerstein JD, Jairath V, et al. Management of patients with acute lower\ngastrointestinal bleeding: an updated ACG guideline. Am J Gastroenterol.\n2023;118(2):208-231.\nShah AR, Jala V, Arshad H, Bilal M. Evaluation and management of lower\ngastrointestinal bleeding. Dis Mon. 2018;64(7):321-332."},{"n":31,"q":"A patient presents with right-sided facial weakness. You suspect Bell palsy, but an assessment suggests a central brain lesion. A central brain lesion would result in which one of the following findings on the affected side?","o":[{"l":"A","t":"Ability to wrinkle the forehead"},{"l":"B","t":"Inability to close the eye"},{"l":"C","t":"Normal extraocular movements"},{"l":"D","t":"Flattening of the nasolabial fold"},{"l":"E","t":"Drooping of the mouth"}],"a":"A","e":"Patients with Bell palsy present with acute weakness or paralysis of the face caused by\ndysfunction of peripheral cranial nerve VII (the facial nerve). A central lesion should be\nsuspected if the patient is able to wrinkle the forehead on the affected side during the\nexamination. This is also true if the patient is able to close both eyes tightly.\nWhile central nervous system lesions such as multiple sclerosis, stroke, or tumor can\nalso cause facial nerve palsy, some motor neurons to the forehead cross sides at the\nlevel of the brain stem, so the fibers in the facial nerve going to the forehead come\nfrom both cerebral hemispheres. Therefore, central lesions affecting the facial nerve will\nnot paralyze the forehead on the affected side. This causes unilateral facial paralysis\nwith sparing of the forehead.\nExpected findings on the affected side in Bell palsy include inability to close the eye,\nnormal extraocular movements, flattening of the nasolabial fold, and drooping of the\nmouth.\nReference\nDalrymple SN, Row JH, Gazewood J. Bell palsy: rapid evidence review. Am Fam\nPhysician. 2023;107(4):415-420."},{"n":32,"q":"A 54-year-old female with Hashimoto thyroiditis sees you for follow-up. She does not report any clinical symptoms, but her TSH level is <0.1 \u03bcU/mL (N 0.5\u20135.0) and her free T level is elevated at 4 1.9 ng/dL (N 0.6\u20131.6). Her only medication is levothyroxine (Synthroid), and she reports taking more than the prescribed dosage to help with weight loss. You tell her that this may have several dangerous outcomes. Which one of the following adverse reactions is the most likely to occur with misuse of this medication?","o":[{"l":"A","t":"Atrial fibrillation"},{"l":"B","t":"Exophthalmos"},{"l":"C","t":"Goiter"},{"l":"D","t":"Seizure"},{"l":"E","t":"Tetany"}],"a":"A","e":"Thyrotoxicosis secondary to the overuse of thyroid hormone, as with other causes of\nhyperthyroidism, has significant adverse effects, including weight loss, diarrhea, and\nloose stools and more concerning adverse effects including osteoporosis, atrial\nfibrillation, and, more rarely, high-output heart failure related to the thyroid hormone\nreceptors in bone and heart tissue. Atrial fibrillation may be present in 10%\u201325% of\npatients with thyrotoxicosis. Even subclinical hyperthyroidism has been associated with\na significantly higher risk for atrial fibrillation. Exophthalmos and goiter do not occur\nbecause they are not caused by the thyroid hormone itself. Seizure and tetany are not\nknown effects of thyrotoxicosis.\nReferences\nBiondi B, Cooper DS. Subclinical hyperthyroidism. N Engl J Med. 2018;378(25):24112419.\nLee SY, Pearce EN. Hyperthyroidism: a review. JAMA. 2023;330(15):1472-1483."},{"n":33,"q":"Which one of the following community design features can be used to encourage people to walk more?","o":[{"l":"A","t":"Frequently sought destinations (eg, school, work, stores) located at least 1 mile away from residential areas"},{"l":"B","t":"High-quality public transit systems"},{"l":"C","t":"High-speed roadways that route traffic through neighborhoods"},{"l":"D","t":"Moving sidewalks and escalators"}],"a":"B","e":"Public transportation systems encourage users to walk to stops or through stations, and\npeople are more likely to use public transportation if it is designed to be comfortable\nand convenient. In contrast, research has shown that people are less likely to walk\nwhen everyday destinations are located more than a half-mile away from home. Safety\nconcerns can be a barrier to walking, and high-speed roadways in neighborhoods\nincrease pedestrian risk. Convenient alternatives, such as moving sidewalks and\nescalators, also discourage walking.\nReference\nOffice of the Surgeon General (US). Step It Up! The Surgeon General's Call to Action to\nPromote Walking and Walkable Communities. Washington (DC): US Department of\nHealth and Human Services; 2015."},{"n":34,"q":"A 60-year-old transgender female comes to your office for a preventive care visit. You review her organ inventory and note that she has hormonally augmented breast tissue; a vulva and a vagina that were constructed via the penile inversion technique, including an orchiectomy; and a prostate. Her BMI is 23 kg/m2. She does not have any significant medical history other than the gender-affirming procedures and her only medication is a transdermal estradiol patch (Climara), 0.05 mg weekly. She is monogamous with her cisgender female partner and has never smoked. Based on U.S. Preventive Services Task Force guidelines, which one of the following preventive care options should be discussed at this time?","o":[{"l":"A","t":"A digital rectal examination"},{"l":"B","t":"An anal Papanicolaou smear"},{"l":"C","t":"Prostate-specific antigen testing"},{"l":"D","t":"Mammography"},{"l":"E","t":"Bone density screening"}],"a":"C","e":"Transgender women who have undergone vaginoplasty retain the prostate, located\nanterior to the vagina at the base of the bladder. The prostate is likely to be very small\nas a result of estradiol therapy and testosterone suppression, and palpation of the\nprostate through the anterior vaginal wall would be difficult. However, given the\npreservation of this gland, it is reasonable to offer PSA screening after discussing the\nsensitivity, specificity, risks, and benefits.\nDigital rectal examinations are not recommended for screening. Currently, there are no\nguidelines for anal Papanicolaou screening.\nThe U.S. Preventive Services Task Force (USPSTF) recommends mammography for\npersons who were assigned female at birth. There is limited data to support\nmammography in transgender women with breast tissue because their breast cancer\nrisk is likely similar to that of cisgender men. It would be reasonable to acknowledge\nthe presence of this tissue and discuss the sensitivity, specificity, risks, and benefits of\nmammography with this patient, but the USPSTF does not have a stated\nrecommendation for or against this screening.\nBone density screening for cisgender women at normal risk is suggested at age 65, but\nthere are no guidelines for such screening in transgender women, although this patient\ncould be considered at additional risk because she is agonadal.\n\nReferences\nBachman E, Travison TG, Basaria S, et al. Testosterone induces erythrocytosis via\nincreased erythropoietin and suppressed hepcidin: evidence for a new\nerythropoietin/hemoglobin set point. J Gerontol A Biol Sci Med Sci. 2014;69(6):725-735.\nColeman E, Radix AE, Bouman WP, et al. Standards of care for the health of\ntransgender and gender diverse people, version 8. Int J Transgend Health.\n2022;23(suppl 1):S1-S259.\nDeutsch MB. Guidelines for the primary and gender-affirming care of transgender and\ngender nonbinary people; 2nd edition. UCSF Gender Affirming Health Program,\nDepartment of Family and Community Medicine, University of California San Francisco.\nJune 17, 2016.\nIslam RM, Bell RJ, Green S, Page MJ, Davis SR. Safety and efficacy of testosterone for\nwomen: a systematic review and meta-analysis of randomised controlled trial data.\nLancet Diabetes Endocrinol. 2019;7(10):754-766.\nUS Preventive Services Task Force. Final recommendation statement: prostate cancer:\nscreening."},{"n":35,"q":"A 48-year-old female with a history of Crohn disease that has been poorly controlled for the past 4\u20136 months is admitted to the hospital. She has a BMI of 15 kg/m2 and has unintentionally lost more than 18% of her body weight in this same span of time. Her potassium level is 3.3 mEq/L (N 3.5\u20135.2) and her phosphorous level is 2.6 mg/dL (N 3.0\u20134.5). In addition to treating her Crohn disease, you should address her malnourished condition by initiating thiamine followed by refeeding and electrolytes using which one of the following strategies?","o":[{"l":"A","t":"Providing less than her expected calorie requirements and replenishing electrolytes immediately"},{"l":"B","t":"Providing her full expected calorie requirements and replenishing electrolytes immediately"},{"l":"C","t":"Providing her full expected calorie requirements and delaying replenishment of electrolytes for 6 hours"},{"l":"D","t":"Providing more than her expected calorie requirements and replenishing electrolytes immediately"},{"l":"E","t":"Providing more than her expected calorie requirements and delaying replenishment of electrolytes for 6 hours"}],"a":"A","e":"This patient meets the criteria for being at high risk of developing refeeding syndrome\n(RFS) with a BMI <16 kg/m\u00b2. In addition to her BMI she has had an unintentional\nweight loss of >15% in the past 3\u20136 months, and low levels of potassium and\nphosphorus prior to therapy. Another major risk factor is little or no nutrition for >10\ndays. Even patients who have lower risk for RFS than this patient should initially receive\nas little as 25%\u201350% of their estimated caloric requirements, and their nutrition\ngradually increased. Electrolytes, especially magnesium, potassium, and phosphate,\nshould be replenished immediately and closely monitored as calorie initiation will drive\nthese electrolytes intracellularly. Minor risk factors for RFS include a BMI <18.5 kg/m\u00b2,\na weight loss of >10% in the preceding 3\u20136 months, little or no nutrition for >5 days,\nand a history of alcohol or drug abuse.\n\nReferences\nFriedli N, Odermatt J, Reber E, Schuetz P, Stanga Z. Refeeding syndrome: update and\nclinical advice for prevention, diagnosis and treatment. Curr Opin Gastroenterol.\n2020;36(2):136-140.\nReber E, Friedli N, Vasiloglou MF, Schuetz P, Stanga Z. Management of refeeding\nsyndrome in medical inpatients. J Clin Med. 2019;8(12):2202."},{"n":36,"q":"A 62-year-old female sees you for follow-up of bilateral lower extremity edema that worsens throughout the day. A BNP level, TSH level, comprehensive metabolic panel, urinalysis, chest x-ray, EKG, and lower extremity venous ultrasound have all been normal. Which one of the following diagnoses should you consider in this patient?","o":[{"l":"A","t":"Celiac disease"},{"l":"B","t":"Cushing syndrome"},{"l":"C","t":"Lyme disease"},{"l":"D","t":"Obstructive sleep apnea"},{"l":"E","t":"Raynaud disease"}],"a":"D","e":"Obstructive sleep apnea is an increasingly recognized possible etiology of lower\nextremity edema and should be considered during the evaluation of this patient. While\nthe exact pathophysiology is unknown, nocturnal hypoxemia is thought to lead to\nincreased sympathetic tone resulting in systemic hypertension. This nocturnal\nhypoxemia can lead to neuroendocrine activation and salt and water retention. Celiac\ndisease, Cushing syndrome, Lyme disease, and Raynaud disease are not associated\nwith lower extremity edema.\nReference\nPatel H, Skok C, DeMarco A. Peripheral edema: evaluation and management in primary\ncare. Am Fam Physician. 2022;106(5):557-564."},{"n":37,"q":"A 42-year-old female sees you for routine follow-up of adrenal insufficiency diagnosed 2 years ago. Today she reports a 2-month history of fatigue, decreased energy, difficulty concentrating, and nausea. She has also had an unintentional 5-lb weight loss over the past 3 months. She takes oral hydrocortisone, 10 mg in the morning and 5 mg in the afternoon. She is adherent to her medication regimen and has not had any illnesses in the past year. Which one of the following would be the most appropriate initial step in the management of this patient\u2019s adrenal insufficiency?","o":[{"l":"A","t":"Increasing the hydrocortisone dosage"},{"l":"B","t":"A random cortisol level"},{"l":"C","t":"A cortisol stimulation test"},{"l":"D","t":"CT of the adrenal glands"}],"a":"A","e":"Hydrocortisone is the preferred glucocorticoid for replacement therapy of adrenal\ninsufficiency, and the goal of treatment is to use the lowest dosage of glucocorticoids to\ncontrol symptoms. After initial replacement, the management of chronic adrenal\ninsufficiency includes assessment of signs and symptoms of under- or overreplacement.\nThis patient has signs and symptoms of underreplacement including fatigue, weight\nloss, nausea, decreased energy, and difficulty concentrating. Her glucocorticoid dosage\nshould be increased by 2.5\u20135 mg daily and her symptoms reassessed in 1 week.\nMeasurement of an early morning corticotropin (ACTH) level is helpful in assessing for\noverreplacement as indicated by a low level; however, an elevated corticotropin level is\nnot necessarily indicative of underreplacement.\nChecking a random cortisol level is typically not necessary. A cortisol stimulation test is\nuseful in the diagnosis of adrenal insufficiency but not in monitoring replacement after\ndiagnosis. CT of the adrenal glands can be useful in evaluating the etiology of adrenal\ninsufficiency but not in the ongoing management of glucocorticoid replacement therapy.\n\nReferences\nBornstein SR, Allolio B, Arlt W, et al. Diagnosis and treatment of primary adrenal\ninsufficiency: an Endocrine Society clinical practice guideline. J Clin Endocrinol Metab.\n2016;101(2):364-389.\nHusebye ES, Allolio B, Arlt W, et al. Consensus statement on the diagnosis, treatment\nand follow-up of patients with primary adrenal insufficiency. J Intern Med.\n2014;275(2):104-115.\nMichels A, Michels N. Addison disease: early detection and treatment principles. Am\nFam Physician. 2014;89(7):563-568."},{"n":38,"q":"Which one of the following findings on a HINTS (head-impulse, nystagmus, test of skew) examination suggests a central etiology for a patient with vertigo?","o":[{"l":"A","t":"Saccade when the patient\u2019s head is thrust 10\u00b0 to the right and left while the patient\u2019s eyes are fixed on the examiner\u2019s nose"},{"l":"B","t":"Spontaneous nystagmus that is unidirectional and horizontal"},{"l":"C","t":"Suppression of nystagmus with visual fixation"},{"l":"D","t":"Vertical deviation upon uncovering a covered eye while the patient is looking straight ahead"}],"a":"D","e":"The HINTS (head-impulse, nystagmus, test of skew) examination can help determine\nwhether the etiology of vertigo is peripheral or central. When performed by trained\nclinicians, it is highly sensitive and specific in identifying central causes such as acute\nstroke. For a test of skew the patient looks straight ahead while each eye is covered\nand uncovered. Vertical deviation of a covered eye after uncovering suggests a central\netiology. Findings that are suggestive of peripheral causes of vertigo include\nspontaneous nystagmus that is unidirectional and horizontal, suppression of nystagmus\nwith visual fixation, and saccade (rapid movement of both eyes where the gaze\novercorrects to keep focused on the examiner) when the patient\u2019s head is thrust 10\u00b0 to\nthe right and left while the patient\u2019s eyes are fixed on the examiner\u2019s nose.\nReference\nMuncie HL, Sirmans SM, James E. Dizziness: approach to evaluation and management.\nAm Fam Physician. 2017;95(3):154-162."},{"n":39,"q":"A 32-year-old female sees you to request breast cancer screening after learning that her 45-year-old sister was diagnosed with breast cancer. She has no other known history of breast cancer. The patient does not have a family history of ovarian, tubal, or peritoneal cancers. Menarche occurred at 13 years of age and she has never been pregnant. On examination there is no nipple discharge or axillary lymphadenopathy and she has no palpable breast masses. Based on U.S. Preventive Services Task Force guidelines, which one of the following should you recommend as the next step in evaluation?","o":[{"l":"A","t":"Monthly breast self-examinations"},{"l":"B","t":"Screening mammography"},{"l":"C","t":"Screening breast ultrasonography"},{"l":"D","t":"Genetic counseling"}],"a":"D","e":"According to the U.S. Preventive Services Task Force (USPSTF), primary care clinicians\nshould evaluate women individually for their family history of breast, ovarian, tubal, and\nperitoneal cancers with a familial risk assessment tool. Patients with a positive risk score\nshould be recommended for genetic counseling (B recommendation). The USPSTF\nrecommends against teaching patients breast self-examination due to a lack of\nsupporting evidence confirming a benefit of breast cancer detection. Neither screening\nmammography nor ultrasonography are recommended without anatomic abnormalities\nindicating further examination at this age.\nReferences\nKhan M, Chollet A. Breast cancer screening: common questions and answers. Am Fam\nPhysician. 2021;103(1):33-41.\nUS Preventive Services Task Force. Final recommendation statement: BRCA-related\ncancer: risk assessment, genetic counseling, and genetic testing. Updated August 20,\n2019.\nUS Preventive Services Task Force. Final recommendation statement: breast cancer:\nscreening. Updated April 30, 2024."},{"n":40,"q":"A 55-year-old female presents with numbness and tingling in the ring and little fingers of her right hand. She also reports weakness when gripping objects and difficulty spreading her fingers apart. A physical examination reveals weakness of the first dorsal interosseous muscle and clawing of the ring and little fingers. A Tinel sign is positive over the medial epicondyle of the right elbow. Which one of the following is the most likely diagnosis?","o":[{"l":"A","t":"Axillary nerve compression"},{"l":"B","t":"Carpal tunnel syndrome"},{"l":"C","t":"Cubital tunnel syndrome"},{"l":"D","t":"Median nerve neuropathy"},{"l":"E","t":"Radial tunnel syndrome"}],"a":"C","e":"This patient's symptoms and the physical examination findings are classic for ulnar\nnerve compression at the elbow, also known as cubital tunnel syndrome. Numbness\nand tingling in the ring and little fingers, weakness in grip, and clawing of the fingers\nare all indicative of ulnar nerve dysfunction. A positive Tinel sign over the medial\nepicondyle further strengthens the diagnosis of cubital tunnel syndrome. Early diagnosis\nand treatment are crucial to prevent permanent nerve damage.\nAxillary nerve compression would produce paresthesias or pain of the lateral shoulder\nand weakness in external shoulder rotation, extension, abduction, and forward flexion.\nCarpal tunnel syndrome affects the median nerve, not the ulnar nerve, and causes\nnumbness and tingling in the thumb, index finger, middle finger, and half of the ring\nfinger. Median nerve neuropathy would cause symptoms similar to carpal tunnel\nsyndrome, but not weakness of the first dorsal interosseous muscle or clawing of the\nfingers. Radial tunnel syndrome affects the radial nerve and causes weakness and\nsensory loss in the back of the hand and thumb.\n\nReference\nSilver S, Ledford CC, Vogel KJ, Arnold JJ. Peripheral nerve entrapment and injury in the\nupper extremity. Am Fam Physician. 2021;103(5):275-285."},{"n":41,"q":"An 80-year-old male who is taking furosemide (Lasix), 80 mg, for heart failure presents to the emergency department (E with a gradual onset of somnolence. He is found to be hyponatremic with a serum sodium level of 104 mEq/L (N 135\u2013145). You should order the administration of which one of the following?","o":[{"l":"A","t":"100 mL of 3% sodium chloride over 10 minutes"},{"l":"B","t":"150 mL of 5% sodium chloride over 30 minutes"},{"l":"C","t":"500 mL of 3% sodium chloride over 30 minutes"},{"l":"D","t":"1 L of 0.9% sodium chloride over 1 hour"},{"l":"E","t":"1 L of 3% sodium chloride over 1 hour"}],"a":"A","e":"Current guidelines recommend correction of the serum sodium level by 4\u20136 mEq/L\nwithin 1\u20132 hours, which can reverse hyponatremic encephalopathy. This may be\naccomplished with either a 100-mL or 150-mL bolus of 3% sodium chloride\nadministered over 10\u201320 minutes and repeated 2\u20133 times until the desired sodium level\nis achieved.\nReference\nAdrogue HJ, Tucker BM, Madias NE. Diagnosis and management of hyponatremia: a\nreview. JAMA. 2022;328(3):280-291."},{"n":42,"q":"A 45-year-old female presents for evaluation of a 3-month history of left knee pain. She commutes by bicycle and is now finding it painful to cycle or even walk. On examination she does not have any deformity, and there is normal range of motion of the hips and knees. She has bilateral knee crepitus, pain on flexion of the left knee, and point tenderness that is noted 2 cm proximal to the left lateral joint line while flexing the knee. Which one of the following is the most likely diagnosis?","o":[{"l":"A","t":"Iliotibial band syndrome"},{"l":"B","t":"Lateral compartment osteoarthritis"},{"l":"C","t":"Patellar tendinitis"},{"l":"D","t":"Patellofemoral syndrome"},{"l":"E","t":"Pes anserine bursitis"}],"a":"A","e":"This patient has iliotibial band syndrome, a common overuse injury in cyclists and\nrunners. Pain occurs due to impingement of the iliotibial band over the lateral femoral\nepicondyle. The Noble compression test is diagnostic for iliotibial band syndrome and is\nconsidered positive if it evokes pain in the area of impingement, as in this patient.\nCrepitus occurs with osteoarthritis but is not specific, and this patient\u2019s history and the\nexamination are more suggestive of iliotibial band syndrome. Patellar tendinitis is more\ncentral, usually at the inferior pole of the patella. Patellofemoral syndrome causes\ndiffuse pain without point tenderness. The pes anserine bursa is distal to the medial\nknee.\nReference\nArnold MJ, Moody AL. Common running injuries: evaluation and management. Am Fam\nPhysician. 2018;97(8):510-516."},{"n":43,"q":"You see an expectant mother for a prenatal visit. She has heard of sudden infant death syndrome and asks for advice on sleeping arrangements. You tell her that infants should sleep","o":[{"l":"A","t":"in a crib and on their backs in the parents\u2019 room"},{"l":"B","t":"in a crib and on their stomachs in the parents\u2019 room"},{"l":"C","t":"in a crib and on their backs in their own room"},{"l":"D","t":"in the parents\u2019 bed and on their backs"},{"l":"E","t":"in the parents\u2019 bed and on their stomachs"}],"a":"A","e":"The infant mortality rate from accidental suffocation and strangling in bed has increased\nin recent decades and some of this increase may be due to sudden infant death\nsyndrome. Physicians should counsel expectant parents that it is safest for infants to\nsleep on their backs in their own cribs on a mattress with a fitted sheet. An infant\nshould sleep in the caregiver\u2019s room until 6\u201312 months of age. Infant suffocation is\nmore common with soft linen when sleeping in the caregiver\u2019s bed.\nReference\nDeGeorge KC, Neltner CE, Neltner BT. Prevention of unintentional childhood injury. Am\nFam Physician. 2020;102(7):411-417."},{"n":44,"q":"A 55-year-old female presents to your office because of a several-month history of progressively worsening fatigue, weakness, and unexplained weight loss. Physical examination findings are remarkable for hyperpigmentation of the skin and buccal mucosa. Initial laboratory studies reveal a low morning cortisol level. Which one of the following is the most likely diagnosis?","o":[{"l":"A","t":"Addison disease"},{"l":"B","t":"Cushing disease"},{"l":"C","t":"Pheochromocytoma"},{"l":"D","t":"Primary hyperaldosteronism"},{"l":"E","t":"Syndrome of inappropriate antidiuretic hormone secretion"}],"a":"A","e":"Addison disease is usually marked by fatigue, weakness, unexplained weight loss, and\nhyperpigmentation along with low cortisol levels. Hyperpigmentation is the result of\nelevated levels of melanocyte-stimulating hormone, a cleavage product of corticotropin\n(ACTH). Cushing disease is the result of excessive cortisol production due to a\ncorticotropin-secreting pituitary adenoma and is marked by weight gain, central obesity,\nmoon facies, buffalo hump, and muscle weakness. Pheochromocytoma is a\ncatecholamine-secreting tumor of the adrenal medulla. It usually presents with episodic\nsymptoms, including hypertension, headache, palpitations, and diaphoresis. Primary\nhyperaldosteronism is due to excessive aldosterone production leading to sodium\nretention, potassium loss, and hypertension. Clinical features of primary\nhyperaldosteronism include hypertension, hypokalemia, and metabolic alkalosis.\nSyndrome of inappropriate antidiuretic hormone secretion (SIADH) is caused by the\ninappropriate release of vasopressin despite normal or increased plasma volume and\nmay be triggered by stroke, infection, trauma, medications, pulmonary disease, or HIV.\nClinical symptoms of SIADH include confusion, muscle weakness, tremor, muscle\ncramps, hallucinations, seizures, and death.\n\nReferences\nBancos I, Prete A. Approach to the patient with adrenal incidentaloma. J Clin Endocrinol\nMetab. 2021;106(11):3331-3353.\nBraun MM, Barstow CH, Pyzocha NJ. Diagnosis and management of sodium disorders:\nhyponatremia and hypernatremia. Am Fam Physician. 2015;91(5):299-307.\nCharoensri S, Bashaw L, Dehmlow C, Ellies T, Wyckoff J, Turcu AF. Evaluation of a bestpractice advisory for primary aldosteronism screening. JAMA Intern Med.\n2024;184(2):174-182.\nKumar R, Wassif WS. Adrenal insufficiency. J Clin Pathol. 2022;75(7):435-442."},{"n":45,"q":"A 65-year-old male presents to your office for a Welcome to Medicare visit. The whisper test is abnormal with both ears. In addition to difficulty hearing and participating in day-to-day conversation, the patient is at increased risk for which one of the following health problems due to his hearing loss?","o":[{"l":"A","t":"Benign paroxysmal positional vertigo"},{"l":"B","t":"Dementia"},{"l":"C","t":"Ear infection"},{"l":"D","t":"Heart failure"},{"l":"E","t":"Temporomandibular joint dysfunction"}],"a":"B","e":"Hearing loss is associated with dementia, decreased quality of life, depression, debility,\ndelirium, falls, and mortality. It does not increase the risk for benign paroxysmal\npositional vertigo, ear infection, heart failure, or temporomandibular joint dysfunction.\nReference\nMichels TC, Duffy MT, Rogers DJ. Hearing loss in adults: differential diagnosis and\ntreatment. Am Fam Physician. 2019;100(2):98-108."},{"n":46,"q":"A 32-year-old female presents with concerns regarding infertility. She has been married for 3 years and has been attempting to conceive for the past 18 months. She reports early menarche at age 10 and a long-standing history of dysmenorrhea and heavy bleeding. These symptoms improved when she was using oral contraceptive therapy in her 20s. Transvaginal ultrasound results are inconclusive. Which one of the following would be the most appropriate next step in management?","o":[{"l":"A","t":"A 6-month trial of oral contraceptive therapy"},{"l":"B","t":"A trial of aromatase inhibitor therapy such as letrozole (Femara)"},{"l":"C","t":"Placement of a levonorgestrel-releasing IUD (Mirena)"},{"l":"D","t":"Diagnostic laparoscopic surgery to confirm the diagnosis"}],"a":"D","e":"There is a high suspicion for endometriosis in this patient who desires pregnancy. She\nhas classic symptoms, including painful menses and early menarche, and she is now\nexperiencing infertility. Her symptoms improved with oral contraceptive treatment in the\npast. Laparoscopic surgery can assist with both diagnosis and treatment. Given that the\npatient desires pregnancy, a trial of oral contraceptive therapy and placement of a\nlevonorgestrel-releasing IUD are not appropriate. While aromatase inhibitor therapy\nsuch as letrozole may be considered in the future, a complete infertility workup,\nincluding evaluation for male factor infertility, should be completed first.\nReference\nEdi R, Cheng T. Endometriosis: evaluation and treatment. Am Fam Physician.\n2022;106(4):397-404."},{"n":47,"q":"A 70-year-old male presents to the emergency department with a sudden onset of severe abdominal pain that radiates to his back. The patient has a history of stroke, hypertension, and type 2 diabetes. He has a 40-pack-year smoking history. A physical examination reveals a pulsatile mass just above the umbilicus. CT of the abdomen confirms the diagnosis. Which one of the following is the greatest risk factor for developing this condition?","o":[{"l":"A","t":"Cigarette smoking"},{"l":"B","t":"Hypertension"},{"l":"C","t":"Male sex"},{"l":"D","t":"Stroke"},{"l":"E","t":"Type 2 diabetes"}],"a":"A","e":"This patient has an abdominal aortic aneurysm (AAA) that may have ruptured. Tobacco\nuse (in the form of cigarette smoking) is the greatest risk factor for developing AAA.\nCurrent U.S. Preventive Services Task Force guidelines recommend one-time abdominal\nscreening ultrasonography for all men ages 65\u201375 who have ever smoked. Additional\nrisk factors include hypertension, male sex, stroke, a family history of AAA, obesity,\ncoronary artery disease, peripheral artery disease, and age >65.\nReference\nHaque K, Bhargava P. Abdominal aortic aneurysm. Am Fam Physician.\n2022;106(2):165-172."},{"n":48,"q":"Of the following, which one is the most effective abortive treatment for cluster headache?","o":[{"l":"A","t":"Hydromorphone (Dilaudid)"},{"l":"B","t":"Ketorolac"},{"l":"C","t":"Ondansetron"},{"l":"D","t":"Propranolol"},{"l":"E","t":"Sumatriptan (Imitrex)"}],"a":"E","e":"Cluster headache is a type of primary headache in the category of trigeminal autonomic\ncephalgia, and abortive therapy consists of 100% high-flow oxygen and triptans. Its\ntypical onset is age 30 and it is 2\u20133 times more common in males than females. The\npain is severe and unilateral in the orbital, supraorbital, or temporal locations. It is\nassociated with at least one of the following symptoms on the ipsilateral side:\nconjunctival injection or lacrimation, nasal congestion or rhinorrhea, miosis or ptosis,\neyelid swelling, and sweating of the forehead and face. The pain can last from 30\nminutes to almost 3 hours. Hydromorphone and ketorolac can be used to mask other\ntypes of pain but are ineffective in stopping cluster headache. Ondansetron stops\nvomiting, but its side effects include headache. Propranolol can be used to prevent\nmigraine.\nReferences\nHeadache Classification Committee of the International Headache Society (IHS). The\ninternational classification of headache disorders, 3rd edition. Cephalalgia.\n2018;38(1):1-211.\nMalu OO, Bailey J, Hawks MK. Cluster headache: rapid evidence review. Am Fam\nPhysician. 2022;105(1):24-32.\nManzoni GC, Taga A, Russo M, Torelli P. Age of onset of episodic and chronic cluster\nheadache-a review of a large case series from a single headache centre. J Headache\nPain. 2016;17:44.\n\nMay A. Cluster headache: pathogenesis, diagnosis, and management. Lancet.\n2005;366(9488):843-855.\nRay JC, Stark RJ, Hutton EJ. Cluster headache in adults. Aust Prescr. 2022;45(1):15-20."},{"n":49,"q":"A 4-month-old female is brought to your office for a well child check. She is here with her mother and 2 older brothers, who are also your patients. The family looks forward to swimming at the local outdoor community pool, going to the beach, and gardening this summer. Which one of the following should you recommend to reduce this family's risk for skin cancer related to sun exposure?","o":[{"l":"A","t":"Applying sunscreen with an SPF \u226515 to the infant before taking her outside"},{"l":"B","t":"Avoiding going to the pool during the middle of the day, and encouraging them to take breaks in the shade"},{"l":"C","t":"Going to the beach only on cloudy days when ultraviolet rays are absent"},{"l":"D","t":"Wearing a baseball cap for sun protection when gardening"}],"a":"B","e":"Exposure to UV light is known to increase the risk for skin cancer. UV rays are strongest\nfrom 10:00 a.m. to 4:00 p.m., so going to the pool in the early morning will reduce\nexposure. The FDA does not recommend the use of sunscreen in infants under 6\nmonths of age. Children under 6 months of age should be kept out of direct sunlight.\nUV rays still damage skin on cloudy days. Hats should shade the ears and the back of\nthe neck as well as the face, so a baseball cap is not a good choice.\nReferences\nSkin cancer: sun safety facts. Centers for Disease Control and Prevention. May 3, 2024.\nSun safety: information for parents about sunburn & sunscreen. American Academy of\nPediatrics. Updated November 20, 2023."},{"n":50,"q":"A 36-year-old female presents with a medical history of hypertension, hyperlipidemia, obesity, and 3 miscarriages. She is not currently pregnant. She was recently discharged from the hospital with her second deep vein thrombosis (DVT) in the past several years. A workup for the underlying cause of her thrombophilia is positive for antiphospholipid antibodies. Which one of the following medications would be most appropriate for the long-term treatment of this patient\u2019s DVT?","o":[{"l":"A","t":"Apixaban (Eliquis)"},{"l":"B","t":"Aspirin"},{"l":"C","t":"Clopidogrel (Plavix)"},{"l":"D","t":"Enoxaparin (Lovenox)"},{"l":"E","t":"Warfarin"}],"a":"E","e":"The correct treatment of a deep vein thrombosis (DVT) in a patient with\nantiphospholipid syndrome is warfarin. Most DVTs can be treated with a direct oral\nanticoagulant (DOAC). DOACs may be acceptable in low-risk patients with a single\nprevious DVT, but they are not preferred for patients with antiphospholipid antibody\nsyndrome due to the risk for increased arterial thrombotic events. Aspirin is clearly not\nappropriate in a patient with recurrent DVTs. Clopidogrel would never be indicated for\nthe treatment of a DVT. If this patient were pregnant, enoxaparin would be preferred.\nThrombophilia evaluation should not be considered in patients with a provoked venous\nthromboembolism (VTE). However, in select patients with recurrent VTE, evaluation\nshould be considered, specifically when the results of the testing would influence the\ntreatment plan (SOR A). Thrombophilia testing may be considered in patients who are\ninterested in stopping anticoagulation because of concerns such as bleeding risk,\nintolerance, or cost. These patients include those with an initial VTE before age 50, a\nhistory of recurrent pregnancy loss, a first-degree relative who had an initial VTE before\n50 years of age, recurrent VTEs, arterial and venous thrombi, or VTE in an unusual site.\n\nReferences\nKhairani CD, Bejjani A, Piazza G, et al. Direct oral anticoagulants vs vitamin K\nantagonists in patients with antiphospholipid syndromes: meta-analysis of randomized\ntrials. J Am Coll Cardiol. 2023;81(1):16-30.\nMount HR, Rich M, Putnam MS. Recurrent venous thromboembolism. Am Fam\nPhysician. 2022;105(4):377-385."},{"n":51,"q":"A generally healthy 5-month-old female is brought to your office by her parent for follow-up of a worsening, painless, red lesion on her right earlobe that has been present since birth. The parent is concerned because the lesion has rapidly increased in size over the last few months. A physical examination reveals a nontender, bluish-red, exophytic plaque on the right earlobe (shown below). Which one of the following would be an appropriate treatment for this condition?","o":[{"l":"A","t":"Topical hydrocortisone 0.5%, twice daily"},{"l":"B","t":"Oral propranolol hydrochloride, 2\u20133 mg/kg daily"},{"l":"C","t":"Embolization"},{"l":"D","t":"Excisional surgery"}],"a":"B","e":"Infantile hemangiomas are the most common benign tumors in childhood, and are\nmostly small and self-resolving. However, patients with large lesions, lesions >2 mm\nabove the skin, or lesions near the eyes, ears, and nose are considered to be at high\nrisk for disfigurement.\nFirst-line treatment includes oral propranolol hydrochloride, 2\u20133 mg/kg daily. Alternative\ntreatments include topical timolol 0.5% gel-forming solution, twice daily, and highpotency corticosteroids such as clobetasol propionate 0.05%, but not hydrocortisone\n0.5%. Embolization and excisional surgery are reserved for select cases in which\nmedical treatment has failed.\nReferences\nHoover L. Infantile hemangioma: AAP releases guideline for management. Am Fam\nPhysician. 2019;100(3):186-187.\nSebaratnam DF, Rodriguez Bandera AL, Wong L-CF, Wargon O. Infantile hemangioma.\nPart 2: management. J Am Acad Dermatol. 2021;85(6):1395-1404."},{"n":52,"q":"A 24-year-old female sees you for treatment of significant depression and associated hypomanic symptoms. She has been experiencing racing thoughts, agitation, and a decreased need for sleep. Which one of the following is CONTRAINDICATED in this patient?","o":[{"l":"A","t":"Cariprazine (Vraylar) monotherapy"},{"l":"B","t":"Quetiapine (Seroquel) monotherapy"},{"l":"C","t":"Sertraline (Zoloft) monotherapy"},{"l":"D","t":"Lurasidone (Latuda) plus valproic acid"},{"l":"E","t":"Quetiapine plus lithium"}],"a":"C","e":"Antidepressant monotherapy is contraindicated in patients with depression who have\nmixed features of associated hypomania or mania because it may precipitate or worsen\nmania. First-line treatment is mood stabilizers such as lithium, anticonvulsants, and\nantipsychotics.\nReference\nMarzani G, Neff AP. Bipolar disorders: evaluation and treatment. Am Fam Physician.\n2021;103(4):227-239."},{"n":53,"q":"A 59-year-old male presents to your office accompanied by his wife for evaluation of a 6-month history of worsening weakness. He reports having difficulty lifting light items to the top shelf at work. His wife adds that he has recently been clumsier around the house. The patient\u2019s vital signs are normal today. On physical examination you note mild dysarthria during conversation, proximal weakness of the upper extremities that is more pronounced on the left, hyperreflexia of the biceps tendon reflex bilaterally, atrophy of the quadriceps that is more pronounced on the right, and absent reflexes of the patellar tendon. Which one of the following is the most likely diagnosis?","o":[{"l":"A","t":"Amyotrophic lateral sclerosis"},{"l":"B","t":"Guillain-Barr\u00e9 syndrome"},{"l":"C","t":"Hypothyroidism"},{"l":"D","t":"Multiple sclerosis"},{"l":"E","t":"Myasthenia gravis  Item #51"}],"a":"A","e":"Weakness is a chief concern that is frequently encountered in medical settings, and a\ncareful history and thorough physical examination are critical to developing an\nappropriate diagnosis. This patient displays features of asymmetric weakness and\nfindings of both upper and lower motor neuron disease, which should lead to a clinical\nsuspicion of amyotrophic lateral sclerosis (ALS), also known as Lou Gehrig disease. ALS\nis an insidious paralytic disorder that is currently incurable. Upper motor signs include\nhyperreflexia, dysarthria, clonus, and a positive Babinski sign. Lower motor signs\ninclude muscle atrophy and hyporeflexia or areflexia.\nGuillain-Barr\u00e9 syndrome is an acute neuromuscular disorder characterized by ascending\nmuscle weakness and lower motor neuron signs that may progress to include the\nrespiratory muscles. While hypothyroidism may lead to hyporeflexia, it is unlikely to lead\nto the other physical examination findings in this case. Multiple sclerosis can have a\nvariable presentation and may display signs of unilateral weakness and upper motor\nneuron signs depending on the location of the lesion. Myasthenia gravis is characterized\nby proximal weakness that progresses throughout the day, often includes ocular\nmuscles, and displays lower motor neuron signs.\nReferences\nBrown RH, Al-Chalabi A. Amyotrophic lateral sclerosis. N Engl J Med. 2017;377(2):162172.\nLarson ST, Wilbur J. Muscle weakness in adults: evaluation and differential diagnosis.\nAm Fam Physician. 2020;101(2):95-108."},{"n":54,"q":"A 49-year-old female presents to your office with severe left ear pain. The patient describes the pain as sharp and deep inside her ear and reports that it has been occurring occasionally for several years. The pain has become more constant over the last 2 months, and she currently rates it as 8 out of 10 on a pain scale. She has not previously sought an evaluation. On physical examination you find a normal ear canal and tympanic membrane. The patient is only able to open her mouth 2 finger widths, has clicking over the left temporomandibular joint with opening, and has pain with palpation of the submandibular musculature. Which one of the following is the most appropriate next step in the management of this disorder?","o":[{"l":"A","t":"Reassurance that her ear is normal, and follow-up in 4 weeks if symptoms have not improved"},{"l":"B","t":"A trial of naproxen and cyclobenzaprine"},{"l":"C","t":"Noncontrast CT of the facial bones"},{"l":"D","t":"Referral to an otolaryngologist for further evaluation"},{"l":"E","t":"Referral to a maxillofacial surgeon for consideration of jaw realignment surgery"}],"a":"B","e":"There is no need for imaging or further workup to determine the cause of pain in this\npatient with uncomplicated temporomandibular joint dysfunction with muscle spasms.\nThe initial treatment is naproxen for inflammation and pain, as well as cyclobenzaprine\nfor muscle spasms. Scheduling a follow-up visit without treatment is not appropriate in\na patient with a clear diagnosis and available medications that can safely provide relief.\nA referral to either an otolaryngologist or a maxillofacial surgeon should be deferred\nuntil a trial of medication is completed.\nReference\nMatheson EM, Fermo JD, Blackwelder RS. Temporomandibular disorders: rapid evidence\nreview. Am Fam Physician. 2023;107(1):52-58."},{"n":55,"q":"A 6-month-old male is brought to your office by his parents for a well baby examination. This is the patient\u2019s first visit to your office as his family recently immigrated to the United States. The infant appears to be developing normally, but the parents are concerned because they have not observed a right testicle. On examination you are able to palpate the left testicle in the normal location. The right testicle is not located in the scrotum but is palpable along the inguinal canal. It can be moved into the upper scrotum but requires constant tension to remain in this position and immediately retracts after release. Which one of the following would be the most appropriate next step in management?","o":[{"l":"A","t":"Reassurance that the condition will resolve spontaneously"},{"l":"B","t":"Follow-up in 2 months"},{"l":"C","t":"An ultrasound of the scrotum and pelvis"},{"l":"D","t":"Referral to an endocrinologist"},{"l":"E","t":"Referral to a urologist"}],"a":"E","e":"Cryptorchidism is the most common genitourinary malformation in male children, and\nprimary care physicians play a key role in the early identification of this condition. The\nnext step in management would be referral to a urologist (SOR C). Reassuring the\nparents that the patient\u2019s condition will spontaneously resolve is not sufficient. If the\ntesticle were located in the upper scrotum or lower inguinal canal, then an annual\nexamination to ensure spontaneous resolution would be acceptable. If the patient had\nbilateral undescended testicles that were nonpalpable, then referral to an\nendocrinologist would be the most appropriate next step. Imaging is not recommended\nbefore consultation with a surgical specialist (SOR C). After surgery, patients need\nlifelong surveillance and counseling regarding fertility implications and increased risk for\ntesticular conditions.\nReference\nNguyen V, Ngo L, Jaqua EE. Cryptorchidism (undescended testicle). Am Fam Physician.\n2023;108(4):378-385."},{"n":56,"q":"A 23-year-old kindergarten teacher presents with a 2-day history of fever up to 102 \u00b0F, a sore throat, headache, and swollen glands. She has not had a runny nose or cough. Her throat is hyperemic and has tonsillar exudates. The anterior cervical nodes are enlarged and tender, but there is no other lymphadenopathy. She requests an antibiotic to prevent complications and to reduce the likelihood of spreading the infection to her students. A throat swab for group A Streptococcus is positive. Which one of the following is true regarding the use of antibiotics in this patient?","o":[{"l":"A","t":"Her current symptoms will not be reduced"},{"l":"B","t":"Her risk for developing poststreptococcal glomerulonephritis will not change"},{"l":"C","t":"Her risk for developing rheumatic fever will not change"},{"l":"D","t":"She will remain contagious for 7\u201310 days even with treatment"}],"a":"B","e":"Up to 90% of cases of pharyngitis in adults are viral in etiology. The patient in this\nclinical scenario, however, has a high clinical likelihood of group A \u03b2-hemolytic\nstreptococcal (GABS) pharyngitis, as she meets 4 of the 5 Modified Centor Criteria\n(fever, hyperemic/exudative tonsillitis, cervical adenopathy, and absence of cough).\nAntibiotic treatment is recommended to reduce communicability, relieve symptoms, and\nhelp prevent rheumatic fever (SOR C). Antibiotic treatment for GABS pharyngitis does\nnot lower the risk for acute poststreptococcal glomerulonephritis. The use of the\nModified Centor Criteria for acute pharyngitis is endorsed by both the American\nAcademy of Family Physicians and the American College of Physicians.\nReference\nZoorob R, Sidani MA, Fremont RD, Kihlberg C. Antibiotic use in acute upper respiratory\ntract infections. Am Fam Physician. 2012;86(9):817-822."},{"n":57,"q":"A 23-year-old female presents to your office for evaluation of amenorrhea. A pregnancy test is positive, and you determine that she is at 6 weeks\u2019 gestation based on her last menstrual period. She has a history of acne, allergic rhinitis, gastroesophageal reflux, and anxiety. The patient\u2019s current medications include the following: Adapalene 0.1% gel (Differin Gel) daily Famotidine (Pepcid), 20 mg as needed Fluticasone propionate (Flonase), 50 \u03bcg daily Hydroxyzine (Vistaril), 25 mg as needed Polyethylene glycol (MiraLAX), 17 g as needed Which one of the patient\u2019s current medications should be discontinued at this time?","o":[{"l":"A","t":"Adapalene"},{"l":"B","t":"Famotidine"},{"l":"C","t":"Fluticasone propionate"},{"l":"D","t":"Hydroxyzine"},{"l":"E","t":"Polyethylene glycol"}],"a":"A","e":"Family physicians should be familiar with medications contraindicated in pregnancy that\nare commonly used by women of reproductive age. Topical adapalene, along with other\nretinoids, is contraindicated in pregnancy due to lack of safety data and known harm\nfrom oral formulations. Famotidine, fluticasone propionate, hydroxyzine, and\npolyethylene glycol are generally considered safe in all trimesters of pregnancy.\nReference\nPowers EA, Tewell R, Bayard M. Over-the-counter medications in pregnancy. Am Fam\nPhysician. 2023;108(4):360-369."},{"n":58,"q":"A 17-year-old male sustains an injury while playing in a high school football game. As the sideline physician, you determine that he needs to be transported to the emergency department with neck stabilization. He is awake, talking, and in no acute distress. There is no concern for airway compromise. Depending on the nature of his other injuries, which one of the following pieces of protective equipment should you remove before transporting the patient?","o":[{"l":"A","t":"Only the helmet if required"},{"l":"B","t":"Only the shoulder pads if required"},{"l":"C","t":"Both the helmet and the shoulder pads"},{"l":"D","t":"Neither the helmet nor the shoulder pads"}],"a":"D","e":"In general, helmets and pads should remain in place during transportation after a\nfootball injury requiring neck stabilization. The facemask may be removed with a special\ntool if there are airway issues or loss of consciousness. If the athlete\u2019s injuries require\neither the helmet or pads to be removed, both should be removed by a trained team.\nRemoval of only one can cause hyperflexion or hyperextension of the neck.\nReferences\nMills BM, Conrick KM, Anderson S, et al. Consensus recommendations on the\nprehospital care of the injured athlete with a suspected catastrophic cervical spine\ninjury. J Athl Train. 2020;55(6):563-572.\nUsman S. Management of head and neck injuries by the sideline physician. Am Fam\nPhysician. 2022;106(5):543-548."},{"n":59,"q":"A 16-year-old female presents for a routine checkup. During the visit, she discloses that she is sexually active and wants to discuss contraceptive options. However, she is hesitant to inform her parents, fearing their disapproval. Which one of the following is the most ethical course of action?","o":[{"l":"A","t":"Providing the patient with contraception without informing her parents, and respecting her confidentiality by not noting this discussion in her medical record"},{"l":"B","t":"Offering confidential counseling and contraceptive options while encouraging open communication with her parents"},{"l":"C","t":"Insisting on parental involvement in the decision-making process, emphasizing the importance of open communication"},{"l":"D","t":"Referring the patient to a mental health professional to address her concerns about parental disapproval before discussing contraception"},{"l":"E","t":"Refusing to discuss contraception without parental consent, citing the patient\u2019s age"}],"a":"B","e":"While respecting the patient\u2019s autonomy and confidentiality is important, ethical\nobligations also extend to ensuring her well-being and safety, and accurately\nmaintaining the medical record. Encouraging open communication with parents can\nfoster trust and support, but forcing it might create a harmful environment. Offering\ncounseling and contraceptive options while advocating for open communication allows\nthe physician to foster patient autonomy as well as uphold responsible guidance. This\napproach aligns with ethical guidelines from the American Academy of Pediatrics that\nemphasize respect for minors\u2019 confidentiality while considering parental involvement in\nsensitive situations.\nReference\nCommittee on Adolescence; Braverman PK, Adelman WP, et al. Contraception for\nadolescents. Pediatrics. 2014;134(4):e1244-e1256."},{"n":60,"q":"A previously healthy 72-year-old female presents to your office 7 days after hospitalization for an acute ischemic stroke diagnosed by MRI. The inpatient evaluation confirmed that she experienced a minor noncardioembolic ischemic stroke. She was not a candidate for reperfusion therapy and did not receive rtPA. Her family reports that her speech impairment and confusion have completely resolved and that she is now back to her baseline. Which one of the following would be the most appropriate pharmacotherapy at this time?","o":[{"l":"A","t":"A direct oral anticoagulant"},{"l":"B","t":"Low-molecular-weight heparin"},{"l":"C","t":"A vitamin K antagonist"},{"l":"D","t":"Single antiplatelet therapy"},{"l":"E","t":"Dual antiplatelet therapy"}],"a":"E","e":"This patient has been diagnosed with a minor noncardioembolic ischemic stroke and\nshould be treated with dual antiplatelet therapy with aspirin and clopidogrel for 21\u201390\ndays post stroke (SOR A). The benefit of reducing recurrent stroke risk outweighs the\nrisk for major bleeding. Using aspirin and clopidogrel longer than 90 days offers no\nadditional benefit but results in significantly increased bleeding risk compared to using\nsingle antiplatelet therapy. Following 21\u201390 days post stroke, either aspirin\nmonotherapy or aspirin in combination with dipyridamole may be used indefinitely. If a\ncardioembolic source is later diagnosed, appropriate anticoagulation therapy with a\ndirect oral anticoagulant or vitamin K antagonist, such as warfarin, can be initiated.\nLow-molecular-weight heparin does not play a role in secondary stroke prevention.\nReference\nLarson ST, Ray BE, Wilbur J. Ischemic stroke management: posthospitalization and\ntransition of care. Am Fam Physician. 2023;108(1):70-77."},{"n":61,"q":"In patients with posttraumatic stress disorder, which one of the following medications is most effective for the treatment of midsleep awakening due to hyperarousal or nightmares?","o":[{"l":"A","t":"Amitriptyline"},{"l":"B","t":"Clonazepam (Klonopin)"},{"l":"C","t":"Fluoxetine (Prozac)"},{"l":"D","t":"Prazosin (Minipress)"},{"l":"E","t":"Extended-release venlafaxine (Effexor XR)"}],"a":"D","e":"The \u03b1-blocker prazosin can be effective in the treatment of midsleep awakening due to\nhyperarousal or nightmares by decreasing sympathetic nervous tone. Due to their\ntoxicity profiles, tricyclic antidepressants such as amitriptyline are usually not initiated in\npatients with posttraumatic stress disorder (PTSD) until multiple first-line treatments\nhave failed. Benzodiazepines such as clonazepam are generally avoided in patients with\nPTSD due to potential misuse and chronic long-term effects. SSRIs such as fluoxetine\nand SNRIs such as venlafaxine are the most effective pharmacologic treatments for\noverall reduction of PTSD symptoms. However, they are not used specifically for\nnighttime trauma-related nightmares.\nReference\nSartor Z, Kelley L, Laschober R. Posttraumatic stress disorder: evaluation and\ntreatment. Am Fam Physician. 2023;107(3):273-281."},{"n":62,"q":"A 2-year-old male is brought to the emergency department after a generalized seizure that lasted for 3 minutes and was witnessed by his parent. An examination is significant for a temporal temperature of 38.8 \u00b0C (101.8 \u00b0F), runny nose, and cough. He does not have any previous history of seizure. A neurologic examination is benign. Which one of the following would be the most appropriate management regarding this patient\u2019s seizure?","o":[{"l":"A","t":"Reassurance and return precautions"},{"l":"B","t":"A CBC and comprehensive metabolic panel"},{"l":"C","t":"Oral levetiracetam (Keppra)"},{"l":"D","t":"Rectal diazepam (Diastat)"},{"l":"E","t":"Electroencephalography"}],"a":"A","e":"This patient had a simple febrile seizure that has ended, and antiseizure medication is\nnot recommended. Routine laboratory examinations, imaging, and\nelectroencephalography are not recommended in simple febrile seizures.\nBenzodiazepines can be used in patients who are actively seizing for longer than 5\nminutes, but this patient\u2019s seizure has ended.\nReference\nSmith DK, Sadler KP, Benedum M. Febrile seizures: risks, evaluation, and prognosis. Am\nFam Physician. 2019;99(7):445-450."},{"n":63,"q":"A 35-year-old male with a medical history of hypertension and a family history of hypercholesterolemia and coronary artery disease sees you for routine follow-up of hypertension. His blood pressure is controlled on hydrochlorothiazide, 25 mg daily, and losartan (Cozaar), 50 mg daily. He has a BMI of 30 kg/m2 and quit smoking tobacco 2 years ago. According to the U.S. Preventive Services Task Force, which one of the following is recommended for the primary prevention of cardiovascular disease in this patient?","o":[{"l":"A","t":"Aspirin, 81 mg daily"},{"l":"B","t":"Low- to moderate-intensity statin therapy"},{"l":"C","t":"Moderate-intensity exercise for 120 minutes per week"},{"l":"D","t":"Referral to behavioral counseling interventions to promote a healthy diet and physical activity"}],"a":"D","e":"This patient is at increased risk for cardiovascular disease (CVD) due to his\nhypertension, family history, elevated BMI, and smoking history. According to the U.S.\nPreventive Services Task Force (USPSTF) recommendations for the primary prevention\nof CVD, adults with CVD risk factors should be referred to behavioral counseling\ninterventions to promote a healthy diet and physical activity. The USPSTF recommends\nshared decision-making for low-dose aspirin for the primary prevention of CVD in\npatients 40\u201359 years of age who have a 10% or greater 10-year risk of CVD. The\nUSPSTF recommends statin therapy for the primary prevention of CVD in patients 40\u2013\n75 years of age who do not have a history of CVD but do have \u22651 CVD risk factors plus\na 10-year CVD risk of 7.5%\u201310%. The USPSTF does not make a recommendation for a\nspecific exercise program.\nReference\nUS Preventive Services Task Force. Final recommendation statement: healthy diet and\nphysical activity for cardiovascular disease prevention in adults with cardiovascular\ndisease risk factors: behavioral counseling interventions. Updated November 24, 2020."},{"n":64,"q":"A 68-year-old male presents with dependent edema and an ulcer over the medial malleolus secondary to venous insufficiency. The dorsalis pedis pulse is intact. Which one of the following would be the most appropriate management of this patient\u2019s edema and ulcer?","o":[{"l":"A","t":"A nongraduated compression stocking with 10\u201320 mm Hg pressure at the ankle"},{"l":"B","t":"A graduated compression stocking with 30\u201340 mm Hg pressure at the ankle"},{"l":"C","t":"A graduated compression stocking with 50\u201360 mm Hg pressure at the ankle"},{"l":"D","t":"An Unna boot"}],"a":"B","e":"Graduated compression stockings are the mainstay of treatment for chronic venous\ninsufficiency. The compression is generally highest at the ankle with decreasing\npressures at the calf. While compression stockings with <20 mm Hg tension may be\nhelpful for comfort, they are not considered adequate for venous insufficiency.\nInsufficiency significant enough to cause venous ulcers should be treated with 30\u201340\nmm Hg pressure stockings, which have been shown to be effective for >90% of ulcers\nif a patient is 70%\u201380% compliant with usage. Varicosities with swelling and discomfort\nmay be helped by 20\u201330 mm Hg pressure compression stockings. Compression\nstockings with >50 mm Hg of pressure are not as well tolerated and are generally used\nin patients with lymphedema. Unna boots have significant variability of pressures and\nare not generally recommended for this condition.\nReferences\nDahm KT, Myrhaug HT, Stromme H, Fure B, Brurberg KG. Effects of preventive use of\ncompression stockings for elderly with chronic venous insufficiency and swollen legs: a\nsystematic review and meta-analysis. BMC Geriatr. 2019;19(1):76.\nEberhardt RT, Raffetto JD. Chronic venous insufficiency. Circulation. 2014;130(4):333346."},{"n":65,"q":"Hypocalcemia can cause which one of the following?","o":[{"l":"A","t":"Constipation"},{"l":"B","t":"Hypertension"},{"l":"C","t":"Paresthesias"},{"l":"D","t":"Respiratory suppression"},{"l":"E","t":"Tachycardia"}],"a":"C","e":"Hypocalcemia causes generalized neuromuscular irritability, leading to peripheral\nsymmetric paresthesias and muscle spasms that can cause tetany, extrapyramidal\nsymptoms, and seizures. Hypocalcemia can cause QTc prolongation, heart block, and\nbronchospasm. It can also lead to complications of hypercalciuria such as\nnephrolithiasis and can trigger psychiatric conditions including anxiety and mania.\nHypocalcemia does not cause hypertension, respiratory suppression, or tachycardia.\nConstipation is more associated with hypercalcemia.\nReference\nPepe J, Colangelo L, Biamonte F, et al. Diagnosis and management of hypocalcemia.\nEndocrine. 2020;69(3):485-495."},{"n":66,"q":"A 60-year-old male who had an ST-elevation myocardial infarction 9 months ago presents for routine follow-up. He has been receiving medical therapy and had been attending cardiac rehabilitation at his community hospital until recently. He reports gradually increasing dyspnea on exertion but is still able to work as a computer programmer and has no problems performing activities of daily living. He has developed mild edema. On cardiac examination you note a heart murmur that was not present 3 months ago. The murmur is holosystolic, grade 3/6, loudest at the cardiac apex, and radiates to the axilla. Which one of the following is the most likely etiology of this murmur?","o":[{"l":"A","t":"Aortic stenosis"},{"l":"B","t":"Mitral regurgitation"},{"l":"C","t":"Mitral stenosis"},{"l":"D","t":"Pericardial effusion"},{"l":"E","t":"Tricuspid regurgitation"}],"a":"B","e":"In patients who have had a myocardial infarction, chronic mitral regurgitation can\ndevelop as a consequence of left ventricular remodeling related to myocardial ischemia.\nChronic mitral regurgitation develops gradually and symptoms that are initially mild can\nprogress. In the case of acute chordae tendineae rupture, mitral regurgitation occurs\nsuddenly, and the patient develops acute pulmonary edema and is often\nhemodynamically unstable.\nA chronic mitral regurgitation murmur is typically grade 3\u20134/6 and holosystolic. It\nusually obscures S1 and radiates to the axilla, and it is loudest when the patient is\nsupine.\nAn aortic stenosis murmur is a decrescendo murmur, usually grade 2\u20133/6, loudest at\nthe aortic area or right upper sternal border, and radiates to the clavicle or neck. A\nmitral stenosis murmur is a subtle diastolic \u201crumble\u201d in the left fifth intercostal space,\nlateral to the nipple, and best heard in the left lateral decubitus position. In a patient\nwith pericardial effusion, heart sounds are generally muffled without a distinct murmur.\nIsolated tricuspid regurgitation is uncommon and exhibits a high-pitched softer\nholosystolic murmur that is best heard at the left lower sternal border and radiates to\nthe right sternal border.\nReference\nO\u2019Gara PT, Loscalzo J. Approach to the patient with a heart murmur. In: Loscalzo J,\nFauci AS, Kasper DL, Hauser SL, Longo DL, Jameson JL, eds. Harrison\u2019s Principles of\nInternal Medicine. Vol 1. 21st ed. McGraw Hill; 2022:278-286."},{"n":67,"q":"A 32-year-old male is hospitalized with a 1-week history of an acute illness. His signs and symptoms include a fever of 38.9 \u00b0C (102.0 \u00b0F), axillary and inguinal lymphadenopathy, sore throat, arthralgias, myalgias, headache, and a skin rash. He has a history of intravenous drug use, but says his last use was 2 weeks ago. He does not have a history of travel outside the United States, tick bites, or occupational exposure. On examination you note pharyngeal edema and erythema without tonsillar enlargement. Shallow, sharply demarcated ulcers are noted on the oral mucosa. He has a generalized rash that began 3 days after the onset of fever and has the appearance of pityriasis rosea. Nontender nodes are noted in the axillae and groin. Laboratory studies reveal mild anemia, thrombocytopenia, and a slight elevation of liver enzymes. His WBC count is 3000/mm3 (N 4300\u201310,800). A rapid plasma reagin test, office testing for mononucleosis, rapid antibody HIV testing, blood cultures, and hepatitis studies are all negative. Which one of the following would be most appropriate at this time?","o":[{"l":"A","t":"Herpes simplex virus IgM testing"},{"l":"B","t":"An HIV viral load"},{"l":"C","t":"A Western blot for HIV"},{"l":"D","t":"Prednisone"},{"l":"E","t":"A skin lesion biopsy"}],"a":"B","e":"Diagnosing acute HIV infection has substantial implications for both the individual and\nfor public health, as the infection will be easy to spread during this time. In a person\nwho has a sudden onset of an ill-defined mononucleosis-like syndrome and/or aseptic\nmeningitis, acute HIV infection should be in the differential diagnosis along with\nmononucleosis, cytomegalovirus, toxoplasmosis, rubella, viral hepatitis, disseminated\ngonococcal infection, and other viral illnesses.\nMucocutaneous ulcer is unusual in most of these conditions and should arouse\nsuspicion. Skin rash is uncommon in mononucleosis, visceral larva migrans, and\ntoxoplasmosis, and tends to spare the palms and soles in rubella. The abrupt onset of\nsymptoms, pharyngeal edema without tonsillar enlargement or exudates, and diarrhea\nall help to distinguish acute HIV from mononucleosis. A positive heterophile antibody\ntest can occur in acute HIV infection, and atypical lymphocytes can be seen in both.\nNegative results of the rapid enzyme-linked immunosorbent assay (ELISA) or Western\nblot test early in the course of illness can be misleading, as the antibody response is not\ndetected until 3\u20137 weeks after infection. Newer fourth-generation tests further reduce\nthis period of false-negative serologic tests to 2\u22124 weeks. However, individuals such as\nthis with acute HIV infection have a markedly elevated viral load easily detected by\nregular viral tests.\nThe utility of serologic testing such as IgM for infection with herpes simplex virus is\nlimited due to low specificity and high false-positive rates. It would be inappropriate or\nharmful to initiate prednisone in the setting of an undiagnosed infection, with rare\nexceptions such as stress-dose corticosteroids for critical illness. While a skin biopsy\nmay provide information to the clinician to prompt consideration of acute HIV in the\ndifferential diagnosis, it would be more expedient to establish the diagnosis and initiate\ntreatment without subjecting this individual to a biopsy.\nReferences\nGoldschmidt R, Chu C. HIV infection in adults: initial management. Am Fam Physician.\n2021;103(7):407-416.\nSimonetti F, Dewar R, Maldarelli F. Diagnosis of human immunodeficiency virus\ninfection. In: Bennett JE, Dolin R, Blaser MJ, eds. Mandell, Douglas, and Bennett's\nPrinciples and Practice of Infectious Diseases. Vol 2. 9th ed. Elsevier; 2020:1619-1641."},{"n":68,"q":"An asymptomatic 20-year-old female who is sexually active with a new male partner requests testing for sexually transmitted infections. She has had 2 sex partners and uses the subdermal etonogestrel implant (Nexplanon) for contraception. Based on U.S. Preventive Services Task Force guidelines, she should be screened for which one of the following?","o":[{"l":"A","t":"Bacterial vaginosis"},{"l":"B","t":"Infection with Chlamydia trachomatis and Neisseria gonorrhoeae"},{"l":"C","t":"Infection with genital herpes simplex virus"},{"l":"D","t":"Infection with HPV"},{"l":"E","t":"Infection with Mycoplasma genitalium"}],"a":"B","e":"According to recommendations from the U.S. Preventive Services Task Force (USPSTF),\nfemales \u226424 years of age who are sexually active should be screened for Chlamydia\ntrachomatis and Neisseria gonorrhoeae infections. A urine nucleic acid amplification test\n(NAAT) is recommended for screening. The USPSTF does not recommend asymptomatic\nscreening for bacterial vaginosis or infection with Mycoplasma genitalium. The USPSTF\nrecommends against routine serologic screening for infection with genital herpes\nsimplex virus in asymptomatic adolescents and adults. HPV testing screens for cervical\ncancer but is not recommended for patients under 21 years of age.\nReferences\nUS Preventive Services Task Force. Final recommendation statement: cervical cancer:\nscreening. Updated August 21, 2018.\nUS Preventive Services Task Force. Final recommendation statement: Chlamydia and\ngonorrhea: screening. Updated September 14, 2021.\nUS Preventive Services Task Force. Final recommendation statement: genital herpes\ninfection: serologic screening. Updated February 14, 2023.\nUS Preventive Services Task Force. Final recommendation statement: syphilis infection\nin pregnant women: screening. Updated September 4, 2018."},{"n":69,"q":"A 42-year-old female presents with a 4-month history of diffuse pain, fatigue, and sleep disturbances. She says that the pain is the most bothersome symptom. After an extensive history and physical examination, you determine that fibromyalgia is the most likely underlying cause. In addition to encouraging exercise and cognitive behavioral therapy, you opt to initiate pharmacotherapy. Which one of the following pharmacologic agents is most likely to improve her pain?","o":[{"l":"A","t":"Acetaminophen"},{"l":"B","t":"Gabapentin (Neurontin)"},{"l":"C","t":"Naproxen"},{"l":"D","t":"Pregabalin (Lyrica)"},{"l":"E","t":"Tramadol"}],"a":"D","e":"Fibromyalgia is a chronic pain syndrome associated with the disordered processing of\npain. It affects approximately 2% of people in the United States, and women are\ndiagnosed 2\u201314 times more frequently than men. While patient education, exercise,\nand cognitive behavioral therapy can improve pain and functioning (SOR A),\nnonpharmacologic measures often do not provide sufficient symptom relief.\nPharmacologic agents with proven benefit to treat fibromyalgia pain include pregabalin,\namitriptyline, duloxetine, and milnacipran (SOR A). Pregabalin reduces pain by up to\n50% with a number needed to treat of 10. There is insufficient evidence to recommend\nacetaminophen and gabapentin. NSAIDs and opioids do not have demonstrated\nbenefits. An adequate trial consists of a single medication that is started at a low\ndosage, slowly increased until a therapeutic dosage is achieved, and maintained for at\nleast 3 months. Satisfactory treatment should be continued for at least 12 months.\n\nReference\nWinslow BT, Vandal C, Dang L. Fibromyalgia: diagnosis and management. Am Fam\nPhysician. 2023;107(2):137-144."},{"n":70,"q":"A hemoglobin level \u22648 g/dL would be an appropriate RBC transfusion threshold for which one of the following hospitalized patients?","o":[{"l":"A","t":"A 19-year-old with symptomatic sickle cell pain crisis"},{"l":"B","t":"A 63-year-old who is hemodynamically stable after a major trauma"},{"l":"C","t":"A 79-year-old with inoperable femur and hip fractures"},{"l":"D","t":"An 81-year-old who underwent cardiac bypass surgery 3 days ago"},{"l":"E","t":"An 85-year-old with diverticulosis and chronic anemia"}],"a":"D","e":"The transfusion of blood products, specifically RBCs, is a common medical procedure.\nThe transfusion threshold of RBCs for most adults is a hemoglobin level \u22647\u20138 g/dL\n(SOR A). However, a slightly less restrictive transfusion threshold of a hemoglobin level\n\u22648 g/dL should be used for patients who have preexisting cardiovascular disease or are\nundergoing orthopedic or cardiac surgery, such as a patient who underwent cardiac\nbypass surgery 3 days ago (SOR C).\nPatients with sickle cell disease should not receive transfusions for chronic anemia or\nuncomplicated pain crisis without an appropriate clinical indication, and not to a higher\nthreshold than regular adults (SOR C). A restrictive transfusion threshold of a\nhemoglobin level \u22647 g/dL should be used for hospitalized adult patients who are\nhemodynamically stable, including those who are critically ill (SOR C).\nReference\nRaval JS, Griggs JR, Fleg A. Blood product transfusion in adults: indications, adverse\nreactions, and modifications. Am Fam Physician. 2020;102(1):30-38."},{"n":71,"q":"You see a 45-year-old male with a history of opioid use disorder for a health maintenance examination. The patient has successfully remained in a treatment program using methadone, and an examination is normal. He has not had a recent EKG. You order an EKG because which one of the following is a very rare but serious complication of methadone treatment?","o":[{"l":"A","t":"Paroxysmal atrial fibrillation"},{"l":"B","t":"QTc prolongation"},{"l":"C","t":"First-degree heart block"},{"l":"D","t":"Second-degree Mobitz type II heart block"},{"l":"E","t":"Complete heart block"}],"a":"B","e":"QTc prolongation is a very rare but serious complication of methadone treatment.\nExpert organizations recommend obtaining a baseline EKG in patients with other risk\nfactors. Although the optimal strategy for patients with a QTc interval \u2265500 milliseconds\nis debated, physicians should review risks and discuss alternatives to other QTc\nprolongation medications. If the risk of continuing methadone outweighs the high-risk\npotential for opioid overdose with methadone discontinuation, alternatives to\nmethadone can be pursued.\nReference\nTaylor JL, Samet JH. Opioid use disorder. Ann Intern Med. 2022;175(1):ITC1-ITC16."},{"n":72,"q":"Lymphadenopathy in which one of the following sites in a 55-year-old male would suggest malignancy?","o":[{"l":"A","t":"Anterior cervical"},{"l":"B","t":"Posterior cervical"},{"l":"C","t":"Axillary"},{"l":"D","t":"Inguinal"},{"l":"E","t":"Supraclavicular"}],"a":"E","e":"While lymphadenopathy is generally self-limited with a benign etiology,\nlymphadenopathy at the supraclavicular, popliteal, and iliac locations is abnormal.\nEpitrochlear nodes >5 mm in diameter are also abnormal. Because it is associated with\na high risk for intra-abdominal malignancy, supraclavicular lymphadenopathy should be\nevaluated immediately. This applies to both adults and children although patients >40\nyears of age are at highest risk. Studies indicate that 34%\u201350% of these patients with\nsupraclavicular lymphadenopathy have malignancy.\nInfection is a common cause of anterior cervical, posterior cervical, submental, and\nsubmandibular lymphadenopathy. Axillary lymphadenopathy is commonly caused by\ninfections or injuries of the upper extremities. Many healthy adults have inguinal\nlymphadenopathy.\nReference\nGaddey HL, Riegel AM. Unexplained lymphadenopathy: evaluation and differential\ndiagnosis. Am Fam Physician. 2016;94(11):896-903."},{"n":73,"q":"A 15-year-old patient who was recently hospitalized for anorexia nervosa sees you for a follow-up visit in your clinic to discuss the next steps in treatment. Which one of the following therapies is the recommended next step in treatment for this patient?","o":[{"l":"A","t":"Self-guided treatment"},{"l":"B","t":"Cognitive behavioral therapy"},{"l":"C","t":"Focal psychodynamic psychotherapy"},{"l":"D","t":"Interpersonal psychotherapy"},{"l":"E","t":"Family-based therapy"}],"a":"E","e":"Family-based therapy is recommended as first-line therapy for anorexia nervosa in\nadolescents and some young adults. Studies have shown that family-based therapy\nresults in higher remission rates and weight gain than individual therapy such as selfguided treatment, cognitive behavioral therapy, focal psychodynamic psychotherapy,\nand interpersonal psychotherapy. Family-based therapy avoids assigning blame and\ninstead focuses on uniting the family against the disorder. Initially, parents take the\nlead in promoting healthy eating behaviors as the patient slowly gains greater\nautonomy in feeding. The therapy improves family communication and leads to patient\nindependence.\nReference\nKlein DA, Sylvester JE, Schvey NA. Eating disorders in primary care: diagnosis and\nmanagement. Am Fam Physician. 2021;103(1):22-32."},{"n":74,"q":"A 67-year-old female presents for an annual health maintenance examination. She has a history of GERD, asthma, and hypothyroidism. Her last colonoscopy revealed tubular adenomas. She has smoked 1 pack of cigarettes per day since age 20. She does not have any current medical concerns. Which one of the following would be most appropriate for this patient?","o":[{"l":"A","t":"Urinalysis screening for bladder cancer"},{"l":"B","t":"Stool DNA testing (Cologuard) for colon cancer"},{"l":"C","t":"Cytology and HPV co-testing for cervical cancer"},{"l":"D","t":"Annual EKG screening for coronary artery disease"},{"l":"E","t":"Annual low-dose CT screening for lung cancer"}],"a":"E","e":"The U.S. Preventive Services Task Force recommends annual screening for lung cancer\nwith low-dose CT for patients between the ages of 50 and 80 who have more than a\n20-pack-year smoking history and either currently smoke or quit smoking within the\npast 15 years. This patient has a 47-pack-year smoking history, so screening is\nappropriate. Neither screening urinalysis nor screening EKG is recommended in this\nasymptomatic patient. This patient has a history of tubular adenomas so additional\ncolon cancer screening should be with a colonoscopy, not stool DNA testing. Cervical\ncancer screening occurs until age 65.\nReferences\nLangan RC, Goodbred AJ. Pulmonary nodules: common questions and answers. Am\nFam Physician. 2023;107(3):282-291.\nUS Preventive Services Task Force. Final recommendation statement: asymptomatic\nbacteriuria in adults: screening. Updated September 24, 2019.\nUS Preventive Services Task Force. Final recommendation statement: cardiovascular\ndisease risk: screening with electrocardiography. Updated June 12, 2018.\nUS Preventive Services Task Force. Final recommendation statement: colon cancer:\nscreening. Updated May 18, 2021.\nUS Preventive Services Task Force. Final recommendation statement: lung cancer:\nscreening. Updated March 9, 2021."},{"n":75,"q":"Which one of the following is the best agent for controlling edema related to chronic kidney disease?","o":[{"l":"A","t":"Chlorthalidone"},{"l":"B","t":"Furosemide (Lasix)"},{"l":"C","t":"Hydrochlorothiazide"},{"l":"D","t":"Mannitol (Osmitrol)"},{"l":"E","t":"Spironolactone (Aldactone)"}],"a":"B","e":"Furosemide is the loop diuretic of choice for removing excess extracellular fluid volume\nin chronic kidney disease. It has a wide margin of safety and will achieve some degree\nof natriuresis in even the most severe renal failure. Other diuretics have relatively little\neffect.\n\nReferences\nBarman JM, Skorecki K. Chronic kidney disease. In: Loscalzo J, Fauci AS, Kasper DL,\nHauser SL, Longo DL, Jameson JL, eds. Harrison\u2019s Principles of Internal Medicine. Vol 2.\n21st ed. McGraw Hill; 2022:2309-2320.\nBrunton LL, ed. Goodman & Gilman's The Pharmacological Basis of Therapeutics. 11th\ned. McGraw-Hill; 2006:753."},{"n":76,"q":"A 32-year-old female presents with a 1-week history of constant right upper quadrant pain. She underwent a nonemergent outpatient laparoscopic cholecystectomy 3 months ago with an unremarkable recovery and has followed her regular diet for more than 2 months. Her medical history includes seasonal allergies, migraine without aura, and 2 uncomplicated deliveries of healthy infants. Her medications include a monophasic oral contraceptive, as-needed sumatriptan (Imitrex), and as- needed loratadine (Claritin). A review of systems is positive for mild nausea and itching without a rash. She has just completed her withdrawal bleed for this contraceptive cycle. Her vital signs are normal. A physical examination reveals mild tenderness to palpation in the right upper quadrant, and scleral icterus. The patient had not noticed this tenderness prior to examination. Her skin appears faintly icteric. Laboratory studies reveal the following: CBC normal Urine hCG negative Urine dipstick 2+ urobilinogen Bilirubin 6.5 mg/dL (N 0.2\u20131.2) Lipase normal AST 50 U/L (N 0\u201335) ALT 66 U/L (N 0\u201345) Alkaline phosphatase 1382 U/L (N 30\u2013120) Gamma-glutamyl transferase 120 U/L (N 0\u201330) Which one of the following is the most likely cause of this patient\u2019s symptoms?","o":[{"l":"A","t":"Ascending cholangitis"},{"l":"B","t":"Choledocholithiasis of the common bile duct"},{"l":"C","t":"Metabolic dysfunction\u2013associated steatohepatitis (nonalcoholic steatohepatitis)"},{"l":"D","t":"Oral contraceptives"},{"l":"E","t":"Stricture following her surgery"}],"a":"B","e":"This patient has choledocholithiasis with either a retained stone or, more likely, a\nrecurrent stone following cholecystectomy. She has jaundice and her hepatic function\ntests demonstrate a cholestatic pattern: an AST to ALT ratio <1.5, suggesting an\nextrahepatic blockage; an elevated alkaline phosphatase level greater than the ALT and\nAST levels; and an elevated gamma-glutamyl transferase level. Cholangitis would cause\na similar elevation but would be accompanied by an increased WBC count. Metabolic\ndysfunction\u2013associated steatohepatitis (formerly known as nonalcoholic steatohepatitis)\nand oral contraceptives would be unlikely to cause pain. Stricture is far less likely than a\nstone.\nReferences\nCianci P, Restini E. Management of cholelithiasis with choledocholithiasis: endoscopic\nand surgical approaches. World J Gastroenterol. 2021;27(28):4536-4554.\nHall P, Cash J. What is the real function of the liver 'function' tests? Ulster Med J.\n2012;81(1):30-36.\nNg HJ, Nassar AHM. Reinterventions following laparoscopic cholecystectomy and bile\nduct exploration. A review of prospective data from 5740 patients. Surg Endosc.\n2022;36(5):2809-2817."},{"n":77,"q":"A 24-month-old male is brought to your office by his parent. During the examination you notice that he seems to speak fewer words than expected and is very hard to understand. He does not use 2-word phrases, cannot point to any body parts, and has difficulty pointing to items in a book. On further questioning the parent confirms that the toddler speaks fewer than 50 words. Both English and German are spoken in his home. Which one of the following factors puts this patient at risk for the likely diagnosis?","o":[{"l":"A","t":"Being the first born"},{"l":"B","t":"Being the last born"},{"l":"C","t":"A birth weight \u22655000 g (11 lb)"},{"l":"D","t":"Growing up in a multilingual household"},{"l":"E","t":"Male sex"}],"a":"E","e":"This toddler\u2019s delay in speech and language development is a common impairment that\naffects 1 in 8 children in the United States. School-aged children with speech and\nlanguage delays are at greater risk for difficulty learning to read, putting them at risk\nfor less skilled jobs in adulthood. The development of speech and language occurs in\nthe first 6 months of life and is marked by distinct milestones according to age. Because\nexposure to language in early childhood influences a child\u2019s language mastery, parents\nand caregivers play an important role in the development of speech and language.\n\nWhen patients present with concerning signs for delays in speech and language\ndevelopment, early referrals for additional evaluation and treatment can mitigate the\nadverse effects on academic and social development. A large study found that the most\nimportant risk factor for speech and language impairment was male sex. Other risk\nfactors included ongoing hearing problems and birth weight \u22642500 g (5.5 lb). Birth\norder does not have an adverse association with speech and language development.\nChildren growing up in bilingual households should reach language milestones at the\nsame rate as those in monolingual households.\nReference\nRupert J, Hughes P, Schoenherr D. Speech and language delay in children. Am Fam\nPhysician. 2023;108(2):181-188."},{"n":78,"q":"A 73-year-old female presents with chronic diarrhea. You suspect microscopic colitis and order colonoscopy. Based on the suspected diagnosis, you should expect which one of the following colonoscopy findings?","o":[{"l":"A","t":"Granulomas"},{"l":"B","t":"Normal mucosa"},{"l":"C","t":"Patchy ulcerations"},{"l":"D","t":"Pseudomembranes"}],"a":"B","e":"In a patient with microscopic colitis, the most common finding on colonoscopy is normal\nmucosa. Because the mucosa appears normal, microscopic colitis needs to be\ndiagnosed with biopsy. Granulomas may be found in patients with Crohn disease.\nUlcerations are found in ulcerative colitis. Pseudomembranes are found in Clostridioides\ndifficile infection. Granulomatous changes and pseudomembranes may also require\nbiopsy for diagnosis.\nReference\nBurgers K, Lindberg B, Bevis ZJ. Chronic diarrhea in adults: evaluation and differential\ndiagnosis. Am Fam Physician. 2020;101(8):472-480."},{"n":79,"q":"A 24-year-old male presents to your clinic to request suture repair of a 3-cm laceration on his arm caused by an accidental cut with a clean knife the night before. The wound is not actively bleeding and there are not any signs of infection. It would be acceptable to proceed with primary closure up to how many hours after the injury occurred?","o":[{"l":"A","t":"2"},{"l":"B","t":"10"},{"l":"C","t":"18"},{"l":"D","t":"24"},{"l":"E","t":"36"}],"a":"C","e":"Noninfected wounds caused by clean objects can undergo primary closure up to 18\nhours after injury (evidence rating B) without a significant increase in infection rates.\nNoninfected head wounds can be repaired up to 24 hours after injury. These time\nparameters should not be used if there are signs of contamination, the laceration length\nis >5 cm, the laceration is located on the lower extremities, or the patient has diabetes\nmellitus.\n\nReferences\nForsch RT, Little SH, Williams C. Laceration repair: a practical approach. Am Fam\nPhysician. 2017;95(10):628-636.\nQuinn JV, Polevoi SK, Kohn MA. Traumatic lacerations: what are the risks for infection\nand has the 'golden period' of laceration care disappeared? Emerg Med J.\n2014;31(2):96-100."},{"n":80,"q":"Which one of the following causes of bloody diarrhea should prompt further evaluation for hemolytic uremic syndrome?","o":[{"l":"A","t":"Campylobacter bacteria"},{"l":"B","t":"Entamoeba histolytica"},{"l":"C","t":"Salmonella bacteria"},{"l":"D","t":"Shiga toxin\u2013producing Escherichia coli"},{"l":"E","t":"Shigella bacteria"}],"a":"D","e":"Hemolytic uremic syndrome (HUS) is a potential serious complication of Shiga toxin\u2013\nproducing Escherichia coli. Frequent monitoring of hemoglobin and platelet counts,\nelectrolytes, and BUN and creatinine levels is recommended to detect early\nmanifestations of HUS. The other listed causes of bloody diarrhea (Campylobacter\nbacteria, Entamoeba histolytica, Salmonella bacteria, and Shigella bacteria) are not\nassociated with HUS.\nReference\nShane AL, Mody RK, Crump JA, et al. 2017 Infectious Diseases Society of America\nclinical practice guidelines for the diagnosis and management of infectious diarrhea. Clin\nInfect Dis. 2017;65(12):1963-1973."},{"n":81,"q":"Which one of the following cardiovascular changes reflects normal physiology of pregnancy in the first trimester?","o":[{"l":"A","t":"Decreased resting heart rate"},{"l":"B","t":"Increased afterload"},{"l":"C","t":"Increased preload"},{"l":"D","t":"Increased systemic vascular resistance"},{"l":"E","t":"Increased systolic blood pressure"}],"a":"C","e":"Several notable changes occur within the maternal cardiovascular system in the first\ntrimester of pregnancy. A rise in cardiac output results from a combination of 3 primary\nfactors: plasma volume expansion that causes an increase in preload, a decrease in\nafterload that mirrors a decline in systemic vascular resistance, and an increase in the\nresting heart rate compared to the pre-pregnancy state. Other cardiovascular changes\nearly in the course of pregnancy include a reduction in both systolic and diastolic blood\npressures compared to pre-pregnancy measurements.\nReferences\nMaternal physiology. In: Cunningham F, Leveno KJ, Dashe JS, Hoffman BL, Spong CY,\nCasey BM, eds. Williams Obstetrics. 26th ed. McGraw-Hill; 2022:51-81.\nMeah VL, Cockcroft JR, Backx K, Shave R, Stohr EJ. Cardiac output and related\nhaemodynamics during pregnancy: a series of meta-analyses. Heart. 2016;102(7):518526."},{"n":82,"q":"A physically active 25-year-old male presents with foot pain after an injury. X-rays are obtained. A proximal fracture at which one of the following metatarsals would be at the greatest risk for nonunion?","o":[{"l":"A","t":"First"},{"l":"B","t":"Second"},{"l":"C","t":"Third"},{"l":"D","t":"Fourth"},{"l":"E","t":"Fifth"}],"a":"E","e":"Proximal fifth metatarsal fractures are categorized by zones. Zone 2 is located at the\nmetaphyseal-diaphyseal junction at the fourth and fifth metatarsal joint. Zone 3\nfractures are located at the proximal 1.5 cm of the diaphysis.\nBecause of poor blood supply, fractures in zone 2 or zone 3 of the fifth metatarsal have\na risk for slow healing and nonunion. Surgical management of these fractures should be\nconsidered in active patients to decrease the risk for nonunion (SOR B).\nReference\nSilver S, Williams E, Plunkett ML. Common foot fractures. Am Fam Physician.\n2024;109(2):119-129."},{"n":83,"q":"A 70-year-old male with well-controlled hypertension reports that he slipped and fell in his bedroom 2 weeks ago. The fall did not result in any injuries. He has heard that tai chi is effective at reducing fall risk in older adults, but no classes are offered locally. He asks about other options to prevent future falls. You should tell this patient that in older adults, evidence shows that any type of exercise","o":[{"l":"A","t":"decreases fall risk for women but not men"},{"l":"B","t":"decreases health-related quality of life"},{"l":"C","t":"reduces the rate of falls"},{"l":"D","t":"reduces the rate of falls requiring hospital admission"}],"a":"C","e":"Evidence shows that in older, community-dwelling adults, all types of exercise reduce\nthe rate of falls by 23% (rate ratio 0.77, 95% confidence interval [CI] 0.71 to 0.83) and\nthe number of persons experiencing \u22651 falls in 1 year by 15% (risk ratio 0.85, 95% CI\n0.81 to 0.89).\nMore women than men have been studied in exercise research, but exercise appears to\nshow similar reductions in falls for men. Exercise has not been found to make a\nsignificant difference in quality of life in older adults. The evidence is insufficient to\ndetermine if exercise programs decrease fall-related hospital admissions.\nReferences\nLee PG, Jackson EA, Richardson CR. Exercise prescriptions in older adults. Am Fam\nPhysician. 2017;95(7):425-432.\nSherrington C, Fairhall NJ, Wallbank GK, et al. Exercise for preventing falls in older\npeople living in the community. Cochrane Database Syst Rev. 2019;2019(1):CD012424."},{"n":84,"q":"A 76-year-old male with a history of hypothyroidism, type 2 diabetes, remote partial ileocolectomy, and a Schatzki ring treated with dilation presents for follow-up. The review of symptoms is negative, but his spouse has noted some new memory impairment. The patient consumes a healthy vegetarian diet that includes dairy. Recent laboratory studies are significant for a vitamin B deficiency. His 12 current medications include: Atorvastatin (Lipitor) Insulin glargine (Lantus) Levothyroxine (Synthroid) Liraglutide (Victoza) Which one of the following factors in this patient would be the most likely cause of a vitamin B 12 deficiency?","o":[{"l":"A","t":"Diet"},{"l":"B","t":"Diabetic therapy"},{"l":"C","t":"Statin therapy"},{"l":"D","t":"Esophageal condition"},{"l":"E","t":"Surgical history"}],"a":"E","e":"Patients who have undergone removal of the distal ileum are at high risk for vitamin B12\nmalabsorption. Metformin can increase the risk for low vitamin B12, but this patient's\ndiabetic therapy consists of a GLP-1 receptor agonist and insulin. A strict vegan diet,\nbut not vegetarian, is a risk factor for vitamin B12 deficiency. Statins and esophageal\nstrictures are not known to affect vitamin B12 absorption.\nReference\nHoffbrand AV. Megaloblastic anemias. In: Loscalzo J, Fauci AS, Kasper DL, Hauser SL,\nLongo DL, Jameson JL, eds. Harrison's Principles of Internal Medicine. Vol 1. 21st ed.\nMcGraw-Hill; 2022:766-776."},{"n":85,"q":"A 68-year-old male with coronary artery disease, major depression, and hypertension presents for routine follow-up. He currently smokes a half-pack of cigarettes per day and asks what options are available to help with smoking cessation. Which one of the following would be the most effective treatment for smoking cessation?","o":[{"l":"A","t":"Bupropion (Wellbutrin SR) only"},{"l":"B","t":"Varenicline only"},{"l":"C","t":"Bupropion plus nicotine gum (Nicorette Gum)"},{"l":"D","t":"Varenicline plus nicotine gum"},{"l":"E","t":"The nicotine patch (Nicoderm CQ) plus nicotine gum"}],"a":"D","e":"There are several pharmaceutical options available to aid in smoking cessation.\nVarenicline is the most effective medical option and is safe in patients with mental\nhealth conditions. Current evidence suggests that the addition of nicotine replacement\ntherapy (NRT) to varenicline improves smoking cessation rates. Both NRT and\nbupropion are effective for smoking cessation, but are not as effective as varenicline.\nCurrent evidence is insufficient to recommend a combination of NRT and bupropion.\nReference\nGaddey HL, Dakkak M, Jackson NM. Smoking cessation interventions. Am Fam\nPhysician. 2022;106(5):513-522."},{"n":86,"q":"A 78-year-old male with a history of hypertension, type 2 diabetes, ongoing tobacco use, and carotid endarterectomy presents to the emergency department with bloody diarrhea and severe lower abdominal pain. Which one of the following is the most likely diagnosis?","o":[{"l":"A","t":"Angiodysplasia"},{"l":"B","t":"Arteriovenous malformation"},{"l":"C","t":"Colon cancer"},{"l":"D","t":"Irritable bowel syndrome"},{"l":"E","t":"Ischemic colitis"}],"a":"E","e":"The differential diagnosis for the painful rectal bleeding in this patient includes\ninflammatory bowel disease, infectious colitis, hemorrhoids, and ischemic colitis. The\npatient's multiple risk factors for vascular disease place him at higher risk for ischemic\ncolitis. The differential diagnosis for painless rectal bleeding includes angiodysplasia,\narteriovenous malformation, colon cancer, diverticular bleeding, and post-polypectomy\nbleeding. Irritable bowel syndrome does not cause rectal bleeding.\nReference\nHawks MK, Svarverud JE. Acute lower gastrointestinal bleeding: evaluation and\nmanagement. Am Fam Physician. 2020;101(4):206-212."},{"n":87,"q":"A 35-year-old male presents to the urgent care clinic this morning after he became lost while hiking and was trapped outdoors overnight. He stayed in freezing temperatures with no preparation and was wearing light daytime clothing. He reports a sensation of pins and needles and very sensitive skin in his left index and middle fingers. On examination his vital signs are normal, including a core temperature of 37.0 \u00b0C (98.6 \u00b0F). His skin is normal except for his left index and middle fingers, which appear pale. Which one of the following would be the most appropriate initial treatment?","o":[{"l":"A","t":"Slow rewarming by remaining indoors at room temperature"},{"l":"B","t":"Rapid rewarming using body heat by placing the hand in the axilla"},{"l":"C","t":"Rapid rewarming in front of a dry heat source"},{"l":"D","t":"Rapid rewarming in a warm water bath"},{"l":"E","t":"Rapid rewarming using small chemical heating pads"}],"a":"D","e":"This patient has signs and a history of exposure indicative of frostbite. Treatment of\nfrostbite requires thorough evaluation of the patient and treatment of hypothermia, if\npresent. It is important to wait to rewarm until the chance of refreezing is low. Rapid\nrewarming should be performed in a water bath at 98.6\u2013102.2 \u00b0F (37.0\u201339.0 \u00b0C). The\naffected extremity should be swirled in the water, avoiding the bath edge, until the skin\nappears red or purple and is soft to the touch. Slow rewarming is not recommended for\nfrostbite. Using body heat by placing the hand in the axilla is not a method of rapid\nrewarming, although it can be used for spontaneous thawing if rapid rewarming is not\npossible. Dry heat should not be used due to difficulty maintaining a stable\ntemperature. Small chemical heating pads that are often used for hands should be\navoided as they can cause burns. The degree of injury related to frostbite cannot be\ndetermined until after rewarming, which will determine further steps in treatment.\nReference\nRathjen NA, Shahbodaghi SD, Brown JA. Hypothermia and cold weather injuries. Am\nFam Physician. 2019;100(11):680-686."},{"n":88,"q":"A patient is considering hormonal contraception, and you counsel her regarding the potential for abnormal uterine bleeding. Which one of the following contraceptives is most associated with abnormal uterine bleeding that is less likely to improve with time?","o":[{"l":"A","t":"A combined oral contraceptive with continuous dosing"},{"l":"B","t":"A combined oral contraceptive with cyclic dosing"},{"l":"C","t":"Medroxyprogesterone acetate (Depo-Provera CI)"},{"l":"D","t":"An etonogestrel implant (Nexplanon)"},{"l":"E","t":"A levonorgestrel IUD (Mirena)"}],"a":"D","e":"Abnormal uterine bleeding is a common issue for patients taking hormonal\ncontraception, and family physicians should engage in shared decision-making with\npatients regarding its potential duration.\nFrequent or prolonged bleeding can occur in up to 23% of patients using the\netonogestrel implant, and this bleeding is less likely to improve over time. Patients on\neither continuous or cyclic combined oral contraceptives can be counseled to expect\nbleeding abnormalities during the first 3 months. The estrogen component helps with\ncycle control because it stabilizes the endometrium. Patients tend to have amenorrhea\nand lighter menses after 6\u201312 months of medroxyprogesterone acetate use (SOR B).\nWhile up to 35% of patients with the levonorgestrel IUD experience frequent or\nprolonged bleeding in the first 3 months of use, most have a reduction in uterine\nbleeding within 12 months (SOR B).\nReference\nSchrager S, Fox K, Lee R. Abnormal uterine bleeding associated with hormonal\ncontraception. Am Fam Physician. 2024;109(2):161-166."},{"n":89,"q":"A 55-year-old female presents with lateral hip pain. You suspect greater trochanteric pain syndrome and prescribe anti-inflammatory medications and physical therapy. If her pain does not respond to these measures, which one of the following alternative diagnoses is most likely?","o":[{"l":"A","t":"Femoroacetabular impingement"},{"l":"B","t":"Gluteus medius tendon tear"},{"l":"C","t":"Ischiofemoral impingement"},{"l":"D","t":"Labral tear"},{"l":"E","t":"Piriformis syndrome"}],"a":"B","e":"The most common cause of lateral hip pain is greater trochanteric pain syndrome\n(formerly referred to as greater trochanteric bursitis), which can be caused by gluteus\nmedius tendinopathy or tearing, or iliotibial band friction. A gluteus medius tendon tear\nshould be considered in patients with greater trochanteric pain syndrome that does not\nrespond to anti-inflammatory medications and physical therapy. MRI and/or\nmusculoskeletal ultrasonography can be used for further diagnosis if a gluteus medius\ntendon tear is suspected, and surgical intervention may improve outcomes in these\npatients.\nFemoroacetabular impingement is a cause of intra-articular hip pain that usually\npresents with anterior pain. It is caused by bony overgrowth of the femoral head and\nneck or by a pincer deformity of the acetabulum and is usually bothersome with\nactivities that require hyperflexion or a wide range of motion at the hip joint.\nIschiofemoral impingement is caused by impingement of the quadratus femoris muscle\nand nerve between the proximal femur at the level of the lesser trochanter and ischial\ntuberosity, resulting in deep buttock pain worsened by activities requiring a long stride.\nLabral tears are associated with anterior hip pain and may cause a popping, catching,\nor clicking sound with activities. Piriformis syndrome is caused by the piriformis\nentrapping the sciatic nerve, and causes hip and buttock pain as well as sciatica.\nReference\nChamberlain R. Hip pain in adults: evaluation and differential diagnosis. Am Fam\nPhysician. 2021;103(2):81-89."},{"n":90,"q":"A 15-year-old male is brought to your office for a sports preparticipation evaluation. You obtain a medical history and perform a physical examination, including elements from the American Heart Association's (AH 14-point screening evaluation. According to the AHA 14-point screening evaluation, which one of the following findings would warrant an EKG prior to clearing this patient for participation in sports?","o":[{"l":"A","t":"Elevated systemic blood pressure"},{"l":"B","t":"Complete recovery from mild COVID-19 diagnosed 14 days ago"},{"l":"C","t":"A family history of coronary artery bypass surgery in a 65-year-old grandfather"},{"l":"D","t":"A family history of mitral stenosis due to rheumatic heart disease in a 45-year-old aunt"},{"l":"E","t":"A coach\u2019s request for an EKG"}],"a":"A","e":"The American College of Cardiology/American Heart Association (ACC/AHA) recommend\nobtaining an EKG prior to clearance for sports participation only in a patient who has a\npositive result, such as elevated systemic blood pressure, on the AHA 14-point\nscreening evaluation. An athlete with COVID-19 and mild symptoms should rest and\navoid exercise for 14 days after diagnosis and may then return to sports if\nasymptomatic. A family history of cardiac problems or sudden death prior to age 50 is a\nqualifying element; however, a history of rheumatic heart disease in a relative would\nnot be relevant. A coach\u2019s preference is not a qualifying element.\n\nReferences\nACC/AHA release recommendations for congenital and genetic heart disease screenings\nin youth. American College of Cardiology. September 15, 2014.\nSchefft M, Wolf ER, Quinonez R, Haskell H, James J. Appropriate use of\nelectrocardiography in preparticipation physical evaluations. Am Fam Physician.\n2022;105(3):302-306."},{"n":91,"q":"A 50-year-old male sees you for follow-up of hypertension. His only medications are hydrochlorothiazide and lisinopril (Zestril). He does not smoke cigarettes or drink alcohol, and he does not have any concerns today. Examination findings are unremarkable. A comprehensive metabolic panel is normal, but a CBC reveals a platelet count of 110,000/mm3 (N 150,000\u2013450,000). A repeat platelet count is 115,000/mm3. Which one of the following would be the most appropriate initial test?","o":[{"l":"A","t":"A prothrombin time and partial thromboplastin time"},{"l":"B","t":"A peripheral blood smear"},{"l":"C","t":"A serum haptoglobin level"},{"l":"D","t":"Serum protein electrophoresis"},{"l":"E","t":"Bone marrow aspiration"}],"a":"B","e":"This patient has mild thrombocytopenia, defined as a platelet count of 100,000\u2013\n150,000/mm3. Moderate thrombocytopenia is defined as a platelet count of 50,000\u2013\n99,000/mm3 and severe thrombocytopenia as <50,000/mm3. This can be due to splenic\nsequestration, decreased production, increased destruction, consumption in immune\ncomplexes or thrombi, or platelet clumping.\nThe initial test is examination of a peripheral blood smear to look for evidence of\nclumping, giant platelets, or fragmented RBCs. If the smear is normal except for\ndecreased platelets, then the problem would be drug-induced thrombocytopenia or\nimmune thrombocytopenic purpura.\nObtaining a prothrombin time and partial thromboplastin time is a rapid way to test the\nintegrity of the clotting cascade. A serum haptoglobin level can be used to confirm\nhemolysis. Serum protein electrophoresis would be utilized if there is suspicion of\nmonoclonal gammopathy. Referral to a hematologist for bone marrow evaluation is\nrecommended for moderate to severe disease.\nReference\nGauer RL, Whitaker DJ. Thrombocytopenia: evaluation and management. Am Fam\nPhysician. 2022;106(3):288-298."},{"n":92,"q":"A 68-year-old male presents to your office because of a sudden onset of pain and cold sensation in the right lower leg that began 3 hours ago. He rates his pain as 9 out of 10. He has a past medical history of hypertension, coronary artery disease with a coronary artery bypass graft 3 years ago, and stage 3a chronic kidney disease. He currently smokes cigarettes. His vital signs include a blood pressure of 160/85 mm Hg, a heart rate of 99 beats/min with regular rhythm, a respiratory rate of 18/min, and an oxygen saturation of 94% on room air. An examination reveals a right lower leg that is cold at the midcalf and right foot without palpable or Doppler pedal pulses. Doppler imaging reveals a venous hum. His capillary refill is very slow, and there is a loss of pinprick sensation in all of the toes of the right foot. His motor ability is maintained. You hear a possible faint bruit over the right femoral artery. Which one of the following is the most appropriate next step in management?","o":[{"l":"A","t":"Urgent outpatient echocardiography"},{"l":"B","t":"Urgent outpatient arteriography of the right leg"},{"l":"C","t":"Emergent referral to the emergency department (ED) for evaluation by a vascular subspecialist"},{"l":"D","t":"Aspirin, 650 mg, plus sublingual nitroglycerin, and ambulance transfer to the ED"},{"l":"E","t":"Hospital admission for heparin infusion"}],"a":"C","e":"This patient has acute limb ischemia (ALI), a medical emergency with possible\nirreversible limb loss within 4\u20136 hours. According to the American Heart Association,\nemergent revascularization is recommended to salvage this patient\u2019s limb. An emergent\nreferral to a vascular subspecialist is the most appropriate immediate action. Depending\non location, this may be a vascular surgeon, a radiologist with invasive vascular\ntreatment ability, or a cardiovascular or general surgeon with peripheral vascular\ntraining and expertise. Determining the source of the thrombosis is not as urgent as\nlimb salvage. Arteriography is a possible aspect of limb salvage but is not the entire\nprocedure. Aspirin, nitroglycerin, and transfer to an emergency department is\nappropriate for acute coronary thrombosis but not for ALI. Anticoagulation is required\nbut is not a sufficient treatment.\nReferences\nFirnhaber JM, Powell CS. Lower extremity peripheral artery disease: diagnosis and\ntreatment. Am Fam Physician. 2019;99(6):362-369.\nGerhard-Herman MD, Gornik HL, Barrett C, et al. 2016 AHA/ACC guideline on the\nmanagement of patients with lower extremity peripheral artery disease: a report of the\nAmerican College of Cardiology/American Heart Association Task Force on Clinical\nPractice Guidelines. Circulation. 2017;135(12):e726-e779."},{"n":93,"q":"A 23-month-old toddler is brought to the clinic with a temperature of 38.2 \u00b0C (100.7 \u00b0F). The parents say the child has been urinating more frequently. A urine dipstick and culture confirm a urinary tract infection. After treatment with an antibiotic, which one of the following would be the most appropriate next step?","o":[{"l":"A","t":"A repeat urine culture"},{"l":"B","t":"Antibiotic prophylaxis"},{"l":"C","t":"Renal and bladder ultrasonography"},{"l":"D","t":"A voiding cystourethrogram"},{"l":"E","t":"A dimercaptosuccinic acid (DMSA) renal scan"}],"a":"C","e":"The American Academy of Pediatrics recommends renal and bladder ultrasonography in\nchildren \u226424 months of age after a first episode of febrile urinary tract infection (UTI)\nto assess for vesicoureteral reflux. A voiding cystourethrogram is indicated if there are\nabnormal findings on ultrasonography. A repeat urine culture and prophylactic antibiotic\ntherapy are not indicated in this case. Most children do not need a dimercaptosuccinic\nacid (DMSA) renal scan after a first episode of UTI.\nReferences\nMattoo TK, Shaikh N, Nelson CP. Contemporary management of urinary tract infection\nin children. Pediatrics. 2021;147(2):e2020012138.\nVeauthier B, Miller MV. Urinary tract infections in young children and infants: common\nquestions and answers. Am Fam Physician. 2020;102(5):278-285."},{"n":94,"q":"A 38-year-old female with uncontrolled hypertension, prediabetes, and polycystic ovary syndrome sees you for follow-up. Her past surgical history includes a cesarean delivery and a tubal ligation. She is concerned because she has not had any menstrual bleeding in the past 5 months. A urine pregnancy test today is negative. Which one of the following would be the most appropriate treatment?","o":[{"l":"A","t":"No medication"},{"l":"B","t":"Drospirenone/ethinyl estradiol (Yaz) daily"},{"l":"C","t":"Levonorgestrel/ethinyl estradiol (Jolessa) continuous cycle daily"},{"l":"D","t":"Medroxyprogesterone (Provera) for 10 days every 3 months"},{"l":"E","t":"A copper IUD (Paragard)"}],"a":"D","e":"This patient has oligomenorrhea in the setting of polycystic ovary syndrome (PCOS).\nPatients with PCOS have a relative excess of estrogen stimulation of the endometrium\nand are at risk for endometrial hyperplasia and cancer. Combined hormonal\ncontraceptives or medications that contain progesterone reduce this risk by stabilizing\nthe endometrium, as well as improving excess androgen. Intermittent progestin therapy\nis the most appropriate option for this patient. Levonorgestrel-containing IUDs would\nalso be an option. Hypertension is a relative contraindication for estrogen use, and this\npatient does not need hormonal contraception.\nReference\nJoham AE, Norman RJ, Stener-Victorin E, et al. Polycystic ovary syndrome. Lancet\nDiabetes Endocrinol. 2022;10(9):668-680."},{"n":95,"q":"A 65-year-old patient presents to your office for an annual health maintenance examination. You discuss vaccination recommendations, and the patient reports having received the live zoster vaccine 8 years ago. Which one of the following should you recommend regarding herpes zoster (shingles) vaccination?","o":[{"l":"A","t":"No further vaccination"},{"l":"B","t":"No further vaccination if laboratory testing reveals immunity"},{"l":"C","t":"One dose of recombinant zoster vaccine (Shingrix)"},{"l":"D","t":"Two doses of recombinant zoster vaccine"},{"l":"E","t":"Two doses of live varicella vaccine (Varivax)"}],"a":"D","e":"The CDC\u2019s Advisory Committee on Immunization Practices recommends recombinant\nzoster vaccine for the prevention of herpes zoster (shingles) infection for\nimmunocompetent patients age 50 and older. The vaccine is given as a series of 2\ndoses, administered 2\u20136 months apart. For patients who previously received live zoster\nvaccine, the full 2-dose series of recombinant vaccine is recommended.\nReferences\nDooling KL, Guo A, Patel M, et al. Recommendations of the Advisory Committee on\nImmunization Practices for use of herpes zoster vaccines. MMWR Morb Mortal Wkly\nRep. 2018;67(3):103-108.\nGreenberg GM, Koshy PA, Hanson MJS. Adult vaccination. Am Fam Physician.\n2022;106(5):534-542."},{"n":96,"q":"Which one of the following studies should be obtained in all toddlers with suspected physical abuse?","o":[{"l":"A","t":"A funduscopic examination"},{"l":"B","t":"Skeletal survey radiography"},{"l":"C","t":"Head CT without contrast"},{"l":"D","t":"Abdominal CT with contrast"},{"l":"E","t":"A bone scan"}],"a":"B","e":"The American Academy of Pediatrics and the American College of Radiology guidelines\nrecommend that all children with suspected physical abuse undergo a skeletal survey,\nparticularly those who are \u22642 years of age. A funduscopic examination should be\nobtained if retinal hemorrhages are suspected in children <2 years. Head CT without\ncontrast is indicated if there is a concern for subdural, subarachnoid, or\nintraparenchymal injury. Abdominal CT with contrast is recommended if there is a\nconcern for intra-abdominal injuries. A bone scan should be obtained if there is a\nconcern for occult fractures up to 2 weeks after injury.\nReferences\nChristian CW; Committee on Child Abuse and Neglect, American Academy of Pediatrics.\nThe evaluation of suspected child physical abuse. Pediatrics. 2015;135(5):e1337-1354.\nExpert Panel on Pediatric Imaging; Wootton-Gorges SL, Soares BP, et al. ACR\nAppropriateness Criteria suspected physical abuse-child. J Am Coll Radiol.\n2017;14(5S):S338-S349.\nSuniega EA, Krenek L, Stewart G. Child abuse: approach and management. Am Fam\nPhysician. 2022;105(5):521-528."},{"n":97,"q":"A 72-year-old female presents with suspected tinnitus. She describes a long-standing, low-grade ringing in both ears that seems to be worsening over time. She started using hearing aids last month for a recent diagnosis of presbycusis, but the tinnitus has not improved. It is nonpulsatile and not associated with any other symptoms including headache, numbness, tingling, or weakness. Examination findings, including a neurologic examination and an ear examination, are normal except for her known hearing loss. Which one of the following has the best evidence of improving quality of life in patients such as this?","o":[{"l":"A","t":"Carbamazepine (Tegretol)"},{"l":"B","t":"Acupuncture"},{"l":"C","t":"Cognitive behavioral therapy"},{"l":"D","t":"Transcranial magnetic stimulation"},{"l":"E","t":"Surgical microvascular decompression"}],"a":"C","e":"Tinnitus is a common problem with unknown etiology that can significantly impact\nquality of life. It can signify a more concerning underlying neurologic condition such as\nvestibular schwannoma, and it is also associated with the use of medications that cause\nototoxicity and with sensorineural hearing loss. Acute tinnitus can occur with otitis\nmedia, middle ear effusion, and cerumen impaction. Patients with tinnitus that is severe\nenough to cause distress should have an audiologic evaluation. Head imaging is only\nrequired in the setting of asymmetric or pulsatile tinnitus, asymmetric hearing loss, or\nabnormal neurologic findings.\nThe treatment with the best evidence of improved quality of life related to tinnitus is\ncognitive behavioral therapy. Hearing aids may alleviate tinnitus in hearing-impaired\npatients. Individuals with depression or anxiety related to their tinnitus should receive\ntreatment for those conditions. Anticonvulsants such as carbamazepine do not have\nevidence of benefit and are not recommended. Other therapies with insufficient\nevidence of benefit include acupuncture, transcranial magnetic stimulation, surgical\ndecompression of cranial nerve VIII, and hyperbaric oxygen.\n\nReference\nDalrymple SN, Lewis SH, Philman S. Tinnitus: diagnosis and management. Am Fam\nPhysician. 2021;103(11):663-671."},{"n":98,"q":"A 72-year-old female presents with pain in her right foot after missing a step while descending a staircase. She was leading with her right foot when she stumbled. On examination she has tenderness in the right dorsal and plantar midfoot. Foot x-rays are normal. An image of the right plantar foot is shown below. Which one of the following would be most appropriate at this time?","o":[{"l":"A","t":"Non\u2013weight bearing status, plus CT or MRI"},{"l":"B","t":"Corticosteroid injection"},{"l":"C","t":"Heel splints and physical therapy"},{"l":"D","t":"Rigid ankle support and physical therapy"},{"l":"E","t":"Rigid ankle support and referral to an orthopedic surgeon"}],"a":"A","e":"This patient has a Lisfranc injury of the right midfoot. Lisfranc injuries occur to the\ntarsometatarsal joint complex of the foot, which is stabilized by a complex ligamentous\nstructure. Injuries can range from simple subluxations to complex fractures with\ndislocations. Falling forward on a plantar-flexed foot, such as when missing a stair step,\nis a common mechanism of injury. Forced dorsiflexion, which often occurs in sports or\nmotor vehicle collisions, is another common mechanism. Missed Lisfranc injuries can\nlead to instability, deformity, and painful chronic osteoarthritis of the midfoot.\nX-rays are the first step in diagnosis but have a sensitivity of around 84%. Plantar\nbruising is a classic sign and should trigger a high index of suspicion for Lisfranc injury\neven with negative plain or weight-bearing x-rays, and CT or MRI should be ordered. If\na Lisfranc injury is seen on imaging or is highly suspected, the patient should remain\nnon\u2013weight bearing. Depending on the severity of the injury, referral to an orthopedic\nsurgeon may be warranted after definitive imaging. Corticosteroid injection, heel splints,\nrigid ankle support, and physical therapy are not appropriate at this time.\nReferences\nGrewal US, Onubogu K, Southgate C, Dhinsa BS. Lisfranc injury: a review and simplified\ntreatment algorithm. Foot (Edinb). 2020;45:101719.\nSilver S, Williams E, Plunkett ML. Common foot fractures. Am Fam Physician.\n2024;109(2):119-129."},{"n":99,"q":"A previously healthy 67-year-old female presents with a 3-month history of new progressive low and middle back pain despite physical therapy and analgesics. She has also noted an onset of fatigue and weight loss. Results of a CBC and comprehensive metabolic panel are notable for normocytic anemia, hypercalcemia, and an elevated creatinine level. Which one of the following tests would help confirm the suspected diagnosis?","o":[{"l":"A","t":"Anti\u2013cyclic citrullinated peptide (anti-CCP) antibody"},{"l":"B","t":"Antimitochondrial antibody"},{"l":"C","t":"Creatine phosphokinase"},{"l":"D","t":"Erythrocyte sedimentation rate"},{"l":"E","t":"Serum free light chains  Item #98"}],"a":"E","e":"This patient\u2019s case is highly consistent with multiple myeloma. In patients with\nsuspected multiple myeloma, the measurement of serum free light chain levels as well\nas serum and urine protein electrophoresis can help confirm the diagnosis. Free light\nchains, including the subtypes kappa and lambda, are smaller components of\nimmunoglobulins that are typically bound to heavy chains. In multiple myeloma,\nelevated levels of one of these unbound or \"free\" light chains can be found in the\nserum, or in the urine as the Bence Jones protein. A ratio of involved to uninvolved free\nlight chains \u2265100 and an involved free light chain concentration of \u226510 mg/dL is part of\nthe diagnostic criteria for multiple myeloma.\n\nAn anti\u2013cyclic citrullinated peptide (anti-CCP) antibody test is used to confirm a\ndiagnosis of rheumatoid arthritis. Testing for antimitochondrial antibodies is used to\nassess for primary biliary cirrhosis. A creatine phosphokinase test is used as a marker of\nmuscle damage. An erythrocyte sedimentation rate is a nonspecific marker of\ninflammation.\nReference\nCowan AJ, Green DJ, Kwok M, et al. Diagnosis and management of multiple myeloma: a\nreview. JAMA. 2022;327(5):464-477."},{"n":100,"q":"The U.S. Preventive Services Task Force recommends screening which one of the following groups for obstructive sleep apnea (OSA)?","o":[{"l":"A","t":"All adults >50 years of age"},{"l":"B","t":"All adults who have \u22651 first-degree relative with documented OSA"},{"l":"C","t":"All adults who have a BMI \u226535 kg/m2"},{"l":"D","t":"All adults who have hypertension"},{"l":"E","t":"No groups should be routinely screened"}],"a":"E","e":"In November 2022, the U.S. Preventive Services Task Force concluded that the current\nevidence was insufficient to assess the balance of benefits and harms of screening for\nobstructive sleep apnea (OSA) in the general adult population (I recommendation). This\napplies to all adults \u226518 years of age without signs of OSA or with unrecognized\nsymptoms of OSA. This recommendation also includes persons who are unaware of or\nare unconcerned by their symptoms.\nReference\nUS Preventive Services Task Force. Final recommendation statement: obstructive sleep\napnea in adults: screening. Updated November 15, 2022."},{"n":101,"q":"A 62-year-old male presents to your office with a 3-month history of increasing dyspnea and cough. He has a history of allergic rhinitis and uses fluticasone propionate nasal spray (Flonase) daily. He has a 15-pack-year smoking history but quit more than 20 years ago. He has a family history of asthma in both his mother and 1 sibling. Examination findings include a respiratory rate of 18/min and an oxygen saturation of 92% on room air. His lung sounds are diminished with scattered rhonchi and no wheezes. The remainder of the examination findings are normal. Spirometry shows an FEV /FVC ratio of 0.6 and the FEV is 70% 1 1 of predicted with no improvement with a bronchodilator. Which one of the following is the most likely cause of his dyspnea?","o":[{"l":"A","t":"Asthma"},{"l":"B","t":"Bronchiectasis"},{"l":"C","t":"COPD"},{"l":"D","t":"Heart failure"},{"l":"E","t":"Pulmonary fibrosis"}],"a":"C","e":"The most likely cause of this patient\u2019s dyspnea is COPD. This patient has an obstructive\npattern on spirometry with an FEV1/FVC ratio <0.7 and no improvement with\nadministration of a bronchodilator, which rules out asthma and is consistent with COPD.\nBronchiectasis is associated with a purulent cough and recurrent lower respiratory tract\ninfections on imaging. Heart failure is unlikely because there are no signs of fluid\noverload and this patient\u2019s presentation is more consistent with COPD. Pulmonary\nfibrosis shows a restrictive pattern on spirometry.\nReferences\nCagle SD Jr, Landrum LS, Kennedy AM. Chronic obstructive pulmonary disease:\ndiagnosis and management. Am Fam Physician. 2023;107(6):604-612.\nZeller TA, Beben K, Walker S. Distinguishing asthma and COPD in primary care: a casebased approach. Am Fam Physician. 2023;107(3):247-252."},{"n":102,"q":"A 17-year-old student athlete is brought to your office for evaluation of a head injury that occurred earlier today. The patient was playing soccer when she performed a header and struck the ball with her head. She reports a frontal headache and mild nausea. Neurologic examination findings are normal. Which one of the following would be the most appropriate management?","o":[{"l":"A","t":"A rest period of at least 24\u201348 hours"},{"l":"B","t":"A brief course of prednisone"},{"l":"C","t":"Returning to normal daily activities only when she is symptom-free"},{"l":"D","t":"Head CT"}],"a":"A","e":"Most guidelines recommend a brief rest period of at least 24\u201348 hours following a\nconcussion. No medications are available specifically for concussion. A more\nconservative approach, including a longer rest period before returning to activity/play, is\nrecommended for children and adolescents with concussions. Guidelines recommend\nwaiting until the child or adolescent has successfully tolerated return to school before\nresuming full activity or play. After an initial brief period of rest, individuals with\nconcussions should be encouraged to gradually return to normal daily activities such as\nschool, work, or leisure activities as tolerated. Children do not need to be asymptomatic\nto return to school. Imaging should be used only to eliminate concerns of more\nsignificant injuries and not for evaluation of uncomplicated concussion.\nReference\nScorza KA, Cole W. Current concepts in concussion: initial evaluation and management.\nAm Fam Physician. 2019;99(7):426-434."},{"n":103,"q":"A 68-year-old male presents for his annual Medicare wellness visit. A routine alcohol screen finds that he consumes 2 drinks every night, but twice per month he consumes 5 or more drinks. However, the screening does not reveal symptoms of alcohol use disorder. Which one of the following would be the most appropriate clinical response to address his alcohol use?","o":[{"l":"A","t":"No intervention"},{"l":"B","t":"A brief counseling intervention"},{"l":"C","t":"Disulfiram"},{"l":"D","t":"Naltrexone"},{"l":"E","t":"Referral for cognitive behavioral therapy"}],"a":"B","e":"This patient drinks more than the recommended amount of alcohol and is at increased\nrisk for associated adverse clinical outcomes such as atrial fibrillation, disordered sleep,\nand cancers of the gastrointestinal tract. A brief counseling intervention is\nrecommended and has been consistently shown to decrease alcohol consumption in\nadults. Medical therapy or a referral to a mental health specialist can be very helpful\nsteps in further treatment once a diagnosis of alcohol use disorder has been established\nand the patient has shown readiness and motivation to change.\nReferences\nAlcohol and pregnancy: alcohol screening and brief intervention (SBI). Centers for\nDisease Control and Prevention. May 15, 2024.\nWinslow BT, Onysko M, Hebert M. Medications for alcohol use disorder. Am Fam\nPhysician. 2016;93(6):457-465."},{"n":104,"q":"A 25-year-old primigravida at 30 weeks\u2019 gestation presents with a 2-week history of intense pruritus of the palms and soles. The pregnancy has otherwise been uncomplicated. There are no skin lesions on examination. A CBC is unremarkable, but a metabolic panel is notable for the following: ALT 85 U/L (N 7\u201355) AST 75 U/L (N 8\u201348) Alkaline phosphatase 140 U/L (N 45\u2013114) Bilirubin 1.8 mg/dL (N 0.1\u20131.2) Which one of the following tests is most likely to confirm the diagnosis?","o":[{"l":"A","t":"An acute hepatitis profile"},{"l":"B","t":"A bile acid level"},{"l":"C","t":"A gamma-glutamyl transferase level"},{"l":"D","t":"Ultrasonography of the liver"},{"l":"E","t":"A punch biopsy of the skin"}],"a":"B","e":"Intrahepatic cholestasis of pregnancy can occur in up to 2% of pregnancies and is most\nfrequent in the second or third trimester. The condition causes severe pruritus initially\noccurring on the palms and soles without skin lesions. The pruritus may become\ngeneralized, and excoriations are often noted due to scratching. Liver enzymes may be\nmildly elevated and up to 10% of patients develop jaundice. A diagnosis can be made\nclinically and by elevated serum bile acid levels. The maternal prognosis is good, but\nthe elevated bile acids present a risk for the fetus, and fetal surveillance should be\ninitiated at the time of diagnosis. Due to the risk for preterm labor and fetal demise,\ndelivery at 36\u201337 weeks\u2019 gestation is recommended. Antihistamines can be used to\ncontrol pruritus, and ursodeoxycholic acid can be used to bind bile acids.\nHepatitis is a reasonable consideration, but this clinical picture is more compatible with\nintrahepatic cholestasis of pregnancy. A serum gamma-glutamyl transferase level would\ntest for liver inflammation but would not add any useful information. Liver\nultrasonography should be performed if obstruction is suspected. A skin biopsy may\nreveal excoriations but would not be diagnostic.\nReference\nErlandson M, Wertz MC, Rosenfeld E. Common skin conditions during pregnancy. Am\nFam Physician. 2023;107(2):152-158."},{"n":105,"q":"Which one of the following endocrine abnormalities is associated with an increased rate of hidradenitis suppurativa?","o":[{"l":"A","t":"Diabetes mellitus"},{"l":"B","t":"Hyperparathyroidism"},{"l":"C","t":"Hyperthyroidism"},{"l":"D","t":"Hypopituitarism"},{"l":"E","t":"Hypothyroidism"}],"a":"A","e":"Hidradenitis suppurativa is a chronic inflammatory disease of the skin that\npredominantly affects the apocrine glands of the axillae and the groin. Multiple\nsystematic reviews and meta-analyses have shown an increased association of\nhidradenitis suppurativa with type 2 diabetes. Associations have also been seen with\ncardiovascular risk factors such as metabolic syndrome, increased BMI, and smoking.\nCurrent research has not demonstrated any association with pituitary or thyroid\ndisorders.\nReferences\nBettoli V, Naldi L, Cazzaniga S, et al. Overweight, diabetes and disease duration\ninfluence clinical severity in hidradenitis suppurativa-acne inversa: evidence from the\nnational Italian registry. Br J Dermatol. 2016;174(1):195-197.\nBui TL, Silva-Hirschberg C, Torres J, Armstrong AW. Hidradenitis suppurativa and\ndiabetes mellitus: a systematic review and meta-analysis. J Am Acad Dermatol.\n2018;78(2):395-402.\n\nFrew JW. Hidradenitis suppurativa and diabetes: big data bias masks a true association.\nClin Exp Dermatol. 2019;44(4):e151-e152.\nPhan K, Charlton O, Smith SD. Hidradenitis suppurativa and diabetes mellitus: updated\nsystematic review and adjusted meta-analysis. Clin Exp Dermatol. 2019;44(4):e126e132."},{"n":106,"q":"A new vaccine is being developed. The risk for infection after vaccination is 19%. The risk for infection without vaccination is 47%. What is the relative risk of the subjects who received the newly manufactured vaccine?","o":[{"l":"A","t":"0.10"},{"l":"B","t":"0.28"},{"l":"C","t":"0.40"},{"l":"D","t":"0.66"},{"l":"E","t":"0.90"}],"a":"C","e":"The relative risk (risk ratio) of infection for the participants who received the newly\ndeveloped vaccine compared to those who did not is 0.40. The risk ratio is calculated by\ndividing the risk of the population under study by the risk of the population who is not\n(those who are vaccinated and those who are not, respectively): 0.19/0.47 = 0.40. In\nother words, vaccinated participants were 40% as likely (or 60% less likely) to contract\nthe infection as those who were not vaccinated.\nReference\nDicker RC, Coronado F, Koo D, Gibson RG. Lesson three: measures of risk: measures of\nassociation. In: Dicker RC, Coronado F, Koo D, Gibson RG. Principles of Epidemiology in\nPublic Health Practice: An Introduction to Applied Epidemiology and Biostatistics. 3rd\ned. US Dept of Health and Human Services; 2006:3-39\u22123-51."},{"n":107,"q":"A 39-year-old female presents to discuss long-standing dysmenorrhea and menorrhagia. Her symptoms have been present for years and have not significantly changed. She is up to date on cervical cancer screening and does not have any risk factors for sexually transmitted infections. She has given birth once and does not wish to conceive again. She has a medical history of hypertension that is well controlled on amlodipine (Norvasc). On bimanual examination you note a slightly enlarged uterus with some mild tenderness and no cervical motion tenderness. You suspect adenomyosis. Which one of the following would be the most appropriate next step to confirm the diagnosis?","o":[{"l":"A","t":"Transvaginal ultrasonography"},{"l":"B","t":"CT of the pelvis"},{"l":"C","t":"MRI of the pelvis"},{"l":"D","t":"Hysteroscopy"},{"l":"E","t":"Endometrial biopsy"}],"a":"A","e":"The preferred initial diagnostic test for patients with suspected adenomyosis is a\ntransvaginal ultrasound. CT scans are not helpful in the diagnosis. While there is higher\nspecificity with MRI of the pelvis, its cost and availability make it a less desirable first\nchoice. Hysteroscopy may be helpful if the diagnosis is in question due to an\ninconclusive ultrasound. Endometrial biopsy does not aid in the diagnosis of\nadenomyosis, but it may be indicated to evaluate for hyperplasia or malignancy in a\npatient who is older or has worsening symptoms.\nReference\nSchrager S, Yogendran L, Marquez CM, Sadowski EA. Adenomyosis: diagnosis and\nmanagement. Am Fam Physician. 2022;105(1):33-38."},{"n":108,"q":"A 76-year-old female presents to the emergency department after a fall when stepping out of the shower. Her past medical history is notable for hypothyroidism, severe asthma, and a low BMI. Her vital signs are normal, but she is unable to bear weight on the left lower extremity. The left lower extremity is shortened and externally rotated with intact neurovascular status. The left anterior groin is also tender to palpation. Which one of the following would be the most appropriate next step?","o":[{"l":"A","t":"Radiography of the hip and pelvis"},{"l":"B","t":"Ultrasonography of the left leg to evaluate for a blood clot"},{"l":"C","t":"CT of the hip and pelvis"},{"l":"D","t":"MRI of the left hip"},{"l":"E","t":"Evaluation by a physical therapist"}],"a":"A","e":"This patient has sustained a traumatic left hip fracture after falling while getting out of\nthe shower. Hip fractures can present with anterior groin pain and the affected\nextremity is often visually deformed with external rotation, shortening, and abduction.\nAssuming the patient is stable and has an intact neurovascular status, the most\nappropriate next step would be to order radiography of the hip and pelvis. CT or MRI\nwould be indicated if x-rays were negative but a high suspicion for fracture persists. Hip\nfractures do increase the risk for blood clot, and ultrasonography could be performed if\nclotting were a concern, but this would not be the first diagnostic step for this patient. A\nphysical therapist should be consulted after making a diagnosis and developing a\ntreatment plan.\nReference\nSchroeder JD, Turner SP, Buck E. Hip fractures: diagnosis and management. Am Fam\nPhysician. 2022;106(6):675-683."},{"n":109,"q":"A 26-year-old nulliparous female presents for an evaluation after she discovered a breast mass while showering. An examination confirms a 4 \u00d7 3-cm nonpainful mass in the upper outer quadrant of the right breast. Which one of the following should you recommend?","o":[{"l":"A","t":"Screening mammography of the breast"},{"l":"B","t":"Diagnostic mammography of the breast"},{"l":"C","t":"Ultrasonography of the breast"},{"l":"D","t":"MRI of the breast"},{"l":"E","t":"Surgical referral for excision and biopsy"}],"a":"C","e":"Diagnostic mammography is typically the preferred imaging modality for a palpable\nbreast mass. However, ultrasonography is more sensitive in women younger than 30\nyears of age and is preferred. Screening mammography should be performed biennially\nfor asymptomatic women ages 40\u221274. MRI is not appropriate for this patient at this\ntime. Surgical excision and biopsy would be necessary if abnormalities are found on\nimaging.\nReferences\nSalzman B, Collins E, Hersh L. Common breast problems. Am Fam Physician.\n2019;99(8):505-514.\nUS Preventive Services Task Force. Final recommendation statement: breast cancer:\nscreening. Updated April 30, 2024."},{"n":110,"q":"A 30-year-old female with no past medical history presents for a routine health maintenance examination. Although she currently has a sedentary lifestyle, she is motivated to begin an exercise program to improve her health and reduce her risk for cardiovascular disease. She asks for specific examples of exercise plans that would be most likely to provide this benefit. According to guidelines from the American College of Cardiology/American Heart Association, 5 days per week of which one of the following would be the most appropriate recommendation for this patient?","o":[{"l":"A","t":"10 minutes of running"},{"l":"B","t":"20 minutes of brisk walking"},{"l":"C","t":"30 minutes of water aerobics"},{"l":"D","t":"40 minutes of stretching"},{"l":"E","t":"50 minutes of casual walking"}],"a":"C","e":"The American College of Cardiology/American Heart Association (ACC/AHA)\nrecommends that adults engage in a minimum of 150 minutes of moderate-intensity or\n75 minutes of vigorous-intensity aerobic physical activity per week, or an equivalent\ncombination of moderate-intensity and vigorous-intensity aerobic activity, to reduce the\nrisk for cardiovascular disease. Examples of moderate-intensity aerobic physical activity\ninclude brisk walking, ballroom dancing, active yoga, water aerobics, cycling on level\nground, and doubles tennis. Examples of vigorous-intensity activities include jogging or\nrunning, swimming laps, cycling vigorously or on uneven ground, and playing singles\ntennis or basketball.\nOf the examples given in this scenario, only 30 minutes of water aerobics (a moderateintensity activity) 5 days per week meets the minimum recommended level of aerobic\nexercise. Casual walking, a light-intensity aerobic activity, is more favorable than\nsedentary behavior for reducing cardiovascular risk, but light-intensity activities do not\ncontribute toward reducing cardiovascular disease risk as effectively as moderate- and\nvigorous-intensity activities, according to ACC/AHA guidelines.\nReferences\nArnett DK, Blumenthal RS, Albert MA, et al. 2019 ACC/AHA guideline on the primary\nprevention of cardiovascular disease: a report of the American College of\nCardiology/American Heart Association Task Force on Clinical Practice Guidelines.\nCirculation. 2019;140(11):e596-e646.\nPhysical activity guidelines for Americans. 2nd ed. US Department of Health and Human\nServices. 2018."},{"n":111,"q":"A 6-year-old female is brought to the urgent care clinic for evaluation of a cough that has persisted for more than 2 months. The cough is dry and nonproductive and seems worse when she goes outside in the cold weather. She has not had any recent illnesses. She does not have any wheezing or shortness of breath. Her vital signs and an examination are normal. A chest x-ray is unremarkable. Which one of the following next steps in evaluation should be recommended to determine the most likely underlying cause?","o":[{"l":"A","t":"Reassurance that no further testing is needed at this time"},{"l":"B","t":"Polymerase chain reaction testing for pertussis"},{"l":"C","t":"Spirometry"},{"l":"D","t":"Bronchoscopy"},{"l":"E","t":"24-hour esophageal pH monitoring"}],"a":"C","e":"This patient most likely has cough variant asthma, a common cause of chronic (lasting\n>8 weeks) cough in children. The minimum appropriate testing for all children with\nchronic cough is chest x-ray and spirometry. Polymerase chain reaction testing for\npertussis is indicated in children who have had a recent upper respiratory tract illness\nthat develops into a classic whooping cough. Bronchoscopy should be considered if\nthere is a history of cough that started and persisted after a choking episode,\nsuggestive of foreign body aspiration. GERD is another common cause of chronic cough\nbut can usually be diagnosed by response to an empiric trial of an antacid medication\nand does not require 24-hour esophageal pH monitoring.\n\nReference\nMichaudet C, Malaty J. Chronic cough: evaluation and management. Am Fam Physician.\n2017;96(9):575-580."},{"n":112,"q":"A 45-year-old female sees you to discuss chronic insomnia. She typically falls asleep fairly easily but awakens throughout the night and has difficulty falling back asleep. Her episodes of wakefulness are not caused by restless legs, pain, urinary frequency, or snoring. She has tried cognitive behavioral therapy and melatonin without improvement and would like to try a prescription medication that is not habit forming. Which one of the following medications has the best evidence of efficacy and safety to help improve her insomnia?","o":[{"l":"A","t":"Diphenhydramine"},{"l":"B","t":"Doxepin (Silenor)"},{"l":"C","t":"Quetiapine (Seroquel)"},{"l":"D","t":"Temazepam (Restoril)"},{"l":"E","t":"Trazodone"}],"a":"B","e":"Low-dose doxepin has the best evidence of efficacy and safety to address this patient\u2019s\nchronic insomnia with impaired sleep maintenance. Dosages of 3\u20136 mg nightly have\nbeen found to increase sleep efficiency and total sleep time. At this low dosage the\nadverse effect and safety profile was similar to placebo, even in older adults. It is\nthought that doxepin\u2019s mechanism of action is via an antihistamine effect, and the\npatient should be counseled about the possibility of anticholinergic side effects such as\nnext-day sleepiness.\nDiphenhydramine, a strong antihistamine, is typically much more sedating and is\nassociated with other anticholinergic side effects. It is not recommended for routine use\nfor insomnia. The antipsychotic quetiapine is sedating but should not be used in the\nabsence of a psychiatric condition such as bipolar disorder. Benzodiazepines such as\ntemazepam are sedating and can improve sleep onset but carry a significant risk for\nphysical dependence, and long-term use is not recommended. The antidepressant\ntrazodone is often used off-label to treat insomnia but evidence for this approach is\nweak and it should not be recommended as first-line therapy.\nReferences\nDrugs for chronic insomnia. Med Lett Drugs Ther. 2023;65(1667):1-6.\nMatheson E, Hainer BL. Insomnia: pharmacologic therapy. Am Fam Physician.\n2017;96(1):29-35."},{"n":113,"q":"A healthy 16-year-old male presents to your office for a sports preparticipation evaluation. The patient\u2019s parent has a close family friend with diabetes mellitus and asks you about screening the adolescent for the condition. He has no signs or symptoms of diabetes. Which one of the following is the current U.S. Preventive Services Task Force recommendation regarding screening for prediabetes and type 2 diabetes in children and adolescents?","o":[{"l":"A","t":"They should not be screened"},{"l":"B","t":"They should be screened only if they have a strong family history of type 2 diabetes"},{"l":"C","t":"They should be screened only if they have morbid obesity"},{"l":"D","t":"They should routinely be screened"},{"l":"E","t":"There is not enough evidence to make a recommendation for or against screening"}],"a":"E","e":"The most recent recommendation from the U.S. Preventive Services Task Force\nregarding screening for prediabetes and type 2 diabetes in children and adolescents\nstates that there is not enough evidence to recommend for or against screening.\nClinicians should use their judgment when recommending screening for particular\npatients and keep in mind that there may be harm caused by screening. Some\nadolescents may have a transient physiologic period of insulin resistance during\npuberty, which can spontaneously revert to a normal state. Screening these patients\nmay lead to overdiagnosis, labeling, and overtreatment.\n\nReferences\nMills J, Barnhart H. Screening for prediabetes and type 2 diabetes in children and\nadolescents. Am Fam Physician. 2023;107(1):79-80.\nUS Preventive Services Task Force. Final recommendation statement: prediabetes and\ntype 2 diabetes in children and adolescents: screening. Updated September 13, 2022."},{"n":114,"q":"A 30-year-old gravida 2 para 2 sees you for evaluation of bothersome palpitations. She is 2 weeks post partum and is breastfeeding the infant. Her medications include ferrous sulfate and sertraline (Zoloft). On physical examination she has a temperature of 36.7 \u00b0C (98.1 \u00b0F), a blood pressure of 130/82 mm Hg, and a respiratory rate of 12/min. Her heart rate is 120 beats/min with occasional extra heartbeats noted. Examination findings are otherwise normal. A CBC and comprehensive metabolic panel are normal, and a TSH level is 0.2 \u03bcU/mL (N 0.5\u20134.0). An EKG reveals tachycardia and occasional premature atrial contractions. Which one of the following would be the most appropriate initial management?","o":[{"l":"A","t":"Observation only"},{"l":"B","t":"Discontinuing sertraline"},{"l":"C","t":"Adding an antithyroid medication"},{"l":"D","t":"Adding a \u03b2-blocker"},{"l":"E","t":"A radioactive iodine uptake scan"}],"a":"D","e":"This patient has postpartum thyroiditis, a destructive triphasic condition that can occur\nafter pregnancy. This patient is in the hyperthyroid phase, which is followed by a\nhypothyroid phase that can last 3\u201312 months. The final stage is euthyroidism. \u03b2Blockers are used for symptomatic treatment in the hyperthyroid phase. Observation\nonly is not appropriate in this patient since she is symptomatic. While amiodarone and\nlithium can affect the thyroid, sertraline does not. Antithyroid medication is not\nindicated. A radioactive iodine uptake scan is contraindicated in a patient who is\nbreastfeeding.\nReference\nMartinez Quintero B, Yazbeck C, Sweeney LB. Thyroiditis: evaluation and treatment. Am\nFam Physician. 2021;104(6):609-617."},{"n":115,"q":"A 4-year-old male with sickle cell disease is brought to the emergency department with left upper quadrant abdominal pain. He has a hemoglobin level of 7.0 g/dL, and his usual hemoglobin level is 10.0 g/dL. A reticulocyte count is elevated above his normal, and his platelet count is 125,000/mm3 (N 150,000\u2013400,000). Which one of the following is the most likely etiology?","o":[{"l":"A","t":"Acute chest syndrome"},{"l":"B","t":"Acute pain crisis"},{"l":"C","t":"Aplastic anemia"},{"l":"D","t":"Splenic sequestration"},{"l":"E","t":"An upper gastrointestinal bleed"}],"a":"D","e":"The normal hemoglobin level in a patient with sickle cell anemia is 6\u201311 g/dL. Acute\nanemia, defined as a drop of \u22652 g/dL in the hemoglobin level, is not a normal finding in\nsickle cell crisis. In children, the most likely cause of acute anemia is splenic\nsequestration. Emergency treatment with RBCs is needed because shock may develop\nquickly. The typical presentation of this emergent condition includes acute anemia, a\nlow platelet level, and left upper quadrant pain and tenderness. Acute pain crises\nshould generally not have the hemoglobin decrease seen in this patient and\ntransfusions are not routine management. Another prominent cause of acute anemia is\nan aplastic crisis, which is usually accompanied by a significant decrease in the\nreticulocyte count. This would not be a usual presentation of acute chest syndrome,\nand an upper gastrointestinal bleed would not be a likely cause of this patient\u2019s\ncondition.\nReference\nKavanagh PL, Fasipe TA, Wun T. Sickle cell disease: a review. JAMA. 2022;328(1):5768."},{"n":116,"q":"A 58-year-old female presents with concerns about hair loss. She has noticed increased hair shedding over the last few years and has recently noticed hair thinning. On examination she has thinning at the center frontal hairline. You diagnose female pattern hair loss. She is interested in a topical or systemic treatment. Which one of the following would be the most appropriate initial pharmacologic treatment for this patient\u2019s hair loss?","o":[{"l":"A","t":"Topical estradiol"},{"l":"B","t":"Topical minoxidil (Rogaine)"},{"l":"C","t":"Transdermal testosterone (AndroGel)"},{"l":"D","t":"Oral medroxyprogesterone (Provera)"},{"l":"E","t":"Oral spironolactone (Aldactone)"}],"a":"B","e":"The initial pharmacologic management for female pattern hair loss is topical minoxidil.\nTopical finasteride in combination with topical minoxidil has also been shown to be\nefficacious. Similarly, oral spironolactone may be efficacious when used in combination\nwith topical minoxidil, but there is no evidence for spironolactone as monotherapy.\nWhile low estrogen levels likely play a role in female pattern hair loss, there is no\ncurrent evidence that using estrogen, progestin, or testosterone is helpful and these are\nnot recommended.\nReference\nBertoli MJ, Sadoughifar R, Schwartz RA, Lotti TM, Janniger CK. Female pattern hair loss:\na comprehensive review. Dermatol Ther. 2020;33(6):e14055."},{"n":117,"q":"A 55-year-old female who is hospitalized for acute pancreatitis and alcohol intoxication expresses a desire for discharge against medical advice on day 2 of her admission. Which one of the following additional factors would represent a CONTRAINDICATION to immediate discharge in this case?","o":[{"l":"A","t":"A current manifestation of mild alcohol withdrawal syndrome"},{"l":"B","t":"A history of major depression with a past suicide attempt"},{"l":"C","t":"An inability to demonstrate appreciation of her medical situation"},{"l":"D","t":"A lack of health insurance"},{"l":"E","t":"An unstable housing situation"}],"a":"C","e":"Discharges against medical advice comprise approximately 1%\u20132% of all hospital\ndischarges and are challenging encounters to navigate. In such situations,\ncommunication, patient safety, and follow-up planning are of paramount importance. In\nassessing a patient who has requested discharge against medical advice, one of the\nprimary tasks is to determine if the patient has the capacity to make this decision.\nDecision-making capacity evaluation involves 4 key components. The patient must be\nable to (1) understand the pertinent medical information, (2) appreciate the medical\nsituation and potential consequences, (3) demonstrate logical reasoning of the various\ntreatment options, and (4) communicate a choice. In this patient scenario, an inability\nto demonstrate appreciation of the medical situation and possible consequences of\nbeing discharged against the advice of the medical team would represent a\ncontraindication to discharging the patient without further evaluation. For a patient who\ncannot demonstrate decision-making capacity, the next step is to consult an advance\ndirective or surrogate decision-maker. If neither is available, the hospital ethics\ncommittee and medicolegal team should be contacted to provide further guidance.\nWhile moderate or severe alcohol withdrawal with associated mental status impairment\nlikely would impair decision-making capacity, mild alcohol withdrawal syndrome alone\nwould not contraindicate a discharge against medical advice. Active suicidal ideation\nmay represent temporary impairment of decision-making capacity and psychiatric\nconsultation is advised in such cases. This patient's history of depression with a past\nsuicide attempt is not a contraindication to granting a request for discharge against\nmedical advice. Neither a lack of health insurance nor an unstable housing situation\nwould contraindicate a discharge against medical advice, although these factors should\nbe considered in disposition and follow-up planning, with an effort to optimize the\npatient\u2019s safety in transitioning care to the outpatient setting.\nReferences\nBarstow C, Shahan B, Roberts M. Evaluating medical decision-making capacity in\npractice. Am Fam Physician. 2018;98(1):40-46.\nMerrell B, Gauer R. The challenges of discharge against medical advice: conflict and\nconsequences. Am Fam Physician. 2023;108(2):193-196."},{"n":118,"q":"A 55-year-old female sees you because of weakness in the left leg. She has a history of hypertension, type 2 diabetes, osteoarthritis of the knees, and degenerative disk disease of the cervical and lumbar spines. An examination is notable for focal weakness on dorsiflexion of her left foot and extension of her toes, and a neurologic examination is otherwise normal. Which one of the following is the most likely explanation for these findings?","o":[{"l":"A","t":"Cervical myelopathy"},{"l":"B","t":"Diabetic neuropathy"},{"l":"C","t":"L4 nerve root impingement"},{"l":"D","t":"Peroneal nerve compression"},{"l":"E","t":"Tarsal tunnel syndrome"}],"a":"D","e":"The most common cause of foot drop is a compression neuropathy of the peroneal\n(also known as common fibular) nerve, most often at the fibular head just distal to the\nlateral knee. Tight-fitting braces and casts as well as prolonged leg crossing can cause\nthis neuropathy. Cervical myelopathy may cause lower extremity weakness, but it may\nalso cause numbness and upper motor neuron findings such as hyperreflexia. Diabetic\nneuropathy is typically bilateral and symmetric and rarely causes motor weakness. L5,\nbut not L4, nerve root impingement can also cause foot drop. Tibial nerve compression\nat the tarsal tunnel causes pain into the lateral midfoot, but it does not lead to foot\ndrop.\nReference\nAmato AA, Barohn RJ. Peripheral neuropathy. In: Loscalzo J, Fauci AS, Kasper DL,\nHauser SL, Longo DL, Jameson JL, eds. Harrison's Principles of Internal Medicine. Vol 2.\n21st ed. McGraw-Hill; 2022:3480-3501."},{"n":119,"q":"A 71-year-old male with no significant past medical history presents to establish care now that he has health insurance. He has not seen a doctor in more than 20 years. He has no symptoms or current health concerns, and he does not take any medications. He quit smoking 18 years ago after smoking 2 packs per day for 30 years. He rarely drinks alcohol and regularly bicycles for exercise. He has not been sexually active since his partner died 12 years ago. He has a blood pressure of 129/89 mm Hg, a heart rate of 86 beats/min, a respiratory rate of 16/min, and a BMI of 26 kg/m2. Physical examination findings are normal. Based on U.S. Preventive Services Task Force guidelines, which one of the following screening tests is recommended for this patient?","o":[{"l":"A","t":"Bone density testing"},{"l":"B","t":"Hemoglobin A 1c"},{"l":"C","t":"Hepatitis C antibody testing"},{"l":"D","t":"HIV testing"},{"l":"E","t":"Low-dose chest CT"}],"a":"C","e":"The U.S. Preventive Services Task Force (USPSTF) recommends screening for hepatitis\nC virus (HCV) infection in persons at risk for infection and also one-time screenings for\nall adults between 18 and 79 years of age (B recommendation). The USPSTF gives an I\nrecommendation to bone density screening. Diabetes mellitus screening with a\nhemoglobin A1c is not recommended because this patient is 71 years of age. Screening\nis recommended in adults 35\u221270 years of age with a BMI that is in the overweight or\nobese categories. This patient is over the age of 65 and no risk factors are noted, so\nHIV screening is not indicated. Lung cancer screening with low-dose CT of the chest is\nnot recommended because the patient quit smoking >15 years ago.\nReference\nUS Preventive Services Task Force. Published recommendations. Updated 2023."},{"n":120,"q":"A fully vaccinated 4-year-old female is brought to your office in September because of a 10-day history of febrile upper respiratory illness. During that time, she tested negative for COVID-19, influenzas A and B, Streptococcus, and respiratory syncytial virus. She appeared to be slowly improving, but today she has begun to report pain in her right shoulder and thigh. This morning she refused to eat her breakfast and choked on her milk. She was unable to dress unassisted today. On examination she is afebrile with normal vital signs, appears tired, and is not speaking as clearly as usual. She has clear nasal discharge, no adenopathy, normal tympanic membranes, a supple neck, and clear lungs. There is no heart murmur. She can rise from her chair but cannot bear weight on her right leg. Her grip strength is good bilaterally, but she cannot raise her right arm against gravity. Reflexes at the right biceps and patella are absent. Her tongue muscles appear weak on examination. You realize her sleepy appearance is due to a mild degree of bilateral ptosis. Which one of the following would be the most appropriate next step?","o":[{"l":"A","t":"Starting oral amoxicillin/clavulanate (Augmentin)"},{"l":"B","t":"Starting oral prednisone"},{"l":"C","t":"Checking IgG and IgM levels for Epstein-Barr virus and cytomegalovirus"},{"l":"D","t":"Obtaining MRI of the right hip"},{"l":"E","t":"Sending her to the emergency department for hospital admission"}],"a":"E","e":"This patient most likely has acute flaccid myelitis (AFM), a disease first named in 2014\nto describe a rapid onset of flaccid limb weakness without a known cause. Most cases\nfollow a viral febrile illness; the disease can progress rapidly to respiratory failure and\ndangerous autonomic instability. When AFM is suspected, patients should be\nimmediately admitted to a hospital capable of intensive care support. Collecting samples\nfor analysis is important but should not delay admission, nor should infectious disease\nconsultation. Corticosteroids may also be administered once the patient is hospitalized,\nalthough human evidence is lacking in this condition. AFM cases have increased rapidly\nsince the condition was first recognized. The disease occurs predominantly in younger\nchildren and causes a nondemyelinating injury to the central grey matter of the spinal\ncord. This is best discerned via MRI and helps to differentiate this disease from acute\ntransverse myelitis, Guillain-Barr\u00e9 syndrome, or multiple sclerosis. Deficits are\nfrequently proximal and do not follow an ascending pattern, and they may include\ncranial nerves. Family physicians should be aware of this condition and prepared to\nrespond with the urgency required.\nReferences\nAcute flaccid myelitis: clinicians & health departments. Centers for Disease Control and\nPrevention. Reviewed August 16, 2022.\nFang X, Huda R. Acute flaccid myelitis (AFM): current status and diagnostic challenges.\nJ Clin Neurol. 2020;16(3):376-382."},{"n":121,"q":"While performing a mental status examination, you request that the patient spell \u201cworld\u201d backward. This test assesses which one of the following mental status components?","o":[{"l":"A","t":"Attention"},{"l":"B","t":"Executive function"},{"l":"C","t":"Memory"},{"l":"D","t":"Orientation"},{"l":"E","t":"Visuospatial proficiency"}],"a":"A","e":"The mental status examination is used to differentiate among conditions such as\ndelirium, dementia, mania, and depression. The components of the mental status\nexamination include attention, executive function, memory, orientation, and visuospatial\nproficiency. Attention is assessed by asking the patient to spell a word backward or\ncount backward by 7s or 5s. Drawing a clock face with the hands at the 11:10 position\ntests for executive function. Memory is tested by asking the patient to repeat 3 words,\nallowing 5 minutes to elapse, and then asking the patient to recall the words.\nOrientation is assessed by asking the year, day, time, location, or name. Visuospatial\nproficiency is tested by requesting that the patient copy intersecting pentagons or a 3dimensional cube on paper. Another option is to draw a triangle and request that the\npatient draw the same shape upside down.\n\nReference\nWiley AT, Dreher JW, London JD. Mental status examination in primary care. Am Fam\nPhysician. 2024;109(1):51-60."},{"n":122,"q":"A 3-month-old male is brought to your office by his parents with a 6-week history of stridor that worsens when the infant is lying down and when he eats. On examination the infant appears well and is in no respiratory distress. His lungs are clear, and his growth curve is stable at the 85th percentile for both weight and length. You note subtle stridor with each inhalation that is more pronounced when he feeds. Which one of the following is the most likely diagnosis?","o":[{"l":"A","t":"Bacterial tracheitis"},{"l":"B","t":"Croup"},{"l":"C","t":"Epiglottitis"},{"l":"D","t":"Foreign body aspiration"},{"l":"E","t":"Laryngomalacia"}],"a":"E","e":"This well-appearing child with chronic stridor most likely has the chronic condition\nlaryngomalacia, in which the supraglottic structures collapse over the trachea during\ninhalation and result in the characteristic stridor. Symptoms typically begin between 1\nand 2 months of age and are often chronic. Affected children are otherwise well. The\nstridor may be more pronounced with eating, and in some cases can lead to impaired\nweight gain or choking, cyanosis, or aspiration with feeding. As the child grows, the\ntrachea will also grow and the condition will resolve.\nBacterial tracheitis, croup, and epiglottitis are all acute, infectious causes of stridor.\nForeign body aspiration is typically an acute presentation that is more common in older\nchildren who are able to grasp and manipulate foreign objects more easily.\nReference\nSkirko J. Childhood respiratory conditions: stridor. FP Essent. 2022;513:25-31."},{"n":123,"q":"A 35-year-old female presents with a swollen right index finger after accidentally slamming the car door on the finger yesterday. She has constant pain of the distal finger but no throbbing under her fingernail. On examination the end of the right index finger is swollen, and she has a small subungual hematoma. She is able to flex and extend the distal interphalangeal (DIP) joint with some pain, but has normal strength. An x-ray shows a transverse fracture across the distal phalanx that does not involve the joint. Which one of the following is the optimal treatment plan for this patient?","o":[{"l":"A","t":"Ice, NSAIDs, and DIP flexion as tolerated"},{"l":"B","t":"Draining the subungual hematoma and bandaging the finger"},{"l":"C","t":"Buddy taping the finger for 3\u20134 weeks"},{"l":"D","t":"Splinting the DIP joint in full extension for 4\u20136 weeks"},{"l":"E","t":"Referral to an orthopedic surgeon"}],"a":"D","e":"A distal phalanx fracture can occur after a crush injury or direct force to the end of the\nfinger. The affected finger will have swelling, bruising, and often a subungual\nhematoma. Simple fractures can be managed with splinting in extension for 4\u20136 weeks\nwith a finger guard or U-shaped aluminum splint. Hematomas that are more than 50%\nof the nail bed surface can be drained with a hot needle or instrument. Buddy taping is\nused for minimally angled middle or proximal phalanx fractures that do not involve the\njoints. A patient who is unable to flex or extend the distal interphalangeal (DIP) joint,\nhas decreased sensation, or has a complex fracture extending into the joint should be\nreferred to an orthopedic surgeon.\nReference\nChildress MA, Olivas J, Crutchfield A. Common finger fractures and dislocations. Am\nFam Physician. 2022;105(6):631-639."},{"n":124,"q":"Which one of the following is an effective topical treatment for postinflammatory hyperpigmentation in persons with Fitzpatrick skin types IV, V, and VI?","o":[{"l":"A","t":"Ammonium lactate 12% lotion (Lac-Hydrin)"},{"l":"B","t":"Clindamycin 1% gel (Clindagel)"},{"l":"C","t":"Hydrocortisone 1% cream (Cortizone-10)"},{"l":"D","t":"Hydroquinone 4% cream"},{"l":"E","t":"Metronidazole 0.75% gel"}],"a":"D","e":"There are a variety of topical therapies for the treatment of postinflammatory\nhyperpigmentation in persons with Fitzpatrick skin types IV, V, and VI, including\nhydroquinone, fluocinolone/hydroquinone/tretinoin, and azelaic acid. Adapalene,\ntretinoin, and tazarotene are also acceptable options for hyperpigmentation associated\nwith acne. Ammonium lactate 12% lotion, clindamycin 1% gel, hydrocortisone 1%\ncream, and metronidazole 0.75% gel are not effective topical therapies for\npostinflammatory hyperpigmentation in such patients.\nReference\nFrazier WT, Proddutur S, Swope K. Common dermatologic conditions in skin of color.\nAm Fam Physician. 2023;107(1):26-34."},{"n":125,"q":"A 12-year-old female is brought to your clinic for a sports preparticipation evaluation for volleyball. Her family history is significant for a paternal grandfather with cardiovascular disease. In early childhood, she was diagnosed with atopic dermatitis and mild intermittent asthma that is controlled with a short-acting bronchodilator. The review of systems is unremarkable except for occasional shortness of breath when she is exposed to cats. On examination in a supine position, a systolic nonradiating murmur is best heard over the left upper sternal border. The murmur decreases with the Valsalva maneuver. Which one of the following is the most likely diagnosis?","o":[{"l":"A","t":"An atrial septal defect"},{"l":"B","t":"Hypertrophic obstructive cardiomyopathy"},{"l":"C","t":"Mitral valve prolapse"},{"l":"D","t":"A pulmonary flow murmur"},{"l":"E","t":"Tricuspid stenosis"}],"a":"D","e":"A pulmonary flow murmur is an innocent systolic harsh murmur most commonly\nidentified in adolescents and best heard at the left upper sternal border with minimal\nradiation. It is reduced when the Valsalva maneuver is performed. Atrial septal defects\npresent as midsystolic murmurs best heard over the left upper sternal border. They\nradiate to the back and start softly then intensify in sound. Hypertrophic obstructive\ncardiomyopathy causes a midsystolic murmur heard over the left lower sternal border\nand apex. It is enhanced by the Valsalva maneuver. A mitral valve prolapse murmur is\nenhanced with the Valsalva maneuver in late systole, has a midsystolic click, and\nradiates to the apex. Tricuspid stenosis is a pathologic mid-diastolic murmur heard over\nthe left lower sternal border. It increases with deep inspiration.\nReference\nFord B, Lara S, Park J. Heart murmurs in children: evaluation and management. Am\nFam Physician. 2022;105(3):250-261."},{"n":126,"q":"A 36-year-old patient presents to the emergency department (E for the third time this month for fevers \u2265101 \u00b0F. Extensive workups at past visits have not identified an etiology. The patient does not take any medications and has not traveled recently. Today a C-reactive protein level and an erythrocyte sedimentation rate are elevated, but a CBC, urinalysis, and chest x-ray are normal. Blood cultures are pending and prior cultures have been negative. A complete physical examination is unremarkable with no sign of localized infection or disease. Which one of the following would be the most appropriate next step?","o":[{"l":"A","t":"Oral naproxen, 500 mg"},{"l":"B","t":"Intravenous ceftriaxone, 1 g, plus intravenous azithromycin (Zithromax), 500 mg"},{"l":"C","t":"Fluorodeoxyglucose (FDG)-PET/CT"},{"l":"D","t":"Exploratory laparotomy"},{"l":"E","t":"Bone marrow biopsy"}],"a":"C","e":"Fever of unknown origin (FUO) in adults is defined as a clinically documented fever\n\u226538.3 \u00b0C (101 \u00b0F) that occurs on multiple occasions without a clear diagnosis. Most\ncases of FUO are due to common diseases. About 75% of all cases of FUO in adults\nresolve spontaneously without a determined diagnosis.\n\nWhen an initial workup is unremarkable, imaging with fluorodeoxyglucose (FDG)PET/CT is helpful in identifying an inflammatory, infectious, or neoplastic cause (SOR B)\nwith sensitivities ranging from 86% to 98% and specificities from 52% to 85%. It is\nestimated that a diagnosis is found in >50% of patients using FDG-PET/CT.\nPatients who are neither neutropenic nor severely immunocompromised should not be\nstarted on empiric antibiotics (SOR C) or anti-inflammatories, as these have not been\nshown to effectively treat FUO. Previously, exploratory laparotomy was preferred in the\nworkup of FUO but is now no longer indicated as the accuracy of less invasive\ndiagnostic tests, such as CT, has increased. Bone marrow biopsy is not indicated in this\npatient with a normal CBC.\nReferences\nDavid A, Quinlan JD. Fever of unknown origin in adults. Am Fam Physician.\n2022;105(2):137-143.\nHaidar G, Singh N. Fever of unknown origin. N Engl J Med. 2022;386(5):463-477."},{"n":127,"q":"A 72-year-old male presents to the emergency department (E with a 2-day history of nausea, vomiting, and diarrhea. The symptoms developed after the recent repair of an inguinal hernia, and his surgeon advised him to come to the ED. The patient has a history of chronic heart disease, hypertension, and diabetes mellitus with kidney disease. His medications include atorvastatin (Lipitor), amlodipine (Norvasc), and dapagliflozin (Farxiga). He does not drink alcohol or use illicit drugs. On presentation he is lucid and making jokes with the staff. His vital signs in the ED include a blood pressure of 110/60 mm Hg, a heart rate of 110 beats/min, and an oxygen saturation of 96% on room air. Physical examination findings are unremarkable. He receives intravenous ondansetron, 4 mg, and laboratory studies are pending. Several hours later, the patient appears drowsy and has difficulty focusing. He fluctuates between lethargy and rambling about unrelated topics. Despite conservative treatment for the suspected condition, he starts displaying severe agitation, putting himself and the staff members at risk for harm. Which one of the following oral medications would be most appropriate for this patient?","o":[{"l":"A","t":"Diazepam (Valium)"},{"l":"B","t":"Haloperidol"},{"l":"C","t":"Lorazepam (Ativan)"},{"l":"D","t":"Risperidone (Risperdal)"},{"l":"E","t":"Sertraline (Zoloft)"}],"a":"D","e":"This patient\u2019s symptoms meet the DSM-5 criteria for delirium related to his emergency\ndepartment visit. Delirium is characterized by an acute disturbance in cognition,\nawareness, and attention that deviates from the patient\u2019s baseline cognition, fluctuates\nin severity, and develops within hours to days. Delirium has 3 subtypes: hyperactive,\nhypoactive, and mixed. An accurate diagnosis is vital to prevent inappropriate\ntreatments, increased morbidity and mortality, and prolonged hospitalization. It is\namong the most common complications in hospitalized adults age 65 and older,\nespecially among those who have undergone surgery. Patients with delirium have an\nincreased risk for death in the following year. While the pathophysiology of delirium is\nnot well understood, multiple comorbidities, older age, poor functional status,\npolypharmacy, and recent surgery are all independent risk factors. Symptoms can\noverlap with other diseases and a comprehensive history and physical examination are\nessential for a timely diagnosis.\nPrevention using a multidisciplinary approach is the optimal management for delirium.\nNonpharmacologic interventions are the foundation of delirium management, and no\nmedications are approved by the FDA for its treatment. However, when indicated,\nsecond-generation antipsychotics such as risperidone, olanzapine, and quetiapine, are\npreferred over haloperidol because they have fewer side effects and a faster onset of\naction. The benzodiazepines lorazepam and midazolam may be given parenterally if\ndelirium is attributed to alcohol consumption, uncontrollable seizure activity, or hypnotic\ndrug withdrawal, but oral diazepam is not indicated. Trazodone may be used as an\nalternative treatment, but sertraline would not be appropriate.\n\nReference\nJaqua EE, Nguyen VTN, Chin E. Delirium in older persons: prevention, evaluation, and\nmanagement. Am Fam Physician. 2023;108(3):278-287."},{"n":128,"q":"A 69-year-old male with a history of coronary artery disease sees you for follow-up after hospitalization for new-onset atrial fibrillation. After some difficulty with low blood pressure with other rate control agents, he was discharged on amiodarone. This patient should be monitored for amiodarone toxicity with which one of the following?","o":[{"l":"A","t":"An amiodarone plasma level"},{"l":"B","t":"A blood glucose level"},{"l":"C","t":"A CBC with differential"},{"l":"D","t":"Pulmonary function testing"},{"l":"E","t":"Urinalysis"}],"a":"D","e":"Patients treated with amiodarone should be monitored with pulmonary function testing\nat baseline and if clinical suspicion of pulmonary toxicity develops. Amiodarone is\ncommonly used to manage ventricular arrhythmias, and for rate and rhythm control in\natrial fibrillation. Amiodarone is associated with pulmonary fibrosis, and baseline\nassessment with pulmonary function tests including measurement of diffusing capacity\nof the lungs for carbon monoxide (DLCO) and chest x-ray is recommended. Amiodarone\nis also associated with hypothyroidism and less commonly with hyperthyroidism, liver\ninflammation, peripheral neuropathies, optic neuritis and corneal microdeposits, and\nbluish skin discoloration. Amiodarone plasma levels, blood glucose monitoring, a CBC\nwith differential, and urinalysis are not routinely indicated in patients taking\namiodarone.\nReference\nSiddoway LA. Amiodarone: guidelines for use and monitoring. Am Fam Physician.\n2003;68(11):2189-2196."},{"n":129,"q":"A 39-year-old female presents for a postpartum visit 2 months after a preterm delivery that was complicated by chronic hypertension and a bicornuate uterus. She does not smoke cigarettes. Which one of the following would be the most appropriate contraceptive for this patient?","o":[{"l":"A","t":"Oral levonorgestrel/ethinyl estradiol"},{"l":"B","t":"An etonogestrel/ethinyl estradiol vaginal ring (NuvaRing)"},{"l":"C","t":"An etonogestrel subdermal implant (Nexplanon)"},{"l":"D","t":"A levonorgestrel IUD (Mirena)"},{"l":"E","t":"A copper IUD (Paragard)"}],"a":"C","e":"This patient has a structural abnormality of the uterus and IUDs are contraindicated.\nFurthermore, even well-controlled hypertension is a relative contraindication to\nestrogen-containing contraceptives such as combination pills and the vaginal ring, due\nto associated vascular risks in a patient older than 35 years. Nonhormonal methods and\nprogesterone-only contraceptive pills, depot injections, and implants remain options.\nThe etonogestrel implant is the most effective of these options.\nReference\nNguyen AT, Curtis KM, Tepper NK, et al. US medical eligibility criteria for contraceptive\nuse, 2024. MMWR Recomm Rep. 2024;73(4):1-126."},{"n":130,"q":"A 77-year-old female with a medical history of atrial fibrillation, COPD, depression, and hypothyroidism presents for follow-up of a recent visit to the emergency department (E for a fall in which she hit her head on the edge of a dresser. CT of the head in the ED was negative for intracranial bleeding and she received staples for a scalp laceration. Which one of the following medications in this patient's current regimen is most likely to increase her fall risk?","o":[{"l":"A","t":"Apixaban (Eliquis)"},{"l":"B","t":"A budesonide/formoterol inhaler (Symbicort)"},{"l":"C","t":"Fluoxetine (Prozac)"},{"l":"D","t":"Levothyroxine (Synthroid)"},{"l":"E","t":"Prednisone"}],"a":"C","e":"Use of an SSRI has been found to increase fall risk in older persons. While\nanticoagulants such as apixaban increase the risk for bleeding from fall-related injuries,\nthey are recommended to prevent stroke in patients with atrial fibrillation regardless of\nfall risk and have not been noted to increase the risk of falling. Budesonide/formoterol,\nlevothyroxine, and prednisone have not been associated with an increased fall risk.\nReferences\nMarcum ZA, Perera S, Thorpe JM, et al. Antidepressant use and recurrent falls in\ncommunity-dwelling older adults: findings from the Health ABC Study. Ann\nPharmacother. 2016;50(7):525-533.\nMoncada LVV, Mire LG. Preventing falls in older persons. Am Fam Physician.\n2017;96(4):240-247.\nThe 2023 American Geriatrics Society Beers Criteria Update Expert Panel. American\nGeriatrics Society 2023 updated AGS Beers criteria for potentially inappropriate\nmedication use in older adults. J Am Geriatr Soc. 2023;71(7):2052-2081."},{"n":131,"q":"A 42-year-old female who has undergone a bilateral prophylactic mastectomy and a bilateral salpingo-oophorectomy due to a known BRCA mutation sees you for follow-up. She is experiencing symptoms of vasomotor instability and dyspareunia. She asks about hormone replacement therapy. Which one of the following is the best evidence-based recommendation for this patient?","o":[{"l":"A","t":"No hormone therapy"},{"l":"B","t":"Estrogen monotherapy until age 50"},{"l":"C","t":"Estrogen and progesterone therapy until age 50"},{"l":"D","t":"Estrogen and progesterone therapy after age 50"}],"a":"C","e":"Hormone therapy until age 50 has been shown to mitigate some of the health outcomes\nof early menopause and is the most effective treatment for menopausal symptoms and\nimproved quality of life. Combined hormone replacement therapy with estrogen and\nprogesterone is indicated for women with a uterus, while estrogen monotherapy is\nindicated for women without a uterus. Hormone therapy does not seem to have a\nrelevant effect on cancer risk in BRCA mutation carriers.\nReferences\nHuber D, Seitz S, Kast K, Emons G, Ortmann O. Hormone replacement therapy in BRCA\nmutation carriers and risk of ovarian, endometrial, and breast cancer: a systematic\nreview. J Cancer Res Clin Oncol. 2021;147(7):2035-2045.\nKingsberg SA, Larkin LC, Liu JH. Clinical effects of early or surgical menopause. Obstet\nGynecol. 2020;135(4):853-868."},{"n":132,"q":"A 5-month-old infant is brought to the urgent care clinic by her parent for evaluation of cough and fever. The parent reports that their 2 school-aged children came home with colds 5 days ago. Home tests were negative for COVID-19. Last night the 5-month-old infant developed a runny nose, sneezing, cough, and fever. The infant has also been sleeping more and nursing less. The infant\u2019s vital signs are notable for a temperature of 38.8 \u00b0C (101.8 \u00b0F), a pulse rate of 140 beats/min, a respiratory rate of 26/min, and an oxygen saturation of 94% on room air. On examination you note mild grunting but no nasal flaring or supraclavicular retractions. Auscultation of the lungs reveals a prolonged expiratory phase with diffuse wheezing and coarse breath sounds. Which one of the following would be the most appropriate intervention at this time?","o":[{"l":"A","t":"Adequate hydration and nutrition"},{"l":"B","t":"Azithromycin (Zithromax)"},{"l":"C","t":"Dexamethasone"},{"l":"D","t":"Viral testing"},{"l":"E","t":"A chest x-ray"}],"a":"A","e":"This patient presents with symptoms and findings consistent with uncomplicated\nrespiratory syncytial virus (RSV) bronchiolitis. Symptoms may include fever, lethargy,\nrhinorrhea, congestion, sneezing, cough, tachypnea, retractions, and difficulty feeding.\nSince this patient does not have any airway complications, concurrent bacterial\ninfection, or need for hospitalization to manage oxygen therapy, treatment is primarily\nsupportive. Ensuring adequate hydration and nutrition, with intravenous or nasogastric\ntube intervention if needed, is the most appropriate intervention at this time.\nAntibiotics such as azithromycin should not be used for the treatment of RSV\nbronchiolitis unless there is concern for a coexisting bacterial infection. Corticosteroids\nsuch as dexamethasone should not be used for the treatment of RSV bronchiolitis since\nthey do not decrease the risk for hospital admission or duration of stay. The diagnosis\nof RSV bronchiolitis is clinical and does not require viral testing for confirmation.\nBecause chest x-rays do not improve outcomes or reduce antibiotic use, they should\nonly be obtained if there is concern for airway complications.\nReference\nOppenlander KE, Chung AA, Clabaugh D. Respiratory syncytial virus bronchiolitis: rapid\nevidence review. Am Fam Physician. 2023;108(1):52-57."},{"n":133,"q":"A 27-year-old comatose female is brought to the emergency department. There is no history of trauma. An overdose of which one of the following would most likely account for a decreased respiratory rate of 10/min?","o":[{"l":"A","t":"Anticonvulsants"},{"l":"B","t":"Antipsychotics"},{"l":"C","t":"Ethanol"},{"l":"D","t":"Opioids"},{"l":"E","t":"Sedative-hypnotics"}],"a":"D","e":"The classic toxidrome of apnea, stupor, and miosis is indicative of opioid overdose. Not\nall of these findings are always present. In a patient not physiologically sleeping, a\nrespiratory rate \u226412/min is strongly suggestive of opioid toxicity. Respiratory depression\nis not usually found with overdose from anticonvulsants, antipsychotics, ethanol, or\nsedative-hypnotic agents.\nReference\nBoyer EW. Management of opioid analgesic overdose. N Engl J Med. 2012;367(2):146155."},{"n":134,"q":"A 65-year-old male sees you for an annual health maintenance examination. His past medical history is significant for hypertension and hyperlipidemia, which are both well controlled with medication. He had a myocardial infarction 10 years ago that was treated with angioplasty and he sees a cardiologist regularly. He has smoked 1 pack of cigarettes per day since age 16. His current medications include: Low-dose aspirin Hydrochlorothiazide Lisinopril (Zestril) Rosuvastatin (Crestor) He currently walks 2000\u20133000 steps daily. In addition to recommending smoking cessation, you suggest a goal of more than 5000 steps daily. He tells you that his calves hurt when he walks more than 100 yards and he has to stop and rest before he can continue. If the suspected diagnosis is confirmed with testing, then which one of the following would be the most appropriate initial treatment?","o":[{"l":"A","t":"A supervised exercise program"},{"l":"B","t":"Cilostazol"},{"l":"C","t":"Pentoxifylline"},{"l":"D","t":"Revascularization"}],"a":"A","e":"According to guidance from the American Heart Association, a supervised exercise\nprogram to improve functional status, decrease symptoms, and improve quality of life is\nthe first-line treatment for mild, non\u2013limb-threatening peripheral artery disease. Aspirin\ndecreases cardiovascular risk but will not improve symptoms or quality of life. Cilostazol\nand pentoxifylline can help with symptoms but are second-line therapy.\nRevascularization can be considered but is not an initial treatment.\nReferences\nFirnhaber JM, Powell CS. Lower extremity peripheral artery disease: diagnosis and\ntreatment. Am Fam Physician. 2019;99(6):362-369.\nTreat-Jacobson D, McDermott MM, Bronas UG, et al. Optimal exercise programs for\npatients with peripheral artery disease: a scientific statement from the American Heart\nAssociation. Circulation. 2019;139(4):e10-e33."},{"n":135,"q":"A 28-year-old nulligravida sees you for preconception advice. She and her husband would like to conceive in the next 6 months. She asks what she can do to prepare for pregnancy. She tells you that she has milk with breakfast and yogurt with lunch most of the time. Which one of the following should you recommend?","o":[{"l":"A","t":"A urine dipstick and culture with preemptive treatment"},{"l":"B","t":"Calcium carbonate, 500 mg twice daily"},{"l":"C","t":"Folic acid, 400 \u03bcg daily"},{"l":"D","t":"Vitamin B (cyanocobalamin), 1000 \u03bcg daily 12"},{"l":"E","t":"Vitamin D (cholecalciferol), 2000 IU daily 3"}],"a":"C","e":"Evidence supports folic acid supplementation for all women prior to pregnancy and\nduring the first trimester to prevent neural tube defects. There is no indication for\ntreating asymptomatic bacteriuria prior to conception. While calcium supplementation is\noften recommended, this patient\u2019s diet provides sufficient calcium. There is uncertain\nevidence regarding vitamin B12 (cyanocobalamin) supplementation in pregnant patients.\nVitamin D supplementation with cholecalciferol is also often recommended during\npregnancy, but the appropriate dosage is 600 IU daily.\nReferences\nFinkelstein JL, Fothergill A, Venkatramanan S, et al. Vitamin B12 supplementation during\npregnancy for maternal and child health outcomes. Cochrane Database of Systematic\nReviews. 2024;1:CD013823.\nPerez-Lopez FR, Pilz S, Chedraui P. Vitamin D supplementation during pregnancy: an\noverview. Curr Opin Obstet Gynecol. 2020;32(5):316-321.\n\nRamirez SI. Prenatal care: an evidence-based approach. Am Fam Physician.\n2023;108(2):139-150.\nWillemse JPMM, Meertens LJE, Scheepers HCJ, et al. Calcium intake from diet and\nsupplement use during early pregnancy: the Expect study I. Eur J Nutr.\n2020;59(1):167-174."},{"n":136,"q":"A 52-year-old male presents with right knee pain after falling from his bicycle earlier today. The patient states that he fell to the right when his bicycle tires slid on wet pavement but is uncertain of the exact mechanism of injury. He says that he can bear weight on the right leg, but the knee has been swollen and tender since the injury. On examination you observe moderate joint effusion without redness of the knee joint, and a range of motion of 80\u00b0\u2013180\u00b0. There is tenderness to palpation over the patella with no other bony tenderness noted. There is no ligamentous laxity. The patient is able to ambulate in the examination room with a notable limp. According to the Ottawa knee rule, this patient is at high risk for fracture and imaging is indicated because of which one of the following factors?","o":[{"l":"A","t":"His age"},{"l":"B","t":"His range of motion"},{"l":"C","t":"A limping gait"},{"l":"D","t":"Moderate joint effusion"},{"l":"E","t":"Tenderness over the patella"}],"a":"E","e":"The Ottawa knee rule helps to determine if imaging is needed in patients with knee\ntrauma and can decrease unnecessary imaging. The criteria are age \u226555, isolated\ntenderness of the patella, tenderness at the fibular head, inability to flex the knee to\n90\u00b0, and inability to bear weight for 4 steps both immediately after the injury and in the\noffice or emergency department.\nTenderness over the patella is the most concerning symptom in this patient, and an xray is warranted to rule out fracture. Joint effusion is not a criterion of the Ottawa knee\nrule.\nReferences\nBunt CW, Jonas CE, Chang JG. Knee pain in adults and adolescents: the initial\nevaluation. Am Fam Physician. 2018;98(9):576-585.\nHwang C. Calculated decisions: Ottawa knee rule. Emerg Med Pract. 2020;22(suppl\n8):CD11-CD12."},{"n":137,"q":"Medicaid is the largest health insurance program in the United States based on its number of enrolled recipients. Which one of the following statements is true regarding Medicaid?","o":[{"l":"A","t":"Fewer than half of all states have participated in the Medicaid expansion associated with the Affordable Care Act"},{"l":"B","t":"Its federal funding decreased during the COVID-19 pandemic"},{"l":"C","t":"It is the predominant insurer for long-term care"},{"l":"D","t":"The racial and ethnic group distribution of Medicaid recipients reflects that of the U.S. population"}],"a":"C","e":"Medicaid, a federal program that is managed by individual states, is the predominant\ninsurer for long-term care in the United States. Once older adults have exhausted their\nresources for long-term care, they can enroll in Medicaid. Sixty-two percent of nursing\nhome residents are funded through Medicaid. As of 2022, 24% of all Americans were\nenrolled in Medicaid and almost 70% of enrollees participate in managed care\nprograms.\n\nMedicaid is a \u201ccountercyclical\u201d program, meaning that as the economy worsens,\nenrollment increases. The federal government committed a 6.2% funding increase to\nstates during the height of the COVID-19 pandemic. The Affordable Care Act of 2010\nexpanded Medicaid coverage to a higher percentage of adults, with the federal\ngovernment initially funding the expansion. As of 2022, 38 states and the District of\nColumbia had adopted the Medicaid expansion. The majority of Medicaid recipients\n(56%) are from racial and ethnic minorities, reflecting income inequality in the United\nStates.\nReference\nDonohue JM, Cole ES, James CV, Jarlenski M, Michener JD, Roberts ET. The US\nMedicaid program: coverage, financing, reforms, and implications for health equity.\nJAMA. 2022;328(11):1085-1099."},{"n":138,"q":"A male patient is brought to your office by his adult granddaughter due to concerns that he has had a stroke. He was found with left arm and leg weakness 3 days ago, and he had fallen several times. His symptoms resolved after the first day. The patient drinks and smokes heavily. He has a history of traumatic brain injury with prolonged seizure from a fall while intoxicated 10 years ago, and he has been taking phenytoin (Dilantin) since that time. An oral examination is significant for very poor dentition and a healing mucosal injury to the posterior left side of his tongue. Noncontrast CT of the head shows no hemorrhage, mass, or sign of ischemia, but reveals mild encephalomalacia in the right cerebral hemisphere. Which one of the following is the most likely cause of this patient\u2019s symptoms?","o":[{"l":"A","t":"Conversion disorder"},{"l":"B","t":"Hemiplegic migraine"},{"l":"C","t":"Hypoglycemia"},{"l":"D","t":"Multiple sclerosis"},{"l":"E","t":"Postictal paralysis (Todd paralysis)"}],"a":"E","e":"This patient\u2019s presentation is most consistent with postictal paralysis, also known as\nTodd paralysis. His history of seizures associated with a brain injury, the prolonged\nnature of his symptoms, the evidence of tongue biting on examination, and the absence\nof signs of stroke on CT all support this diagnosis. Postictal neurologic findings account\nfor approximately 20% of suspected strokes in the emergency department. There is no\nhistory to support a diagnosis of conversion disorder or hypoglycemia in this patient.\nHemiplegic migraine is generally accompanied by headache, and rarely presents in older\nadults. Multiple sclerosis symptoms would be expected to persist.\nReferences\nBrigo F, Lattanzi S. Poststroke seizures as stroke mimics: clinical assessment and\nmanagement. Epilepsy Behav. 2020;104(Pt B):106297.\nKana T, Mehjabeen S, Patel N, Kawamj A, Shamim Z. Sporadic hemiplegic migraine.\nCureus. 2023;15(5):e38930.\nXu SY, Li ZX, Wu XW, Li L, Li CX. Frequency and pathophysiology of post-seizure Todd's\nparalysis. Med Sci Monit. 2020;26:e920751."},{"n":139,"q":"A 45-year-old female sees you for a refill of her asthma medication. She takes 1 puff of her albuterol inhaler (Proventil, Ventolin) daily prior to exercising. She wakes up at night a couple of times per week with dyspnea, which is relieved with another puff from her albuterol inhaler. Her most recent asthma exacerbation requiring oral corticosteroids was 4 months ago. She has not been hospitalized for an asthma exacerbation since she was a child. Which one of the following should be prescribed for this patient to reduce severe asthma exacerbations?","o":[{"l":"A","t":"An interleukin-5 antagonist"},{"l":"B","t":"A leukotriene receptor antagonist"},{"l":"C","t":"A long-acting \u03b2-agonist (LABA)"},{"l":"D","t":"A long-acting muscarinic antagonist"},{"l":"E","t":"An inhaled corticosteroid/LABA combination"}],"a":"E","e":"This patient has moderate persistent asthma, based on the history of symptoms that\noccur daily and more than once per week at night. Single maintenance and reliever\ntherapy (SMART) with an inhaled corticosteroid and long-acting \u03b2-agonist (LABA) is\nrecommended for management of moderate asthma in adults and adolescents (SOR A).\nLABAs have a boxed warning against monotherapy due to an increase in death related\nto asthma secondary to the risk for paradoxical bronchospasm. Long-acting muscarinic\nantagonists may also cause paradoxical bronchospasm and are not recommended for\nfirst-line therapy in asthma. Interleukin-5 antagonists may be considered in severe\nasthma as add-on maintenance but not as a reliever treatment. Leukotriene receptor\nantagonists are considered second-line controller therapy and not considered for\nreliever treatment.\nReference\nRaymond TJ, Peterson TA, Coulter J. Chronic asthma treatment: common questions and\nanswers. Am Fam Physician. 2023;107(4):358-368."},{"n":140,"q":"A 40-year-old female presents to the urgent care clinic because of significant fatigue, malaise, nausea, and intermittent vomiting. She is also experiencing recurrent fever and abdominal pain and says that her symptoms started a couple of weeks ago while she was in South America. Now her urine is dark and her spouse has noted a yellow tinge to her skin and the white of her eyes, prompting today\u2019s acute visit. Her vital signs are normal. A physical examination is unremarkable except for hepatomegaly and jaundice. Which one of the following test results would confirm the suspected diagnosis?","o":[{"l":"A","t":"Anti\u2013hepatitis A IgG antibodies"},{"l":"B","t":"Anti\u2013hepatitis A IgM antibodies"},{"l":"C","t":"Anti\u2013hepatitis B surface antibodies"},{"l":"D","t":"A serum creatinine level of 2.5 mg/dL (N 0.6\u20131.1)"},{"l":"E","t":"Elevated serum transaminase levels"}],"a":"B","e":"Hepatitis A is a common cause of acute hepatic inflammation and jaundice. It was the\nmost commonly reported type of hepatitis in the United States until 2004, when a\ncombination of widespread vaccination and food safety practices decreased its\nincidence. Hepatitis A is caused by nonenveloped positive-strand RNA hepatitis A virus.\nHumans are the only natural host. Classified as a picornavirus, it is stable in many\nenvironments and is able to survive for multiple weeks on surfaces. It is transmitted\nthrough ingestion of infected stool particles. Consumption of contaminated water and\nfood or close interpersonal or sexual contact with a person who is infected are common\ncauses of infection, whereas drug use and blood transfusion are less common causes of\ninfection. Incubation lasts approximately 30 days, followed by infectious symptoms,\nincluding nonspecific influenza-like symptoms, malaise, fever, nausea with vomiting,\nand abdominal pain. The classic findings are jaundice and dark urine.\nMost cases of acute hepatitis A are self-limited and there is no specific treatment.\nSupportive and symptomatic care should be utilized and hepatotoxins should be\navoided. A liver transplant may be considered if fulminant hepatic failure develops.\nSerologic testing is required for the diagnosis of hepatitis A. Anti\u2013hepatitis A IgM\nantibodies become detectable 5\u201310 days before the onset of symptoms, peak within a\nmonth, and can persist for >6 months. However, anti\u2013hepatitis A IgG antibodies appear\nduring the convalescent phase and remain elevated throughout the patient's lifetime.\nTherefore, anti\u2013hepatitis A IgM antibodies would confirm the diagnosis instead of antihepatitis A IgG antibodies. Anti\u2212hepatitis B surface antibodies indicate immunity to\nhepatitis B and would not be present in acute hepatitis B infection. A serum creatinine\nlevel >2 mg/dL is a positive predictor of fulminant hepatitis and death, but it is not\ndiagnostic of hepatitis A. Although laboratory findings may include elevations of serum\ntransaminase levels, it is not specific for hepatitis A.\nReferences\nLangan RC, Goodbred AJ. Hepatitis A. Am Fam Physician. 2021;104(4):368-374.\nWilkins T, Sams R, Carpenter M. Hepatitis B: screening, prevention, diagnosis, and\ntreatment. Am Fam Physician. 2019;99(5):314-323."},{"n":141,"q":"A healthy 15-year-old female is brought to your office for a well adolescent visit. She does not have any health concerns or preexisting medical conditions. Based on the guidelines from the U.S. Preventive Services Task Force, which one of the following would be most appropriate for this patient?","o":[{"l":"A","t":"A vision examination"},{"l":"B","t":"Depression screening"},{"l":"C","t":"A CBC"},{"l":"D","t":"A lipid panel"},{"l":"E","t":"HPV testing"}],"a":"B","e":"The U.S. Preventive Services Task Force (USPSTF) recommends depression screening\nfor adolescents beginning at age 12 (B recommendation). The American Academy of\nPediatrics (AAP) recommends routine vision screening from 12 months to 5 years of age\nand only risk-based vision screening in adolescents as vision conditions are less likely to\nbegin in older children. The USPSTF recommends vision screening at least once in all\nchildren ages 3\u20135 (B recommendation). Iron deficiency screening is not recommended\nin adolescents; however, the AAP recommends universal hemoglobin or hematocrit\nscreening at 12 months of age while the USPSTF states that there is insufficient\nevidence (I recommendation). While the AAP recommends dyslipidemia screening in\nchildren ages 9\u201311, the USPSTF currently states there is insufficient evidence for\nscreening for \u226420 years of age (I recommendation). The USPSTF recommends against\ncervical cancer screening before age 21 (D recommendation). Furthermore, cytology is\nrecommended for those age 21 and older while high-risk HPV testing is not\nrecommended until age 30.\nReferences\nLambert M. AAP updates recommendations for routine preventive pediatric health care.\nAm Fam Physician. 2016;94(4):324.\nUS Preventive Services Task Force. A & B recommendations.\nUS Preventive Services Task Force. Final recommendation statement: iron deficiency\nanemia in young children: screening. Updated September 7, 2015.\nUS Preventive Services Task Force. Final recommendation statement: lipid disorders in\nchildren and adolescents: screening. Updated July 18, 2023.\nUS Preventive Services Task Force. Final recommendation statement: vision in children\nages 6 months to 5 years: screening. Updated September 5, 2017."},{"n":142,"q":"A 62-year-old male presents to your office with chest pain that began after he ate his usual breakfast of bacon and eggs this morning. He describes the pain as a substernal tightness that worsens with activity and radiates to his left arm. He reports dyspnea and nausea but no emesis. On examination the patient is diaphoretic and appears to be in slight distress. He has a temperature of 37.0 \u00b0C (98.6 \u00b0F), a pulse rate of 106 beats/min, a respiratory rate of 22/min and nonlabored, a blood pressure of 110/70 mm Hg, and an oxygen saturation of 92% on room air. The lungs are clear, and the heart is regular without any murmurs. Examination of the abdomen is notable for tenderness to palpation in the right upper quadrant, normal bowel sounds, no rebound or guarding, and a negative Murphy sign. Examination of the extremities reveals no edema and 1+ pedal pulses. A neurologic examination shows no focal deficits and a normal gait. An EKG shows a left bundle branch block that was not present on an EKG 1 year ago. His pain improves with the administration of chewable aspirin, 162 mg, and sublingual nitroglycerin. Which one of the following would be the most appropriate next step in the management of this patient\u2019s chest pain?","o":[{"l":"A","t":"A high-sensitivity cardiac troponin level in your office"},{"l":"B","t":"Coronary CT angiography"},{"l":"C","t":"Referral to a cardiologist for treadmill stress testing"},{"l":"D","t":"Transportation to a hospital capable of urgent coronary intervention"}],"a":"D","e":"This patient has new-onset chest pain with symptoms typical of coronary artery disease\nand needs urgent evaluation with coronary angiography and possible percutaneous\ncoronary intervention (PCI). He has a new left bundle branch block indicative of acute\ncoronary syndrome and should be emergently transported to a facility that can perform\nurgent coronary angiography and further intervention as needed, including PCI. Once\nthe patient has been identified as having acute coronary syndrome, transfer should not\nbe delayed while waiting for further cardiac testing. Outpatient laboratory testing,\ncoronary CT angiography, and cardiac stress testing would not be appropriate in this\nsituation.\nReferences\nBuelt A, Kennady J, Arnold M. Chest pain evaluation: updated guidelines from the\nAHA/ACC. Am Fam Physician. 2023;107(2):204-206.\nGulati M, Levy PD, Mukherjee D, et al. 2021 AHA/ACC/ASE/CHEST/SAEM/SCCT/SCMR\nguideline for the evaluation and diagnosis of chest pain: a report of the American\nCollege of Cardiology/American Heart Association Joint Committee on Clinical Practice\nGuidelines. Circulation. 2021;144(22):e368-e454."},{"n":143,"q":"A 29-year-old female was recently treated for an uncomplicated urinary tract infection. She presents to your office with recurrence of an itchy rash on her elbow and lower back (shown below). Which one of the following is the most likely diagnosis?","o":[{"l":"A","t":"Drug eruption"},{"l":"B","t":"Pityriasis rosea"},{"l":"C","t":"Psoriasis"},{"l":"D","t":"Seborrheic dermatitis"},{"l":"E","t":"Tinea corporis"}],"a":"C","e":"This patient has a rash with a distribution and appearance that is highly consistent with\npsoriasis, with thick, well-circumscribed plaques with silvery scale on the lower back\nand extensor elbows. Drug eruptions can have variable presentations, but this rash is\nmuch more consistent with psoriasis. Pityriasis rosea presents with more diffuse\nmacules and patches with a fine scale. Both psoriasis and seborrheic dermatitis can\ncause itchy red rashes on the scalp, but seborrhea is less frequent on the back and\nelbows. Tinea corporis is more common in intertriginous areas.\nReference\nArmstrong AW, Read C. Pathophysiology, clinical presentation, and treatment of\npsoriasis: a review. JAMA. 2020;323(19):1945-1960."},{"n":144,"q":"A 64-year-old male with stage 3b chronic kidney disease (CK","o":[{"l":"D","t":"sees you for recommended follow- up screenings. Which one of the following is most likely to be found in a patient with chronic kidney disease\u2013mineral and bone disorder (CKD-MBD)?"},{"l":"A","t":"An elevated 25-hydroxyvitamin D level"},{"l":"B","t":"An elevated calcium level"},{"l":"C","t":"An elevated phosphate level"},{"l":"D","t":"A low parathyroid hormone level  Item #143 Item #143"}],"a":"C","e":"Screening for signs of chronic kidney disease\u2013mineral and bone disorder (CKD-MBD)\nthrough the monitoring of calcium, phosphate, parathyroid hormone (PTH), and alkaline\nphosphatase, and possibly 25-hydroxyvitamin D levels is recommended beginning in\nstage 3 CKD. Early changes include the kidneys\u2019 decreased ability to excrete phosphate.\nThis can lead to elevated serum phosphate and PTH levels (secondary\nhyperparathyroidism). Decreased renal vitamin D production can lead to a lower\ncalcium level, which also increases the PTH level. These changes can then lead to the\nabnormalities of bone strength and mineralization seen in CKD-MBD.\nReferences\nGoodbred AJ, Langan RC. Chronic kidney disease: prevention, diagnosis, and treatment.\nAm Fam Physician. 2023;108(6):554-561.\nKetteler M, Block GA, Evenepoel P, et al. Executive summary of the 2017 KDIGO chronic\nkidney disease-mineral and bone disorder (CKD-MBD) guideline update: what's changed\nand why it matters. Kidney Int. 2017;92(1):26-36."},{"n":145,"q":"A 62-year-old male who currently receives chemotherapy for colon cancer presents to the emergency department with a 1-week history of worsening nausea and vomiting. He has been vomiting all oral intake for the past day, and he has not had a bowel movement in the past week. He reports severe, diffuse, crampy, intermittent abdominal pain that improves after vomiting. He has not had any fevers or chills. The physical examination is significant for abdominal distention, minimal bowel sounds, and diffuse tenderness. Which one of the following studies would be the most appropriate next step in evaluation?","o":[{"l":"A","t":"Ultrasonography of the right upper quadrant"},{"l":"B","t":"CT of the abdomen and pelvis with contrast"},{"l":"C","t":"A PET/CT scan"},{"l":"D","t":"A HIDA scan"},{"l":"E","t":"Magnetic resonance cholangiopancreatography (MRCP) of the abdomen"}],"a":"B","e":"This patient\u2019s presentation is consistent with a malignant bowel obstruction, and CT of\nthe abdomen and pelvis with contrast is useful for determining if any surgical\ninterventions are warranted. Ultrasonography typically does not yield useful information\ndue to the amount of bowel gas present during an obstruction. A PET/CT scan would\nnot be indicated to evaluate for the etiology of a bowel obstruction in an acute\nsituation. A HIDA scan or magnetic resonance cholangiopancreatography (MRCP) would\nbe useful if biliary obstruction or gallbladder disease were suspected, but these are not\nhelpful in the evaluation of a malignant bowel obstruction.\nReferences\nJackson P, Vigiola Cruz M. Intestinal obstruction: evaluation and management. Am Fam\nPhysician. 2018;98(6):362-367.\nYew KS, George MK, Allred HB. Acute abdominal pain in adults: evaluation and\ndiagnosis. Am Fam Physician. 2023;107(6):585-596."},{"n":146,"q":"Which one of the following medication classes reduces heart failure\u2013related hospitalizations in patients without diabetes mellitus?","o":[{"l":"A","t":"Calcium channel blockers"},{"l":"B","t":"DPP-4 inhibitors"},{"l":"C","t":"Insulin"},{"l":"D","t":"SGLT2 inhibitors"},{"l":"E","t":"Statins"}],"a":"D","e":"Adding an SGLT2 inhibitor to the medication regimen of patients with heart failure and\nwithout diabetes mellitus has been shown to reduce heart failure\u2013 related\nhospitalizations. Calcium channel blockers may have no effect or worsen heart failure.\nDPP-4 inhibitors can worsen the effects of heart failure. Insulin provides improved\nglucose control for patients with diabetes mellitus; however, it has not been\nindependently shown to reduce heart failure\u2013related hospitalizations. Statins are\neffective at reducing cholesterol levels but have not been shown to reduce heart\nfailure\u2013related hospitalizations.\nReferences\nAnker SD, Butler J, Filippatos G, et al. Empagliflozin in heart failure with a preserved\nejection fraction. N Engl J Med. 2021;385(16):1451-1461.\nMancini GBJ, O'Meara E, Zieroth S, et al. 2022 Canadian Cardiovascular Society\nguideline for use of GLP-1 receptor agonists and SGLT2 inhibitors for cardiorenal risk\nreduction in adults. Can J Cardiol. 2022;38(8):1153-1167.\nShaughnessy AF. SGLT2 inhibitors improve all-cause and cardiovascular mortality in\npatients regardless of diabetes or heart failure status. Am Fam Physician.\n2021;103(10):630-631.\nShaughnessy AF. SGLT-2 inhibitors reduce heart failure-related hospitalization in\npatients without diabetes. Am Fam Physician. 2022;106(4):461-462.\nZou X, Shi Q, Vandvik PO, et al. Sodium-glucose cotransporter-2 inhibitors in patients\nwith heart failure: a systematic review and meta-analysis. Ann Intern Med.\n2022;175(6): 851-861."},{"n":147,"q":"A 46-year-old female with a BMI of 36 kg/m2 and a history of bilateral tubal ligation presents with intermenstrual bleeding. An endometrial biopsy reveals endometrial hyperplasia with atypia. Which one of the following should you recommend at this time?","o":[{"l":"A","t":"Oral progesterone"},{"l":"B","t":"Combined oral contraceptives"},{"l":"C","t":"A levonorgestrel IUD (Mirena)"},{"l":"D","t":"Uterine MRI"},{"l":"E","t":"Hysterectomy"}],"a":"E","e":"This patient\u2019s age and elevated BMI put her at risk for endometrial cancer. Appropriate\nevaluation includes an endometrial biopsy. Patients who have endometrial hyperplasia\nwith atypia should be referred for hysterectomy, as it is the treatment of choice. Oral\nprogesterone may be offered to a patient who desires a future pregnancy. Endometrial\nhyperplasia without atypia may be treated with a levonorgestrel IUD or oral\nprogesterone. Uterine MRI would not offer any additional information for diagnosis and\nwould not change the need for hysterectomy.\n\nReference\nJordahl-Iafrato MA, Reed H, Hadley SK, Kolman KB. A systematic approach to chronic\nabnormal uterine bleeding. J Fam Pract. 2019;68(2):82-84, 86-92."},{"n":148,"q":"A 3-year-old male with a peanut allergy is brought to your office by his parents for a well child visit. His parents ask if there is anything they can do to prevent a peanut allergy if they have more children in the future. Which one of the following would be the most appropriate recommendation to decrease the risk for food allergies in children?","o":[{"l":"A","t":"Early sequential exposure to allergenic food between 4 and 6 months of life"},{"l":"B","t":"Exclusive breastfeeding for the first 3\u20134 months of life"},{"l":"C","t":"Regular antibiotics in the first 2 years of life"},{"l":"D","t":"Restricted cow's milk supplementation during the first 3 months of life"},{"l":"E","t":"A restricted maternal diet during pregnancy and breastfeeding"}],"a":"A","e":"Food allergies affect 8% of children and about 40% of these food allergies are reported\nas severe, causing anxiety for parents and caregivers. Peanuts, shellfish, cow's milk,\ntree nuts, and eggs are the most common allergenic foods, and peanuts are the most\ncommon food that causes life-threatening anaphylaxis. Risk factors include atopic\ndermatitis; allergic rhinitis; asthma; and allergies to latex, medications, and insect\nvenoms. A family history of atopy as well as vitamin D insufficiency and antibiotic use in\nthe first 2 years of life also increase the risk for developing food allergies.\nThe primary treatment of food allergies is eliminating the offending foods. Preventive\nmeasures shown to decrease the risk for developing food allergies include sequential\nexposure to allergenic foods starting between 4 and 6 months of life and restricting\nexposure to cow's milk in the first 3 days of life. Exclusive breastfeeding for 3\u20134 months\nreduces the likelihood of developing asthma and eczema, but it does not reduce the risk\nfor food allergies. There is no supporting evidence that restricting the mother's diet\nduring pregnancy and lactation reduces the risk for food allergies in children.\nReference\nBright DM, Stegall HL, Slawson DC. Food allergies: diagnosis, treatment, and\nprevention. Am Fam Physician. 2023;108(2):159-165."},{"n":149,"q":"A 30-year-old female comes to your office to establish care. She reports symptoms consistent with possible mild chronic malabsorption. A review of past records reveals that she was previously tested for celiac disease with an IgA tissue transglutaminase (tTG) level, which was negative. The review of systems is positive for chronic recurrent sinus infections. Examination of the head and neck, lungs, and abdomen is unremarkable. Which one of the following is the most appropriate next step to evaluate for a potential cause of this patient\u2019s chronic abdominal and upper respiratory symptoms?","o":[{"l":"A","t":"A repeat IgA tTG level"},{"l":"B","t":"A total IgA level"},{"l":"C","t":"Vitamin D and B levels 12"},{"l":"D","t":"A 24-hour fecal fat collection study"},{"l":"E","t":"CT of the abdomen and pelvis"}],"a":"B","e":"IgA deficiency is more common in patients with celiac disease than in the general\npopulation. Patients with IgA deficiency often experience chronic upper respiratory tract\ninfections, such as recurrent sinus infections. It is important to include a total IgA level\nwhen obtaining celiac disease panels to avoid a false-negative result. Serologic testing\nalong with a careful history is sufficiently sensitive to rule out celiac disease, but the\ngold standard for diagnosis still includes duodenal biopsy. Every patient with signs or\nsymptoms of chronic malabsorption (diarrhea, steatorrhea, weight loss, fat-soluble\nvitamin deficiencies, bloating, abdominal pain) should be tested for celiac disease.\nThis initial laboratory testing can be performed by primary care clinicians, and specialty\ncare should be sought if the workup fails to rule out celiac disease. Diagnostic imaging\nis not sensitive or specific for celiac disease. While fecal fat, vitamin D, and vitamin B12\nlevels may all be part of the overall workup in this patient, they are not the most helpful\ntests in diagnosing celiac disease at this time.\nReferences\nBurgers K, Lindberg B, Bevis ZJ. Chronic diarrhea in adults: evaluation and differential\ndiagnosis. Am Fam Physician. 2020;101(8):472-480.\nPelkowski TD, Viera AJ. Celiac disease: diagnosis and management. Am Fam Physician.\n2014;89(2):99-105."},{"n":150,"q":"A 54-year-old postmenopausal female with a past medical history of hypertension, nicotine dependence, and obesity sees you to establish care. Her medications include hydrochlorothiazide, losartan (Cozaar), and metformin. She smokes 1 pack of cigarettes per day and drinks 1 glass of wine each night. She returns 1 week later to discuss the results of laboratory studies. The laboratory studies demonstrate a positive hepatitis C antibody. Reflex testing reveals hepatitis C virus genotype and a hepatitis C viral load of 253,351 IU/mL. The AST level, ALT level, creatinine level, and INR are within normal limits. Tests for HIV, hepatitis A, and hepatitis B are negative. You calculate a Fibrosis-4 (FIB-4) score of 0.93, indicating a lack of advanced fibrosis. You initiate vaccination for hepatitis A and B. Which one of the following would be the most appropriate timing to initiate treatment with glecaprevir/pibrentasvir (Mavyret)?","o":[{"l":"A","t":"At this visit"},{"l":"B","t":"After she has abstained from alcohol for 3 months"},{"l":"C","t":"If a repeat hepatitis C viral load is increased in 3 months"},{"l":"D","t":"After completing the hepatitis A and B vaccination series"},{"l":"E","t":"If a Doppler ultrasound of the liver is negative for a hepatic vein thrombosis"}],"a":"A","e":"The Infectious Diseases Society of America recommends glecaprevir/pibrentasvir for\npatients with chronic hepatitis C virus (HCV) infection who have never received\ntreatment and do not have cirrhosis or have compensated cirrhosis. Limiting alcohol use\nis important to decrease the risk for cirrhosis, but cessation is not necessary in those\nundergoing treatment for HCV infection. Further hepatitis C viral load testing in 3\nmonths is not the most appropriate next step for this patient. While vaccinations are\nimportant, the hepatitis A and B series do not need to be completed prior to initiating\ntreatment. Further imaging is not indicated for this patient given her low Fibrosis-4\n(FIB-4) score, which indicates a very low likelihood of cirrhosis.\nReference\nBhattacharya D, Aronsohn A, Price J, Lo Re V; AASLD-IDSA HCV Guidance Panel.\nHepatitis C guidance 2023 update: AASLD-IDSA recommendations for testing,\nmanaging, and treating hepatitis C virus infection. Clin Infect Dis. 2023:ciad319."},{"n":151,"q":"A 63-year-old male with a medical history of diabetes mellitus presents to an urgent care clinic with nausea, vomiting, and abdominal pain. His spouse reports that the patient began having trouble breathing during the short drive to the clinic. He has an insulin pump, and his spouse says it has been malfunctioning. On examination the patient is lethargic, tachycardic, and appears volume depleted. You note Kussmaul respirations and abdominal tenderness. After initiating intravenous fluids, you obtain an initial laboratory evaluation with the following results: Glucose 190 mg/dL Sodium 135 mEq/L (N 135\u2013145) Potassium 5.1 mEq/L (N 3.5\u20135.2) Chloride 102 mEq/L (N 98\u2013107) Creatinine 1.30 mg/dL (N 0.50\u20131.04) Osmolality 300 mOsm/kg H O (N 280\u2013305) 2 Bicarbonate 10 mEq/L (N 19\u201329) Anion gap 23 mEq/L (N <18) Urine ketones 4+ Urine glucose 4+ Which one of the following medications may be contributing to this clinical picture?","o":[{"l":"A","t":"Atorvastatin (Lipitor)"},{"l":"B","t":"Canagliflozin (Invokana)"},{"l":"C","t":"Lisinopril (Zestril)"},{"l":"D","t":"Metformin"},{"l":"E","t":"Semaglutide (Ozempic)"}],"a":"B","e":"This patient has classic symptoms of diabetic ketoacidosis (DKA) triggered by a\nmalfunctioning insulin pump, but he appears euglycemic on presentation due to taking\nan SGLT2 inhibitor. Glycosuria occurs and can even persist 10\u201314 days after\ndiscontinuation of an SGLT2 inhibitor. Further evaluation of this patient would reveal an\nelevated urine glucose level despite his relatively normal serum glucose level. With a\nhigh anion gap, a low arterial pH and a high serum \u03b2-hydroxybutyrate level should also\nbe expected. Atorvastatin is not implicated in acute metabolic problems. Lisinopril can\ncause hyperkalemia, but not DKA. Metformin can cause lactic acidosis in acutely ill\npatients, but the risk is low and lactic acid rather than ketone bodies would be high.\nGLP-1 receptor agonists such as semaglutide are not associated with an increased risk\nfor euglycemic DKA.\nReferences\nDutta S, Kumar T, Singh S, Ambwani S, Charan J, Varthya SB. Euglycemic diabetic\nketoacidosis associated with SGLT2 inhibitors: a systematic review and quantitative\nanalysis. J Family Med Prim Care. 2022;11(3):927-940.\nPowers AC, Niswender KD, Evans-Molina C. Diabetes mellitus: diagnosis, classification,\nand pathophysiology. In: Loscalzo J, Fauci AS, Kasper DL, Hauser SL, Longo DL,\nJameson JL, eds. Harrison's Principles of Internal Medicine. Vol 2. 21st ed. McGraw-Hill;\n2022:3094-3103."},{"n":152,"q":"A 45-year-old gravida 2 para 2 with a history of irregular menses and bilateral tubal ligation presents with a 2-month history of bilateral milky nipple discharge. Her last menstrual period was 1 week ago. She does not take any medications. A physical examination reveals a small amount of milky nipple discharge bilaterally with no breast masses. A urine pregnancy test is negative. Laboratory testing reveals normal thyroid and kidney function, and a prolactin level of 95 ng/mL (N 5\u201320). Pituitary MRI with gadolinium shows a 7-mm enhancing mass. Which one of the following would be the most appropriate pharmacotherapy for this patient\u2019s condition?","o":[{"l":"A","t":"Bromocriptine (Parlodel)"},{"l":"B","t":"Cabergoline"},{"l":"C","t":"Levonorgestrel/ethinyl estradiol"},{"l":"D","t":"Metoclopramide (Reglan)"},{"l":"E","t":"Risperidone (Risperdal)"}],"a":"B","e":"This patient has hyperprolactinemia due to pituitary microadenoma and guidelines from\nthe Endocrine Society recommend cabergoline as an initial treatment. Studies have\nfound that cabergoline is more effective than bromocriptine or other dopamine agonists\nat decreasing prolactin levels and shrinking tumor size. Oral contraceptives may\nregulate menstrual conditions but are not recommended as first-line treatment for\nhyperprolactinemia. Metoclopramide and risperidone are dopamine antagonists and can\nbe a cause of hyperprolactinemia.\n\nReferences\nBruehlman RD, Winters S, McKittrick C. Galactorrhea: rapid evidence review. Am Fam\nPhysician. 2022;106(6):695-700.\nMelmed S, Casanueva FF, Hoffman AR, et al. Diagnosis and treatment of\nhyperprolactinemia: an Endocrine Society clinical practice guideline. J Clin Endocrinol\nMetab. 2011;96(2):273-288."},{"n":153,"q":"An 18-year-old male with no significant past medical history presents for a sports preparticipation evaluation prior to his high school senior football season. On cardiac auscultation, you detect a previously undocumented systolic murmur. Which one of the following additional characteristics of this murmur, if present, would raise concern for hypertrophic cardiomyopathy and necessitate additional testing prior to clearing this patient for sports participation?","o":[{"l":"A","t":"Decreased intensity with an isometric handgrip"},{"l":"B","t":"Decreased intensity with the Valsalva maneuver"},{"l":"C","t":"Increased intensity with moving from squatting to standing"},{"l":"D","t":"Increased intensity with passive leg raise"}],"a":"C","e":"One of the most important purposes of the sports preparticipation evaluation is to\nscreen for potentially life-threatening cardiovascular conditions. Hypertrophic\ncardiomyopathy is a leading cause of sudden cardiac death in younger athletes, and\nrecognition of the typical pathologic murmur that occurs with this condition can identify\npeople who are at risk. The characteristic harsh midsystolic ejection murmur results\nfrom a dynamic left ventricular outflow tract obstruction. The murmur intensifies with\nmaneuvers that reduce preload or afterload, which increase the relative obstruction.\nMoving from squatting to standing, the Valsalva maneuver, and dehydration states all\nreduce preload and therefore cause the murmur to increase. In contrast, maneuvers\nthat increase preload or afterload cause the murmur to soften due to decrease in the\nrelative obstruction. This includes moving from standing to squatting and passive leg\nraise, which increase preload, and isometric handgrip, which increases afterload.\nReferences\nAuthors/Task Force members; Elliott PM, Anastasakis A, et al. 2014 ESC guidelines on\ndiagnosis and management of hypertrophic cardiomyopathy: the Task Force for the\nDiagnosis and Management of Hypertrophic Cardiomyopathy of the European Society of\nCardiology (ESC). Eur Heart J. 2014;35(39):2733-2779.\nHouston BA, Stevens GR. Hypertrophic cardiomyopathy: a review. Clin Med Insights\nCardiol. 2015;8(suppl 1):53-65.\nLeggit JC, Whitaker D. Diagnosis and management of hypertrophic cardiomyopathy:\nupdated guidelines from the ACC/AHA. Am Fam Physician. 2022;105(2):207-209.\nMacDonald J, Schaefer M, Stumph J. The preparticipation physical evaluation. Am Fam\nPhysician. 2021;103(9):539-546.\nMarian AJ, Braunwald E. Hypertrophic cardiomyopathy: genetics, pathogenesis, clinical\nmanifestations, diagnosis, and therapy. Circ Res. 2017;121(7):749-770."},{"n":154,"q":"A 45-year-old male presents to your office for evaluation of acute penile pain. He has had painful erections for the past several days, and the current erection has lasted 5 hours. He has a history of sickle cell disease and diabetes mellitus. His only medication is daily metformin. On examination the patient appears quite uncomfortable and has a full erection with significant tenderness along the sides of the penile shaft. Which one of the following would be the most appropriate next step?","o":[{"l":"A","t":"Analgesia within 30 minutes"},{"l":"B","t":"A penile blood gas measurement"},{"l":"C","t":"Intracavernosal alprostadil (Caverject)"},{"l":"D","t":"Intracavernosal phenylephrine (Vazculep)"},{"l":"E","t":"Urgent evaluation by a urologist"}],"a":"E","e":"This patient is presenting with priapism, defined as an erection that is not associated\nwith sexual activity and lasts \u22654 hours. Priapism may be ischemic or nonischemic.\nNonischemic (high-flow) priapism is much rarer, stemming from an arterial fistula\ncaused by trauma. Ischemic priapism typically presents with a painful, fully erect penis\nwith a natural history of painful erections ranging from days to weeks preceding the\nacute presentation. Sickle cell disease is an important etiology of ischemic priapism.\nOther causes include other hematologic issues such as leukemia, and medications.\nIntracavernosal vasodilator agents and antipsychotics are more likely causes than\nphosphodiesterase-5 inhibitors. This is a urologic emergency that requires emergent\nevaluation and treatment by a urologist. Analgesic therapy is not the most appropriate\nnext step for this patient. While a penile blood gas measurement can be used to\ndistinguish between ischemic and nonischemic processes, urologic evaluation and\ntreatment should not be delayed. Intracavernosal alprostadil is a common cause of\nischemic priapism. Intracavernosal phenylephrine is used in the treatment of ischemic\npriapism after a urologist has performed several rounds of aspiration and reestablished\noxygenated blood flow into the corpus cavernosum.\nReferences\nEricson C, Baird B, Broderick GA. Management of priapism: 2021 update. Urol Clin\nNorth Am. 2021;48(4):565-576.\nLadkany D, Davis JE. Penile swelling. Am Fam Physician. 2020;102(12):751-752."},{"n":155,"q":"A 71-year-old male presents with an episode of reddish-brown urine. He has no other urinary tract symptoms. A urine dipstick is heme-positive and a microscopic urine examination reveals RBCs too numerous to count. He has a 35-pack-year smoking history. Which one of the following would be most appropriate to order at this time?","o":[{"l":"A","t":"Cytology"},{"l":"B","t":"CT urography only"},{"l":"C","t":"CT urography plus cystoscopy"},{"l":"D","t":"Urinary tract ultrasonography plus cystoscopy"},{"l":"E","t":"Urinary tract MRI plus cystoscopy"}],"a":"C","e":"This patient is at high risk for bladder cancer. Risk factors for urologic cancer in patients\nwith hematuria include age \u226560 years, a >30-pack-year smoking history, >25 RBCs/hpf\non a single urinalysis, and a history of gross hematuria. Patients with hematuria who\nare at high risk for bladder cancer should undergo CT urography plus cystoscopy.\nCytology may be used as an adjunct if initial studies do not reveal a cause for the\nhematuria. CT alone may not identify bladder cancer. Urinary tract ultrasonography plus\ncystoscopy is adequate and more cost effective for patients who are at moderate and\nlow risk. Urinary tract MRI is not recommended in this situation.\nReference\nIngelfinger JR. Hematuria in adults. N Engl J Med. 2021;385(2):153-163."},{"n":156,"q":"A 32-year-old male presents with frequent episodes of palpitations, sweating, dizziness, and paresthesias associated with an impending sense of doom. These symptoms have occurred several times per week and have disrupted his performance at work. After an appropriate evaluation, you diagnose panic disorder. Which one of the following would be most appropriate for initial treatment?","o":[{"l":"A","t":"Bupropion"},{"l":"B","t":"Buspirone"},{"l":"C","t":"Escitalopram (Lexapro)"},{"l":"D","t":"Hydroxyzine (Vistaril)"},{"l":"E","t":"Lorazepam (Ativan)"}],"a":"C","e":"The first-line pharmacologic treatment of panic disorder is SSRI and SNRI\nantidepressant medications (SOR A), including the SSRI escitalopram. Evidence has not\nshown bupropion or buspirone to be effective in the treatment of panic disorder.\nSedating antihistamines such as hydroxyzine also are not recommended for first-line\nmanagement of panic disorder because of limited evidence of effectiveness and\ndecreased tolerability due to their anticholinergic effects. Benzodiazepines such as\nlorazepam are less effective than antidepressants but improve symptoms compared to\nplacebo, but they carry an increased risk for adverse effects including tolerance,\ndependence, withdrawal, and mortality.\nReference\nDeGeorge KC, Grover M, Streeter GS. Generalized anxiety disorder and panic disorder in\nadults. Am Fam Physician. 2022;106(2):157-164."},{"n":157,"q":"A 46-year-old male sends you a message in the patient portal asking how to prevent acute altitude sickness during his upcoming ski trip. He has no significant medical history and no previous history of altitude sickness. He will be sleeping at a resort located at an altitude of 3000 m (9843 ft) above sea level and the slopes have a peak altitude of 4500 m (14,764 ft) above sea level. He plans to start skiing the day after arrival and does not have time to gradually acclimatize to the change in altitude. Which one of the following would be most appropriate regarding the prevention of altitude sickness?","o":[{"l":"A","t":"Overhydration to dilute the urine"},{"l":"B","t":"Full genome sequencing to identify alleles associated with altitude sickness"},{"l":"C","t":"Acetazolamide, 125 mg twice daily"},{"l":"D","t":"Dexamethasone, 6 mg daily"},{"l":"E","t":"Ibuprofen, 800 mg 3 times daily"}],"a":"C","e":"Altitude sickness is possible with rapid ascent to altitudes over 2500 m (8202 ft) above\nsea level. Slow ascent is usually recommended, but it is not often feasible for\nrecreational winter athletes. Acetazolamide is the mainstay of pharmaceutical\nprophylaxis if a patient desires medication. Other actions such as avoiding alcohol and\nincreasing hydration are often recommended but are not well supported. No genetic\nalleles have been identified that confer increased risk for altitude sickness.\nDexamethasone can be used to prevent and treat severe high-altitude pulmonary\nedema, but it is not recommended as a first-line prevention in patients such as this.\nIbuprofen has been proposed as an alternative prophylactic agent, but studies have\nshown it to be inferior to acetazolamide.\nReferences\nLuks AM, Swenson ER, Bartsch P. Acute high-altitude sickness. Eur Respir Rev.\n2017;26(143):160096.\nSavioli G, Ceresa IF, Gori G, et al. Pathophysiology and therapy of high-altitude\nsickness: practical approach in emergency and critical care. J Clin Med.\n2022;11(14):3937."},{"n":158,"q":"A 60-year-old male has an enlarging erythematous 1.0-cm papule with a central keratotic plug on the dorsum of his arm. Superficial biopsy shows keratoacanthoma. This type of lesion requires further diagnosis and treatment because it may be associated with which one of the following?","o":[{"l":"A","t":"Actinic keratosis"},{"l":"B","t":"Basal cell carcinoma"},{"l":"C","t":"Cutaneous squamous cell carcinoma"},{"l":"D","t":"Malignant melanoma"}],"a":"C","e":"Keratoacanthoma is a rapidly growing lesion that may be difficult to distinguish from\ncutaneous squamous cell carcinoma (CSCC) and may contain CSCC in its base. Because\nof this, it should be considered a malignant lesion and requires adequate pathology and\nremoval. Actinic keratosis is a precursor to CSCC. Basal cell carcinoma and malignant\nmelanoma are not related to keratoacanthoma.\nReference\nFirnhaber JM. Basal cell and cutaneous squamous cell carcinomas: diagnosis and\ntreatment. Am Fam Physician. 2020;102(6):339-346."},{"n":159,"q":"A 72-year-old male with a medical history of dilated cardiomyopathy with an ejection fraction (EF) of 30%, type 2 diabetes, and benign prostatic hyperplasia comes to your clinic for follow-up. His most recent echocardiogram shows an improved EF of 55%\u201360%. His current medications include the following: Carvedilol (Coreg), 25 mg twice daily Dapagliflozin (Farxiga), 10 mg daily Furosemide (Lasix), 20 mg daily Metformin, 500 mg twice daily Sacubitril/valsartan (Entresto), 97/103 mg twice daily Spironolactone (Aldactone), 25 mg daily The patient walks 2 miles daily and does not have any dyspnea. On examination his blood pressure is 118/76 mm Hg, his pulse rate is 64 beats/min, and his respiratory rate is 12/min and regular. His lungs are clear bilaterally, and his heart sounds are regular with no S /S heart sounds or murmurs. 3 4 His lower extremities show no edema. He has a creatinine level of 0.8 mg/dL (N 0.7\u20131.3) and a hemoglobin A of 7.0%. A urinalysis is negative for microalbuminuria. 1c Which one of the following is recommended at this time for management of this patient\u2019s cardiomyopathy?","o":[{"l":"A","t":"No change to his current regimen"},{"l":"B","t":"Changing spironolactone to as-needed for edema"},{"l":"C","t":"Discontinuing carvedilol"},{"l":"D","t":"Discontinuing dapagliflozin"},{"l":"E","t":"Discontinuing sacubitril/valsartan"}],"a":"A","e":"According to the 2022 American College of Cardiology/American Heart Association heart\nfailure guidelines, guideline-directed medical therapy should be continued in patients\nwith heart failure with an improved or recovered ejection fraction (EF). This is based on\nthe TRED-HF trial that showed a relapse of 44% in patients with dilated\ncardiomyopathy and an improved EF who discontinued pharmacotherapy compared\nwith 0% relapse in those who continued pharmacotherapy. The recommendation for\nthis patient would be to continue his current regimen.\nReferences\nBelkin MN, Cifu AS, Pinney S. Management of heart failure. JAMA. 2022;328(13):13461347.\nHalliday BP, Wassall R, Lota AS, et al. Withdrawal of pharmacological treatment for\nheart failure in patients with recovered dilated cardiomyopathy (TRED-HF): an openlabel, pilot, randomised trial. Lancet. 2019;393(10166):61-73.\nHeidenreich PA, Bozkurt B, Aguilar D, et al. 2022 AHA/ACC/HFSA guideline for the\nmanagement of heart failure: executive summary: a report of the American College of\nCardiology/American Heart Association Joint Committee on Clinical Practice Guidelines. J\nAm Coll Cardiol. 2022;79(17):1757-1780."},{"n":160,"q":"A right hand\u2013dominant 9-year-old male is brought to your office by his parents after falling from a piece of playground equipment and landing on his left hand. He is in significant pain and there is visible swelling of the distal left forearm. An examination reveals intact distal sensation and capillary refill. He is given oral NSAIDs. X-rays reveal a unicortical irregularity at the distal radial metaphysis without displacement. You diagnose a buckle fracture. Which one of the following would be most appropriate at this time?","o":[{"l":"A","t":"No treatment"},{"l":"B","t":"Immobilization in a prefabricated removable splint for 2\u20133 weeks"},{"l":"C","t":"Immobilization in a short arm cast for 6 weeks"},{"l":"D","t":"Immobilization in a long arm cast for 6 weeks"},{"l":"E","t":"Referral to an orthopedic surgeon"}],"a":"B","e":"This patient has a buckle fracture, or an incomplete compression fracture. These\nfractures are common in younger children due to the relative elasticity of their bones.\nIncreasing evidence supports a shorter period of immobilization and follow-up is often\nnot necessary if symptoms are improving. Removable splints are acceptable and may be\nbetter tolerated and more convenient in younger patients.\nReferences\nKuba MHM, Izuka BH. One brace: one visit: treatment of pediatric distal radius buckle\nfractures with a removable wrist brace and no follow-up visit. J Pediatr Orthop.\n2018;38(6):e338-e342.\nPatel DS, Statuta SM, Ahmed N. Common fractures of the radius and ulna. Am Fam\nPhysician. 2021;103(6):345-354."},{"n":161,"q":"A 25-year-old farmworker from Central America who has been working in the United States for 3 years consults you regarding immunizations. He does not recall receiving any childhood vaccines. He is currently undergoing chemotherapy for non-Hodgkin lymphoma. His next chemotherapy session is in 2 weeks, and he would like to receive as many vaccinations as possible. Which one of the following vaccines would be CONTRAINDICATED in this patient at this time?","o":[{"l":"A","t":"COVID-19"},{"l":"B","t":"Hepatitis B"},{"l":"C","t":"MMR"},{"l":"D","t":"Pneumococcal"},{"l":"E","t":"Tdap"}],"a":"C","e":"Live virus vaccines such as MMR and varicella are contraindicated in\nimmunocompromised persons, including those who are undergoing chemotherapy.\nHowever, COVID-19, hepatitis B, pneumococcal, and Tdap vaccines would all be\nindicated in this patient, especially considering his immunocompromised status.\nReference\nAdult immunization schedule by age: recommendations for ages 19 years or older,\nUnited States, 2024. Centers for Disease Control and Prevention. Last reviewed\nNovember 16, 2023."},{"n":162,"q":"A 74-year-old male with no significant past medical history comes to your office because of pain in his left lower extremity. The patient\u2019s leg was recently immobilized in a cast because of a fibular fracture. Doppler ultrasonography reveals a thrombosis of the iliac vein. Which one of the following is indicated for this patient?","o":[{"l":"A","t":"No anticoagulation"},{"l":"B","t":"Anticoagulation for 3 months"},{"l":"C","t":"Anticoagulation for 6 months"},{"l":"D","t":"Anticoagulation for 12 months"},{"l":"E","t":"Extended anticoagulation with no set stop date"}],"a":"B","e":"This patient experienced a deep vein thrombosis (DVT) that was provoked by his recent\nimmobilization in a cast. According to the American College of Chest Physicians 2021\nguidelines, the recommended duration of anticoagulation for an initial episode of a\nprovoked DVT and pulmonary embolism is 3 months.\n\nReference\nStevens SM, Woller SC, Baumann Kreuziger L, et al. Antithrombotic therapy for VTE\ndisease: second update of the CHEST guideline and expert panel report. Chest.\n2021;160(6):e545-e608."},{"n":163,"q":"A 60-year-old patient presents with a 3-month history of gustatory dysfunction and says that nothing tastes normal. Which one of the following nutritional deficiencies could be responsible for this patient\u2019s taste disorder?","o":[{"l":"A","t":"Calcium"},{"l":"B","t":"Selenium"},{"l":"C","t":"Vitamin B 3"},{"l":"D","t":"Vitamin D"},{"l":"E","t":"Vitamin E"}],"a":"C","e":"Disorders of taste and smell are reported by as many as one-fifth of those \u226540 years of\nage and one-third of those \u226580 years of age. These disorders affect patients\u2019 quality of\nlife and safety. The differential diagnosis is extensive. Of the options listed, only a\ndeficiency of vitamin B3 can cause a taste disturbance (SOR C).\nReference\nSavard DJ, Ursua FG, Gaddey HL. Smell and taste disorders in primary care. Am Fam\nPhysician. 2023;108(3):240-248."},{"n":164,"q":"A 40-year-old female presents with symptoms of heartburn and regurgitation of sour-tasting fluid into her throat after meals. She experiences these symptoms at least twice per week and says that they have been significantly affecting her quality of life. She has tried lifestyle modifications, including elevating the head of her bed and avoiding trigger foods, without significant relief. Which one of the following would be the most appropriate initial management of this patient's condition?","o":[{"l":"A","t":"An antacid as needed"},{"l":"B","t":"An H -receptor antagonist as needed 2"},{"l":"C","t":"A proton pump inhibitor (PPI) as needed"},{"l":"D","t":"A PPI daily for 4\u20138 weeks"},{"l":"E","t":"Esophageal pH monitoring"}],"a":"D","e":"This patient's symptoms of heartburn and regurgitation that occur at least twice per\nweek and significantly affect her quality of life are suggestive of GERD. The most\nappropriate initial management for this patient would be a proton pump inhibitor (PPI)\ndaily for 4\u20138 weeks. PPIs are more effective than antacids and H\u2082-receptor antagonists\nin providing sustained symptomatic relief and resolution of esophagitis.\nAntacids provide short-term relief of symptoms by neutralizing gastric acid but do not\nprovide sustained relief or resolve esophagitis, making them inadequate as the initial\nmanagement strategy for this patient. Similarly, H\u2082-receptor antagonists reduce the\nsecretion of gastric acid but are less effective than PPIs in providing symptom relief and\nhealing esophagitis. They are typically used as an alternative treatment or for milder\ncases of GERD. As-needed PPIs are not the preferred initial management strategy for\nthis patient. Esophageal pH monitoring is indicated in cases in which there is diagnostic\nuncertainty or when evaluating the effectiveness of acid suppression therapy in\nrefractory GERD, but it is not necessary for the initial management of uncomplicated\nGERD.\nReference\nKatz PO, Dunbar KB, Schnoll-Sussman FH, Greer KB, Yadlapati R, Spechler SJ. ACG\nclinical guideline for the diagnosis and management of gastroesophageal reflux disease.\nAm J Gastroenterol. 2022;117(1):27-56."},{"n":165,"q":"Which one of the following is true regarding bariatric surgery?","o":[{"l":"A","t":"It has no effect on obesity-related mortality"},{"l":"B","t":"It results in weight loss equivalent to that seen with intensive multicomponent behavioral interventions"},{"l":"C","t":"It is effective for treating diabetes mellitus"},{"l":"D","t":"Laparoscopic sleeve banding leads to the greatest weight loss"}],"a":"C","e":"Bariatric surgery is highly effective in treating obesity-related comorbidities, particularly\ndiabetes mellitus (SOR A). It also reduces obesity-related mortality (SOR B) and results\nin greater weight loss than nonsurgical weight loss interventions (SOR A). Among the 3\nmajor bariatric surgery procedures, Roux-en-Y gastric bypass leads to the greatest\nweight loss over the first 2 years.\nReference\nSchroeder R, Harrison TD, McGraw SL. Treatment of adult obesity with bariatric\nsurgery. Am Fam Physician. 2016;93(1):31-37."},{"n":166,"q":"Bruising in which one of the following locations would most likely suggest a diagnosis of child abuse?","o":[{"l":"A","t":"Forehead"},{"l":"B","t":"Neck"},{"l":"C","t":"Elbows"},{"l":"D","t":"Knees"},{"l":"E","t":"Shins"}],"a":"B","e":"Bruises on the torso, ears, or neck in children \u22644 years of age are predictive of child\nabuse. \u201cTEN 4\u201d is a useful mnemonic for identifying child abuse: torso (T), ear (E), neck\n(N), and 4 (children \u22644 years of age and any infant <4 months of age). Bruising is the\nmost common injury of physical abuse and may be the only external indicator of an\ninternal injury. Bruises vary by age, location, and pattern. Any bruises identified in a\nnonambulatory infant require careful medical evaluation for possible abuse.\nBruising related to normal activity typically increases with age. The majority of\npreschool- and school-aged children have accidental bruises. The most common sites of\nbruising in nonabused, ambulatory children are the knees and shins, with the majority\nlocated over bony prominences, including the forehead.\nReferences\nChristian CW; Committee on Child Abuse and Neglect, American Academy of Pediatrics.\nThe evaluation of suspected child physical abuse. Pediatrics. 2015;135(5):e1337-e1354.\nSuniega EA, Krenek L, Stewart G. Child abuse: approach and management. Am Fam\nPhysician. 2022;105(5):521-528."},{"n":167,"q":"A 55-year-old male presents to your office with a 3-day history of pain, swelling, and tenderness in the right first metatarsophalangeal (MTP) joint. Four days ago he attended a celebration where he drank a large amount of beer and participated in a hot dog\u2013eating contest. On examination he is afebrile and visibly in pain from his right toe. The right first MTP joint is warm, tender, and swollen. There is no streaking of the skin and no obvious abscess. Which one of the following laboratory tests would support the likely diagnosis?","o":[{"l":"A","t":"A C-reactive protein level"},{"l":"B","t":"A CBC"},{"l":"C","t":"A comprehensive metabolic panel"},{"l":"D","t":"An erythrocyte sedimentation rate"},{"l":"E","t":"A uric acid level"}],"a":"E","e":"This patient is most likely having a flare of gout. Gout is caused by the deposition of\nmonosodium urate crystals in large joints, classically the first metatarsophalangeal joint.\nA patient with a gout flare typically has an elevated uric acid level.\nA C-reactive protein level and an erythrocyte sedimentation rate would likely be\nelevated in this patient, but elevations in those laboratory values are not specific for the\nlikely diagnosis of gout. A CBC would potentially show elevated WBCs in this patient.\nHowever, leukocytosis is nonspecific and would not lead to the specific diagnosis of\ngout. A comprehensive metabolic panel likely would not provide insight into the likely\ndiagnosis.\nReferences\nAbhishek A, Roddy E, Doherty M. Gout-a guide for the general and acute physicians.\nClin Med (Lond). 2017;17(1):54-59.\nClebak KT, Morrison A, Croad JR. Gout: rapid evidence review. Am Fam Physician.\n2020;102(9):533-538.\nDalbeth N, Gosling AL, Gaffo A, Abhishek A. Gout. Lancet. 2021;397(10287):1843-1855."},{"n":168,"q":"A 32-year-old female presents to your office because of a 2-month history of fatigue and myalgias. She reports a 5-lb weight loss and bilateral joint pain in her hands and knees. She has had intermittent fevers to 101 \u00b0F with no cough, dyspnea, or abnormal urinary symptoms. Examination findings are normal. An erythrocyte sedimentation rate is elevated at 35 mm/hr (N <20), and a CBC reveals leukocytosis and a hemoglobin level of 10.4 g/dL (N 12.0\u201315.0). An antinuclear antibody titer is positive at 1:80, and anti\u2013double-stranded DNA and anti-Smith antibodies are elevated. Which one of the following is the most likely diagnosis?","o":[{"l":"A","t":"Polymyalgia rheumatica"},{"l":"B","t":"Psoriatic arthritis"},{"l":"C","t":"Rheumatoid arthritis"},{"l":"D","t":"Septic arthritis"},{"l":"E","t":"Systemic lupus erythematosus"}],"a":"E","e":"This patient\u2019s presentation is suggestive of systemic lupus erythematosus, in which the\ndiagnosis is confirmed by a positive antinuclear antibody (ANA) test and positive anti\u2013\ndouble-stranded DNA and anti-Smith antibodies.\nPolymyalgia rheumatica usually occurs in older patients with bilateral joint pain and\nweakness in the shoulder joint who also have elevated erythrocyte sedimentation rates\nbut do not have a positive ANA test or other positive autoantibodies. Psoriatic arthritis\nusually presents as a polyarthritis and is not associated with a positive ANA test.\nRheumatoid arthritis typically presents with morning stiffness and symmetrical\npolyarthritis in small joints. Septic arthritis typically has an acute presentation involving\na single joint with findings of erythema, warmth, and leukocytosis.\n\nReferences\nFoster ZJ, Day AL, Miller J. Polyarticular joint pain in adults: evaluation and differential\ndiagnosis. Am Fam Physician. 2023;107(1):42-51.\nLam NCV, Brown JA, Sharma R. Systemic lupus erythematosus: diagnosis and\ntreatment. Am Fam Physician. 2023;107(4):383-395."},{"n":169,"q":"A 52-year-old female sees you for a health maintenance examination. Which one of the following findings on fundoscopic examination would be most concerning for glaucoma?","o":[{"l":"A","t":"Constricted retinal vessels"},{"l":"B","t":"Dilated retinal vessels"},{"l":"C","t":"A diminished cup to disc ratio"},{"l":"D","t":"An elevated cup to disc ratio"},{"l":"E","t":"Papilledema"}],"a":"D","e":"Glaucoma is defined as a group of eye diseases that damage the optic nerve. It is\noften, but not always, accompanied by increased intraocular pressure. An increased cup\nto disc ratio (cupping) is an abnormality that is associated with glaucoma. This has\nbeen defined as a ratio >0.3\u20130.5. Retinal vessel changes are not associated with\nglaucoma. Papilledema is a swelling of the optic disc that is generally caused by\nincreased intracranial pressure.\nReference\nMichels TC, Ivan O. Glaucoma: diagnosis and management. Am Fam Physician.\n2023;107(3):253-262."},{"n":170,"q":"A 33-year-old female sees you for follow-up of recently diagnosed diarrhea-predominant irritable bowel syndrome (IBS-D). She has had some improvement in the consistency of her stools and in the frequency and urgency of her bowel movements with the addition of a psyllium supplement, but she continues to have periodic significant cramping and bloating. She prefers over-the-counter products and supplements to prescription medication when possible. Which one of the following over-the-counter products has the best evidence of benefit for improving global symptoms of IBS-D?","o":[{"l":"A","t":"Bismuth subsalicylate (Pepto-Bismol)"},{"l":"B","t":"Omega-3 fatty acids"},{"l":"C","t":"Peppermint oil"},{"l":"D","t":"Hypericum perforatum (St John\u2019s wort)"},{"l":"E","t":"Wheat bran"}],"a":"C","e":"Peppermint oil has evidence of benefit in alleviating symptoms related to irritable bowel\nsyndrome (IBS) and is recommended by the American College of Gastroenterologists,\nthe American Gastroenterological Association, and the British Society of\nGastroenterology in their clinical practice guidelines. Peppermint oil is classified as an\nantispasmodic, and it is thought to have a relaxant effect on smooth muscle due to the\nblockade of calcium channels. Enteric-coated formulations are recommended to avoid\nesophageal reflux that may occur due to relaxation of the lower esophageal sphincter.\nBismuth subsalicylate, omega-3 fatty acids, Hypericum perforatum (St John\u2019s wort), and\nwheat bran are not evidence-based recommendations for the management of IBS in\nany guidelines. Furthermore, wheat bran is a source of insoluble fiber, and soluble fiber\nis recommended for IBS.\nReferences\nLacy BE, Pimentel M, Brenner DM, et al. ACG clinical guideline: management of irritable\nbowel syndrome. Am J Gastroenterol. 2021;116(1):17-44.\n\nLembo A, Sultan S, Chang L, Heidelbaugh JJ, Smalley W, Verne GN. AGA clinical\npractice guideline on the pharmacological management of irritable bowel syndrome with\ndiarrhea. Gastroenterology. 2022;163(1):137-151.\nVasant DH, Paine PA, Black CJ, et al. British Society of Gastroenterology guidelines on\nthe management of irritable bowel syndrome. Gut. 2021;70(7):1214-1240."},{"n":171,"q":"A generally healthy 13-month-old female is brought to the urgent care clinic by her parent because of concerns that she might have pneumonia. The parent says that the toddler has been coughing for the last week and has low energy and decreased appetite. She does not have a history of wheezing or breathing problems. Which one of the following history or physical examination findings, if present, would be the most concerning for community-acquired pneumonia as a cause of this toddler\u2019s cough?","o":[{"l":"A","t":"A 3-day history of fevers up to 100.2 \u00b0F"},{"l":"B","t":"Cloudy nasal drainage"},{"l":"C","t":"Coughing that wakes the child"},{"l":"D","t":"Grunting and retractions"},{"l":"E","t":"Recent pneumococcal vaccination"}],"a":"D","e":"An abnormal chest examination, including grunting and retractions, is one of the\nphysical examination findings most predictive of community-acquired pneumonia in\npediatric patients and one of the criteria used in the Pediatric Acute Febrile Respiratory\nIllness rule. Nasal drainage and the absence of significant fever are negative predictors\nin this rule. Cough that disrupts sleep is a common reason for children to be seen by a\nphysician for medical care, but it is not necessarily suggestive of pneumonia.\nPneumococcal vaccination decreases a child\u2019s risk for significant bacterial communityacquired pneumonia.\nReferences\nChan FYY, Lui CT, Tse CF, Poon KM. Decision rule to predict pneumonia in children\npresented with acute febrile respiratory illness. Am J Emerg Med. 2020;38(12):25572563.\nKatz SE, Williams DJ. Pediatric community-acquired pneumonia in the United States:\nchanging epidemiology, diagnostic and therapeutic challenges, and areas for future\nresearch. Infect Dis Clin North Am. 2018;32(1):47-63.\nKobayashi M, Farrar JL, Gierke R, et al. Use of 15-valent pneumococcal conjugate\nvaccine among US children: updated recommendations of the Advisory Committee on\nImmunization Practices\u2013United States, 2022. MMWR Morb Mortal Wkly Rep.\n2022;71(37):1174-1181.\nMurgia V, Manti S, Licari A, De Filippo M, Ciprandi G, Marseglia GL. Upper respiratory\ntract infection-associated acute cough and the urge to cough: new insights for clinical\npractice. Pediatr Allergy Immunol Pulmonol. 2020;33(1):3-11.\nSmith DK, Kuckel DP, Recidoro AM. Community-acquired pneumonia in children: rapid\nevidence review. Am Fam Physician. 2021;104(6):618-625."},{"n":172,"q":"An 89-year-old female with end-stage, widely metastatic lung cancer is receiving hospice care. Her symptoms, including pain, have been well controlled until recently. According to her caregiver, she is now experiencing excessive oropharyngeal secretions. Which one of the following medications would most effectively control this patient\u2019s secretions?","o":[{"l":"A","t":"Chlorpheniramine/hydrocodone suspension"},{"l":"B","t":"Glycopyrrolate"},{"l":"C","t":"Haloperidol"},{"l":"D","t":"Hydroxyzine"},{"l":"E","t":"Morphine"}],"a":"B","e":"Symptom management at the end of life aims to provide comfort and dignity for\npatients and their families. One of the common symptoms at the end of life is excessive\noropharyngeal secretions. This can cause increased noisy breathing in the last hours to\ndays of life, often referred to as a death rattle. Terminal secretions do not result in\nairway obstruction or respiratory distress for the patient but can be distressing to family\nmembers who are concerned that the patient is \u201cdrowning\u201d in secretions. Family\nmembers often request that suctioning be performed; however, this does not reduce\nthe rattling noise and can cause further distress to the patient.\nAnticholinergic medications can be used to reduce the volume of secretions and noisy\nbreathing, but there is little high-quality evidence to support this practice.\nGlycopyrrolate, hyoscyamine, and transdermal scopolamine may also be used. Neither\nchlorpheniramine/hydrocodone nor hydroxyzine has a role in typical end-of-life care.\nHaloperidol is effective for the treatment of delirium. Opioids such as morphine are\nused to treat dyspnea (SOR B) but have no effect on secretions.\nReferences\nAlbert RH. End-of-life care: managing common symptoms. Am Fam Physician.\n2017;95(6):356-361.\nLim RBL. End-of-life care in patients with advanced lung cancer. Ther Adv Respir Dis.\n2016;10(5):455-467."},{"n":173,"q":"Which one of the following is a best practice strategy for avoiding the use of stigmatizing or judgmental language in the medical record?","o":[{"l":"A","t":"Attributing responsibility to patients for their condition"},{"l":"B","t":"Documenting when a patient \u201crefuses\u201d a recommendation"},{"l":"C","t":"Including socioeconomic status in the \u201cone-liner\u201d about the patient"},{"l":"D","t":"Leading with ethnic identifiers"},{"l":"E","t":"Using person-first language"}],"a":"E","e":"Person-first language focuses on the patient and not the condition and is an important\nhumanizing strategy that should be used in clinical documentation. For example, \u201ca\npatient with diabetes\u201d is preferred over referring to a patient as \u201ca diabetic.\u201d It is\nimportant to avoid blaming the patient by attributing responsibility for their condition to\nthem. Documenting that a patient \u201crefuses\u201d a recommendation carries a negative\nconnotation and it is preferable to use a neutral alternative such \u201cchooses.\u201d Social\nidentifiers such as race, ethnicity, or socioeconomic status can be markers of\nmarginalization and trigger unconscious bias. These identifiers should not be used to\nlead the history of present illness or included in a \u201cone-liner.\u201d Instead, they can be\nincluded in the social history if verified by the patient.\n\nReference\nHealy M, Kidia K. The power in our words: reducing bias in clinical communication. Am\nFam Physician. 2023;107(5):454-455."},{"n":174,"q":"A 32-year-old female presents to your office because of a 2-month history of painful intercourse and vaginal dryness. She is 1 year post partum and started combined oral contraceptives 4 months ago. She is no longer breastfeeding and desires continued contraception. Her menstrual cycles have been regular, and she has not had any vaginal discharge. She reports intermittent dysuria and frequency, but no urinary incontinence. The pelvic examination is within normal limits and her symptoms are not reproduced on examination. A urine pregnancy test is negative, and a urinalysis is within normal limits. Which one of the following would most likely alleviate this patient\u2019s symptoms?","o":[{"l":"A","t":"Switching to a levonorgestrel IUD (Mirena)"},{"l":"B","t":"Trigger point injections"},{"l":"C","t":"OnabotulinumtoxinA (Botox)"},{"l":"D","t":"Cognitive behavioral therapy"},{"l":"E","t":"Myofascial pelvic physical therapy"}],"a":"A","e":"This patient has dyspareunia, and the most likely etiology is vaginal dryness related to\nher use of combined oral contraceptives. The levonorgestrel IUD has not been\nassociated with vaginal dryness, and changing her contraception would likely alleviate\nher symptoms and provide ongoing desired contraception. She can use vaginal\nlubricants or moisturizers for vaginal dryness. She does not meet the diagnostic criteria\nfor vulvodynia, vaginismus, or myofascial pelvic pain syndrome. Trigger point injections,\ncognitive behavioral therapy, and myofascial pelvic physical therapy are possible\ntreatments for vaginismus or vulvodynia. OnabotulinumtoxinA is used off-label as a\ntreatment option for interstitial cystitis or female chronic pelvic pain but only after other\ntreatments have failed.\nReferences\nBoth S, Lew-Starowicz M, Luria M, et al. Hormonal contraception and female sexuality:\nposition statements from the European Society of Sexual Medicine (ESSM). J Sex Med.\n2019;16(11):1681-1695.\nHill DA, Taylor CA. Dyspareunia in women. Am Fam Physician. 2021;103(10):597-604.\nSmith NK, Jozkowski KN, Sanders SA. Hormonal contraception and female pain, orgasm\nand sexual pleasure. J Sex Med. 2014;11(2):462-470."},{"n":175,"q":"A 32-year-old male has presented to your office 4 times over the past several months because of periods of intractable nausea and vomiting lasting 1\u20132 days, with up to 14 episodes each day. He has also experienced moderate abdominal pain, flushing, sweating, and dry mouth during these episodes. On 2 occasions he has required brief admission to the hospital for fluid resuscitation. Promethazine, ondansetron, and metoclopramide (Reglan) have been ineffective in treating his symptoms, but hot showers provide him relief. His medical history is significant for allergic rhinitis and obesity. His social history includes episodes of binge drinking approximately twice monthly and daily marijuana use since age 21. He has no history of intravenous drug use or tobacco abuse. Physical findings are significant for a weight loss of 4.5 kg (10 lb) over the past 3 months and moderate tenderness to epigastric palpation. During acute episodes, laboratory evaluations have revealed only mild elevations in BUN and creatinine levels and hematocrit. Abdominal ultrasonography and CT scans have been normal. Which one of the following is the most likely diagnosis?","o":[{"l":"A","t":"Abdominal migraines"},{"l":"B","t":"Cannabinoid hyperemesis syndrome"},{"l":"C","t":"Carcinoid syndrome"},{"l":"D","t":"Pancreatitis"},{"l":"E","t":"Peptic ulcer disease"}],"a":"B","e":"Cannabinoid hyperemesis syndrome (CHS) has become more common with increased\nlegalization and acceptance of cannabis use. While it can be used as an antiemetic,\ncannabis can also promote vomiting in susceptible individuals who have a significant\nhistory of cannabinoid use. Long duration, higher frequency of use, and higher amounts\nof cannabis use are all risk factors for CHS. Symptomatic relief with hot showers or\nbaths is not found in abdominal migraines, carcinoid syndrome, or peptic ulcer disease.\nPancreatitis would cause elevations in lipase levels and some findings on imaging would\nbe expected. Nausea from the other causes is generally relieved with traditional\nantiemetics. Carcinoid syndrome also causes episodic symptoms such as facial flushing,\ndiarrhea, hypotension, and tachycardia, but not nausea or vomiting.\n\nReferences\nAngus-Leppan H, Saatci D, Sutcliffe A, Guiloff RJ. Abdominal migraine. BMJ.\n2018;360:k179.\nFashner J, Gitu AC. Diagnosis and treatment of peptic ulcer disease and H. pylori\ninfection. Am Fam Physician. 2015;91(4):236-242.\nIto T, Lee L, Jensen RT. Carcinoid-syndrome: recent advances, current status and\ncontroversies. Curr Opin Endocrinol Diabetes Obes. 2018;25(1):22-35.\nPerisetti A, Gajendran M, Dasari CS, et al. Cannabis hyperemesis syndrome: an update\non the pathophysiology and management. Ann Gastroenterol. 2020;33(6):571-578.\nSorensen CJ, DeSanto K, Borgelt L, Phillips KT, Monte AA. Cannabinoid hyperemesis\nsyndrome: diagnosis, pathophysiology, and treatment-a systematic review. J Med\nToxicol. 2017;13(1):71-87."},{"n":176,"q":"Which one of the following conditions is most associated with an increased risk for venous thromboembolism?","o":[{"l":"A","t":"Active cancer"},{"l":"B","t":"COPD"},{"l":"C","t":"Poorly controlled type 2 diabetes"},{"l":"D","t":"Severe intermittent asthma"},{"l":"E","t":"Stage 3 chronic kidney disease"}],"a":"A","e":"Patients with venous thromboembolism (VTE) should receive anticoagulant therapy for\nat least 3 months to reduce the risk for further embolization. In patients with persistent\nprovoking factors such as active cancer or antiphospholipid syndrome, or who have had\nprevious episodes of unprovoked VTE, the long-term risk for recurrence is high and\nindefinite anticoagulation therapy is recommended. The risk for VTE is much higher\nwith active cancer compared to COPD, poorly controlled type 2 diabetes, severe\nintermittent asthma, and stage 3 chronic kidney disease.\nReference\nOrtel TL, Neumann I, Ageno W, et al. American Society of Hematology 2020 guidelines\nfor management of venous thromboembolism: treatment of deep vein thrombosis and\npulmonary embolism. Blood Adv. 2020;4(19):4693-4738."},{"n":177,"q":"A 59-year-old female asks when she should consider screening for osteoporosis. Her last menstrual period was at age 53. According to the U.S. Preventive Services Task Force, which one of the following risk factors, if present, should lead to a calculation of osteoporosis risk with a screening tool and consideration of screening for osteoporosis now?","o":[{"l":"A","t":"Low caffeine consumption"},{"l":"B","t":"High alcohol consumption"},{"l":"C","t":"Body weight >100 kg (220 lb)"},{"l":"D","t":"A maternal aunt with a history of hip fracture"},{"l":"E","t":"Nonsmoking status"}],"a":"B","e":"In postmenopausal women younger than age 65, the U.S. Preventive Services Task\nForce recommendations for osteoporosis screening include assessing for osteoporosis\nrisk factors (parental history of hip fracture, smoking, high alcohol consumption, or low\nbody weight) and use of a clinical risk assessment tool if 1 or more risk factors are\npresent.\n\nReference\nUS Preventive Services Task Force; Curry SJ, Krist AH, et al. Screening for osteoporosis\nto prevent fractures: US Preventive Services Task Force recommendation statement.\nJAMA. 2018;319(24):2521-2531."},{"n":178,"q":"A 62-year-old female sees you for evaluation of pain and stiffness in her neck. For several years she has attributed these symptoms to the aging process, but she has recently developed a loss of dexterity in her hands that makes typing and knitting difficult. She does not have any loss of sensation or weakness in her extremities but has noticed some difficulties with balance in recent weeks. The pain does not radiate, and she does not have any history of recent trauma. She feels well otherwise and has not had any fevers, chills, bowel incontinence, or bladder incontinence. On examination you note mild tenderness of the spinous processes and paraspinous muscles of the cervical spine without focal tenderness. Her range of motion at the neck is limited due to pain. There are brisk reflexes in the bilateral upper and lower extremities and a positive Hoffman sign bilaterally with 4 beats of clonus on the right and 5 on the left. Her strength and sensation to light touch are intact in the bilateral upper extremities. Which one of the following cervical spine conditions is the most likely diagnosis?","o":[{"l":"A","t":"Facet joint arthropathy"},{"l":"B","t":"Myelopathy"},{"l":"C","t":"Radiculopathy"},{"l":"D","t":"Vertebral compression fracture"},{"l":"E","t":"Vertebral osteomyelitis"}],"a":"B","e":"The patient history and physical examination findings are most consistent with\ndegenerative cervical myelopathy, a condition in which spinal cord dysfunction develops\ndue to compression in the neck. Spinal cord compression can be due to disk herniation,\nligament hypertrophy, or osteophyte formation, sometimes collectively called\nspondylosis. Symptoms can initially be nonspecific and subtle, and they can overlap\nwith less serious conditions. Loss of hand dexterity, ataxia, and urinary urgency can be\nsigns of spinal cord compression and warrant a comprehensive neurologic examination.\nThe development of upper motor neuron signs including hyperreflexia, a positive\nHoffmann sign (digital reflex of the fingers), and clonus are key findings that warrant\nurgent evaluation with MRI.\nFacet joint arthropathy causes more focal pain and is not associated with neurologic\nsymptoms. Cervical radiculopathy involves compression of the nerve root rather than\nthe spinal cord. Symptoms include shooting pain with sensory changes and weakness in\na dermatomal distribution. A vertebral compression fracture leads to focal pain in the\nneck at the site of the fracture without neurologic symptoms. Osteomyelitis also causes\nmore focal pain in the setting of systemic symptoms such as malaise and fever.\nReferences\nChildress MA, Stuek SJ. Neck pain: initial evaluation and management. Am Fam\nPhysician. 2020;102(3):150-156.\nDavies BM, Mowforth OD, Smith EK, Kotter MRN. Degenerative cervical myelopathy.\nBMJ. 2018;360:k186."},{"n":179,"q":"A 30-year-old female presents to your office to discuss fertility and her irregular menses. The patient and her husband have been trying to conceive for the past 3 years but have been unsuccessful due to her irregular menstrual periods. Physical examination findings are significant for hirsutism and acne with hyperpigmentation on the posterior aspect of the neck and in the axillae. Her BMI is 35 kg/m2. Laboratory studies from 1 month ago show a hemoglobin A of 5.0%. 1c Which one of the following medications would be the most appropriate treatment of this patient\u2019s infertility?","o":[{"l":"A","t":"A GLP-1 receptor agonist"},{"l":"B","t":"Letrozole (Femara)"},{"l":"C","t":"Metformin"},{"l":"D","t":"Spironolactone (Aldactone)"}],"a":"B","e":"This patient likely has polycystic ovary syndrome (PCOS) based on the clinical history\nand physical examination findings. Letrozole is an aromatase inhibitor that decreases\nthe amount of estrogen produced by the body and is considered the first-line treatment\nfor inducing ovulation in women with PCOS.\n\nGLP-1 receptor agonists reduce the degree of metabolic syndrome in patients with\nPCOS and are not indicated for ovulation induction. Metformin is inferior to letrozole for\novulation induction in patients with PCOS. Furthermore, this patient's hemoglobin A1c\nindicates that she does not have prediabetes or diabetes mellitus. Spironolactone is an\nantiandrogen and is used to treat many PCOS symptoms, such as hirsutism, but does\nnot induce ovulation.\nReferences\nGoodman NF, Cobin RH, Futterweit W, et al. American Association of Clinical\nEndocrinologists, American College of Endocrinology, and Androgen Excess and PCOS\nSociety Disease State clinical review: guide to the best practices in the evaluation and\ntreatment of polycystic ovary syndrome-part 1. Endocr Pract. 2015;21(11):1291-1300.\nGoodman NF, Cobin RH, Futterweit W, et al. American Association of Clinical\nEndocrinologists, American College of Endocrinology, and Androgen Excess and PCOS\nSociety Disease State clinical review: guide to the best practices in the evaluation and\ntreatment of polycystic ovary syndrome-part 2. Endocr Pract. 2015;21(12):1415-1426.\nShrivastava S, Conigliaro RL. Polycystic ovarian syndrome. Med Clin North Am.\n2023;107(2):227-234.\nWilkinson LD, Brady PH, Gin GT, Rosenblum E. Female pelvic conditions: polycystic\novary syndrome. FP Essent. 2022;515:26-31.\nWilliams T, Moore JB, Regehr J. Polycystic ovary syndrome: common questions and\nanswers. Am Fam Physician. 2023;107(3):264-272."},{"n":180,"q":"Which one of the following is present in polycythemia vera?","o":[{"l":"A","t":"An \u03b1-1 antitrypsin deficiency"},{"l":"B","t":"An elevated \u03b1-fetoprotein level"},{"l":"C","t":"An elevated erythropoietin level"},{"l":"D","t":"Antimitochondrial antibodies"},{"l":"E","t":"A Janus kinase 2 mutation"}],"a":"E","e":"The World Health Organization\u2019s major diagnostic criteria for polycythemia vera include\nan elevated hemoglobin or hematocrit level, abnormal bone marrow biopsy results, and\nthe presence of the Janus kinase 2 (JAK2) genetic mutation, found in 98% of cases.\nThe only minor criterion is a subnormal erythropoietin level, which helps distinguish\npolycythemia vera from common causes of secondary erythrocytosis such as smoking,\nsleep apnea, and testosterone use.\nReference\nFox S, Griffin L, Robinson Harris D. Polycythemia vera: rapid evidence review. Am Fam\nPhysician. 2021;103(11):680-687."},{"n":181,"q":"A 72-year-old male presents to your office 3 months after hospitalization for an ischemic stroke. He has a history of diabetes mellitus that is well controlled on basal insulin. He has impaired mobility and balance, as well as left upper and lower extremity spasticity. He has fallen twice in the last week. His blood pressure is well controlled and recent laboratory studies are notable for an LDL-cholesterol level of 64 mg/dL and a hemoglobin A of 6.9%. There is no evidence of cognitive impairment. His 1c Patient Health Questionnaire\u20139 (PHQ-9) score is 3. Which one of the following would be the most appropriate next step in optimizing his post-stroke care?","o":[{"l":"A","t":"Repeating neuroimaging"},{"l":"B","t":"Increasing the basal insulin dosage"},{"l":"C","t":"Initiating lorazepam (Ativan), 1\u20132 mg at bedtime"},{"l":"D","t":"Initiating sertraline (Zoloft), 50 mg daily"},{"l":"E","t":"Referral to a physical therapist"}],"a":"E","e":"This patient has common post-stroke complications and will benefit from physical\ntherapy to address his mobility and spasticity, and to prevent falls. Repeat\nneuroimaging would only be indicated with a change in neurologic examination,\nincluding new focal neurologic deficits. His diabetes mellitus is adequately controlled\nand further increasing his insulin puts him at increased risk of hypoglycemia. Lorazepam\nis not first-line therapy for spasticity and is also associated with increased fall risk.\nDepression is common post stroke, but this patient is not reporting symptoms of low\nmood and has a normal Patient Health Questionnaire\u20139 score.\nReference\nLarson ST, Ray BE, Wilbur J. Ischemic stroke management: posthospitalization and\ntransition of care. Am Fam Physician. 2023;108(1):70-77."},{"n":182,"q":"You see a 50-year-old female for a health maintenance examination. She is the primary caregiver for her father who has dementia, and she has heard that Alzheimer disease is genetic and asks if there is anything she can do to reduce her risk. She is in perimenopause and experiences severe hot flashes. She recently started a kickboxing class and drinks 1\u20132 beers per week. On examination her vital signs include a blood pressure of 138/80 mm Hg, a pulse rate of 63 beats/min, and a BMI of 30 kg/m2. Which one of the following should you recommend to decrease this patient\u2019s risk for dementia?","o":[{"l":"A","t":"A memory training app on her smartphone"},{"l":"B","t":"Abstaining from alcohol"},{"l":"C","t":"Testing for biomarkers associated with Alzheimer disease"},{"l":"D","t":"A target systolic blood pressure \u2264130 mm Hg"},{"l":"E","t":"Hormone therapy with estrogen and progesterone"}],"a":"D","e":"Maintaining a systolic blood pressure \u2264130 mm Hg in midlife has been shown to reduce\nthe risk for developing dementia. While reading, playing music, and speaking a foreign\nlanguage have demonstrated benefits in maintaining cognition, there is no good-quality\nevidence to show that computer-based memory training games prevent cognitive\ndecline. Extremes of alcohol use (both long-term abstinence and abuse) are associated\nwith an increased risk for dementia. Most people who are positive for biomarkers\nassociated with Alzheimer disease will not go on to develop the disease. Additionally,\nthere is no evidence that presymptomatic identification of Alzheimer disease is\nbeneficial. Hormone therapy with estrogen and progesterone is an effective treatment\nfor vasomotor symptoms of menopause but is associated with an increased risk for\ndementia when administered in women \u226565 years of age. For women in their 40s and\n50s, hormone therapy with estrogen only has demonstrated a significant decrease in\ndementia, while estrogen plus progesterone therapy has demonstrated a nonsignificant\ndecrease.\nReferences\nGartlehner G, Patel SV, Reddy S, Rains C, Schwimmer M, Kahwati L. Hormone therapy\nfor the primary prevention of chronic conditions in postmenopausal persons: updated\nevidence report and systematic review for the US Preventive Services Task Force. JAMA.\n2022;328(17):1747-1765.\n\nGates NJ, Vernooij RW, Di Nisio M, et al. Computerised cognitive training for preventing\ndementia in people with mild cognitive impairment. Cochrane Database Syst Rev.\n2019;3(3):CD012279.\nLivingston G, Huntley J, Sommerlad A, et al. Dementia prevention, intervention, and\ncare: 2020 report of the Lancet Commission. Lancet. 2020;396(10248):413-446.\nNerattini M, Jett S, Andy C, et al. Systematic review and meta-analysis of the effects of\nmenopause hormone therapy on risk of Alzheimer\u2019s disease and dementia. Front Aging\nNeurosci. 2023;15:1260427."},{"n":183,"q":"Which one of the following attention-deficit/hyperactivity disorder (ADH medications is considered safest to take while breastfeeding?","o":[{"l":"A","t":"Amphetamine (Evekeo)"},{"l":"B","t":"Atomoxetine (Strattera)"},{"l":"C","t":"Clonidine"},{"l":"D","t":"Guanfacine"},{"l":"E","t":"Methylphenidate (Ritalin)"}],"a":"E","e":"Racemic methylphenidate has been studied in breastfeeding mothers and drug levels in\nbreast milk were found to be about 0.2% of the adult dose. Drug levels were\nundetectable in breastfed infants and the infants had no long-term growth or\ndevelopmental issues. Methylphenidate can reduce serum prolactin levels, but this has\nnot been shown to have any clinical impact on milk supply. Less is known about\namphetamine in breastfeeding, but milk and infant serum levels are significantly higher\nthan with methylphenidate. Atomoxetine and guanfacine have no reliable data in\nbreastfeeding and should be avoided until more is known. Clonidine has been shown to\nbe present in significant amounts in breast milk and serum from breastfed infants (up\nto 50% of the maternal serum levels). While no adverse effects have been shown, this\nhigh level of medication in the infant raises concerns, and experts recommend avoiding\nclonidine while breastfeeding.\nReferences\nAnderson PO. Stimulant therapy during breastfeeding. Breastfeed Med.\n2021;16(12):931-932.\nSpencer JP, Thomas S, Trondsen Pawlowski RH. Medication safety in breastfeeding. Am\nFam Physician. 2022;106(6):638-644."},{"n":184,"q":"A 20-year-old female is brought to the emergency department after experiencing blunt abdominal trauma during a motor vehicle accident. A focused assessment with sonography for trauma (FAST) examination is performed at the bedside and there are no signs of internal bleeding. Based on these results, which one of the following should be the next step in evaluation?","o":[{"l":"A","t":"No further imaging to evaluate for internal bleeding"},{"l":"B","t":"Additional imaging only if the patient develops signs of hemodynamic compromise"},{"l":"C","t":"Additional imaging to confirm the absence of bleeding"},{"l":"D","t":"Diagnostic peritoneal lavage"}],"a":"C","e":"The focused assessment with sonography for trauma (FAST) evaluates the pericardium\nand 3 potential spaces within the peritoneal cavity for hemoperitoneum and\nhemopericardium. This bedside examination can be completed in less than 5 minutes,\nso it is ideal for emergency department settings. FAST has replaced diagnostic\nperitoneal lavage as a bedside evaluation for bleeding. A Cochrane review found that\nFAST has a 96% specificity but only a 74% sensitivity for detecting internal bleeding.\nThe sensitivity in children was found to be even lower at 62%. Therefore, while a\npositive result will almost always be reliable and should prompt immediate bleeding\ncontrol measures, a negative result carries the risk of being a false negative and must\nbe confirmed by additional imaging such as CT.\nReferences\nArnold MJ, Jonas CE, Carter RE. Point-of-care ultrasonography. Am Fam Physician.\n2020;101(5):275-285.\nStengel D, Leisterer J, Ferrada P, Ekkernkamp A, Mutze S, Hoenning A. Point-of-care\nultrasonography for diagnosing thoracoabdominal injuries in patients with blunt trauma.\nCochrane Database Syst Rev. 2018;12(12):CD012669."},{"n":185,"q":"A 65-year-old male sees you for follow-up after he was hospitalized for pneumonia a few months ago. He has smoked 1 pack of cigarettes per day for 40 years. Pulmonary function testing today shows an FEV of 60% of predicted and an FEV /FVC ratio of 0.65. Physical examination findings 1 1 include a BMI of 24 kg/m2 and scattered rhonchi in the chest. Which one of the following inhalers is the recommended initial treatment to decrease this patient\u2019s number of exacerbations?","o":[{"l":"A","t":"Budesonide/formoterol (Symbicort)"},{"l":"B","t":"Fluticasone propionate"},{"l":"C","t":"Ipratropium bromide/albuterol (Combivent Respimat)"},{"l":"D","t":"Salmeterol (Serevent Diskus)"},{"l":"E","t":"Tiotropium (Spiriva)"}],"a":"E","e":"According to the GOLD Spirometry Classification, an FEV1/FVC ratio <0.70 and an FEV1\n\u226550% and <80% of predicted is stage 2 COPD. Initial inhaler pharmacotherapy can be\nguided by the GOLD ABCD assessment that integrates symptoms and exacerbations.\nModerate exacerbations require either an oral antibiotic, an oral corticosteroid, or both,\nwhile a severe exacerbation results in an emergency department visit or hospitalization.\nPatients with 2 or more moderate exacerbations or 1 or more hospitalizations, such as\nthis patient, should be prescribed a long-acting muscarinic antagonist (LAMA) as firstline therapy. Monotherapy with this group of medications reduces symptoms, decreases\nexacerbations, and decreases hospitalizations.\n\nInhaled corticosteroids (ICS) such as fluticasone propionate are not recommended as\nmonotherapy for COPD, particularly for those who have had pneumonia. Using a longacting \u03b2-agonist (LABA) with an ICS is less effective at reducing exacerbations and\nincreases the risk for pneumonia. Monotherapy with a LABA such as salmeterol reduces\nexacerbations requiring hospitalization, but symptoms are better controlled when a\nLABA is used in combination with a LAMA. Short-acting \u03b2-adrenergic agonists and shortacting muscarinic antagonists are appropriate for acute exacerbations rather than\nprevention.\nReferences\nArnold M, Vordtriede C, Chadwick C, Trivette E. COPD inhaler therapy: a path to\nsuccess. J Fam Pract. 2022;71(7):280-289.\nGlobal Initiative for Chronic Obstructive Lung Disease (GOLD). Spirometry for health\ncare providers. 2010."},{"n":186,"q":"You are the attending physician at a nursing home and the charge nurse notifies you that 3 symptomatic patients in 1 unit have tested positive for influenza A. The facility is implementing enhanced contact and droplet precautions. To prevent additional cases, you should recommend chemoprophylaxis with oseltamivir (Tamiflu) for","o":[{"l":"A","t":"no residents or staff"},{"l":"B","t":"only residents of the affected unit who have not received influenza vaccine"},{"l":"C","t":"only residents of the affected unit"},{"l":"D","t":"only residents of the facility who have not received influenza vaccine"},{"l":"E","t":"all residents of the facility"}],"a":"C","e":"In its 2018 clinical practice guideline, the Infectious Diseases Society of America\nsummarized its recommendations on the diagnosis and management of seasonal\ninfluenza, including institutional outbreak management. These recommendations\ninclude active surveillance for additional cases any time a resident of a long-term care\nfacility is diagnosed with laboratory-confirmed influenza. Influenza can spread rapidly in\nthe long-term care setting and outbreak control measures should be implemented\nimmediately. The risk for severe disease and complications from influenza are high in\nfrail older adults, and those with cognitive impairment may be less able to describe their\nsymptoms, making case-finding more difficult. When a resident develops any\nrespiratory symptoms during an influenza outbreak, empiric antiviral treatment should\nbe initiated as soon as possible without waiting for diagnostic testing results. Residents\nwho have been exposed to those with influenza should receive chemoprophylaxis as\nsoon as possible, regardless of their vaccination status. It is not necessary to initiate\nchemoprophylaxis for residents who are located on remote units.\nReference\nUyeki TM, Bernstein HH, Bradley JS, et al. Clinical practice guidelines by the Infectious\nDiseases Society of America: 2018 update on diagnosis, treatment, chemoprophylaxis,\nand institutional outbreak management of seasonal influenza. Clin Infect Dis.\n2019;68(6):e1-e47."},{"n":187,"q":"A 65-year-old female with no chronic medical problems presents for an annual Medicare wellness visit. You initiate a discussion regarding cervical cancer screening. According to current clinical guidelines, which one of the following would be an indication for additional cervical cancer screening in this patient?","o":[{"l":"A","t":"A family history of cervical cancer in a first-degree relative"},{"l":"B","t":"Loop excision of a high-grade precancerous lesion 15 years ago, with consecutive normal results since then"},{"l":"C","t":"Three consecutive normal cytology results within the past 10 years, most recently 3 years ago"},{"l":"D","t":"Two consecutive normal cytology results with negative high-risk HPV co-testing within the past 10 years, most recently 4 years ago"},{"l":"E","t":"Unprotected intercourse with a new sex partner"}],"a":"B","e":"The U.S. Preventive Services Task Force (USPSTF) recommends against cervical cancer\nscreening for women >65 years of age with normal Papanicolaou (Pap) smears, who\nhave had adequate prior screening, and who otherwise are not at increased risk for\ncervical cancer (D recommendation). The most recent definition of \u201cadequate prior\nscreening\u201d given by the American Cancer Society (ACS) is 3 consecutive negative\ncytology results, 2 consecutive negative co-testing results, or 2 consecutive negative\nhigh-risk HPV tests in the 10 years prior to discontinuation of screening, with the most\nrecent test having occurred within the relevant recommended testing interval. The\nrecommended interval is every 3 years for cytology, and 5 years for both high-risk HPV\nand co-testing.\nImportantly, USPSTF guidelines do not apply to individuals who are at increased risk for\ncervical cancer, including women with a history of high-grade precancerous cervical\nlesions or cervical cancer. The ACS and the American Society of Colposcopy and\nCervical Pathology (ASCCP) guidelines recommend continuation of cervical cancer\nscreening for women with a history of a high-grade precancerous lesion (defined as\ncervical intraepithelial neoplasia [CIN] grade 2 or higher) for a minimum of 25 years\nbeyond the treatment of the lesion, even if this extends beyond 65 years of age. Thus,\nif this patient had a history of treatment for a high-grade lesion 15 years ago, this\nwould warrant continued screening for an additional 10 years.\nThe presence of a new sex partner should not impact the decision to discontinue\nscreening for women who otherwise are eligible for cessation of screening. In fact, ACS\nrecommendations apply to all asymptomatic people with a cervix, without regard to\ntheir sexual history. In contrast to several other common cancer types, cervical cancer\nrisk is not associated with a familial/genetic inheritance pattern; therefore, a family\nhistory of cervical cancer, even in a first-degree relative, should not impact a cervical\ncancer screening decision.\nReferences\nFontham ETH, Wolf AMD, Church TR, et al. Cervical cancer screening for individuals at\naverage risk: 2020 guideline update from the American Cancer Society. CA Cancer J\nClin. 2020;70(5):321-346.\nPerkins RB, Guido RS, Castle PE, et al. 2019 ASCCP risk-based management consensus\nguidelines for abnormal cervical cancer screening tests and cancer precursors. J Low\nGenit Tract Dis. 2020;24(2):102-131.\nUS Preventive Services Task Force. Final recommendation statement: cervical cancer:\nscreening. Updated August 21, 2018."},{"n":188,"q":"A 67-year-old male presents for an annual health maintenance visit. His medical conditions include hypertension, dyslipidemia, severe aortic stenosis, and osteoarthritis. He is under the care of a cardiologist and is scheduled for an annual echocardiogram next week. He reports that he generally feels well but \u201ccan\u2019t keep up with the grandkids\u201d anymore. He has not had any lightheadedness, chest pain, shortness of breath, or lower extremity edema. Which one of the following findings would support surgical treatment for aortic stenosis at this time?","o":[{"l":"A","t":"An elevated 10-year atherosclerotic cardiovascular disease risk"},{"l":"B","t":"A left ventricular ejection fraction of 40%\u201345%"},{"l":"C","t":"A need for an elective total knee replacement"},{"l":"D","t":"A normal exercise stress test result"}],"a":"B","e":"Aortic stenosis (AS) occurs primarily in older adults and is a result of narrowing of the\naortic valve area due to damage from the aging process that involves lipid\naccumulation, calcification, and inflammation. While survival rates in patients with\nasymptomatic AS match those without AS, survival rates drop dramatically once\nsymptoms develop. Because there is no effective medical management for preventing\nthe progression of AS, recognizing indications for aortic valve replacement (AVR) results\nin improved survival and symptoms. Any symptomatic patient with severe AS\n(maximum transaortic velocity \u22654.0 m/s or mean pressure gradient \u226540 mm Hg)\nshould undergo AVR. It is difficult to determine whether this patient is truly\nsymptomatic from AS, but a left ventricular ejection fraction <50% would support a\nneed for AVR in this patient. An abnormal exercise stress test, rather than a normal\ntest, would also indicate a need for AVR. Finally, a need for other cardiac surgery, such\nas coronary artery bypass grafting, would also prompt AVR. An elevated atherosclerotic\ncardiovascular disease risk should prompt consideration of statin and aspirin prophylaxis\nbut does not play a role in deciding when to perform AVR. A need for a noncardiac,\nelective surgical intervention would not lead to a recommendation for AVR due to the\nhigh-risk nature of AVR.\nReference\nGrimard BH, Safford RE, Burns EL. Aortic stenosis: diagnosis and treatment. Am Fam\nPhysician. 2016;93(5):371-378."},{"n":189,"q":"A 44-year-old male presents for evaluation of left shoulder pain and stiffness that has developed gradually over the past few months after a fall while skiing. He describes a dull, deep, poorly localized ache. On examination he has impaired active and passive range of motion in all planes. Radiography of the shoulder is unremarkable. Which one of the following is most likely to lead to symptom resolution?","o":[{"l":"A","t":"Wearing a sling on the left arm for 4\u20136 weeks"},{"l":"B","t":"Extracorporeal shock wave therapy"},{"l":"C","t":"Biceps tendon sheath injection and physical therapy"},{"l":"D","t":"Glenohumeral corticosteroid injection and physical therapy"},{"l":"E","t":"Surgical repair"}],"a":"D","e":"This patient presents with adhesive capsulitis, manifested as the typical cardinal\nsymptoms of pain, stiffness, and dysfunction of the affected shoulder. A combination of\nglenohumeral or subacromial corticosteroid injection and physical therapy is most likely\nto produce early and sustained improvement in symptoms and joint functioning.\nProlonged use of a sling would worsen the condition. Referral for surgery may be\nindicated after a 3-month trial of conservative treatment fails. While extracorporeal\nshock wave therapy has shown benefit for frozen shoulder, its current role is as an\nadjunct to other primary therapies.\n\nReferences\nRamirez J. Adhesive capsulitis: diagnosis and management. Am Fam Physician.\n2019;99(5):297-300.\nZhang R, Wang Z, Liu R, Zhang N, Guo J, Huang Y. Extracorporeal shockwave therapy\nas an adjunctive therapy for frozen shoulder: a systematic review and meta-analysis.\nOrthop J Sports Med. 2022:10(2)."},{"n":190,"q":"A 6-year-old male is brought to your office by his parents for follow-up after being seen in the emergency department (E","o":[{"l":"D","t":"for an unprovoked, nonfebrile seizure. He does not have any prior seizure history and his past medical history is unremarkable. An EEG in the ED was normal. The parents are concerned about his risk for recurrent seizure and ask about treatment with anti-epileptic drug (AED) therapy. Which one of the following should you recommend?"},{"l":"A","t":"Starting AED monotherapy only if he has a second seizure"},{"l":"B","t":"Starting AED monotherapy now"},{"l":"C","t":"Starting combination AED therapy only if he has a second seizure"},{"l":"D","t":"Starting combination AED therapy now"}],"a":"A","e":"In the absence of risk factors such as abnormal EEG results, the presence of a\npredisposition to seizures, or an etiology such as severe head trauma or cerebral palsy,\nanti-epileptic drug (AED) therapy is not indicated after a first unprovoked childhood\nseizure. There is no significant difference in 1- to 2-year seizure remission rates\nbetween starting AED therapy after the first or second seizure, and there are significant\nrisks associated with AED treatment. AED monotherapy should be attempted before\nstarting AED combination therapy.\nReference\nLiu G, Slater N, Perkins A. Epilepsy: treatment options. Am Fam Physician.\n2017;96(2):87-96."},{"n":191,"q":"A 48-year-old female presents to your office because of an erythematous rash on her left posterior calf and right posterior thigh (shown below). Five days ago she was stung by wasps in those locations. The stings were initially associated with intense pain and small areas of erythema that have since expanded to approximately 10-cm erythematous patches surrounding the original sting sites. On examination there are erythematous patches on her left posterior calf and right posterior thigh with warmth, induration, and tenderness to palpation. She does not have any fevers or chills. The examination findings are otherwise within normal limits. Which one of the following would be the most appropriate treatment at this time?","o":[{"l":"A","t":"Topical neomycin/polymyxin B/pramoxine (Neosporin)"},{"l":"B","t":"Oral cephalexin"},{"l":"C","t":"Oral diphenhydramine"},{"l":"D","t":"Oral prednisone"},{"l":"E","t":"Oral sulfamethoxazole/trimethoprim (Bactrim)"}],"a":"D","e":"This patient is experiencing a large local reaction to an insect sting, occurring between\na few days to 1 week after the initial sting. This occurs in about 19% of reactions and\ncarries a 5%\u201310% risk for a systemic reaction in subsequent exposures. The treatment\nis prednisone, 40\u201360 mg daily for 3\u20135 days. This is not an infection but rather a\nreaction to the Hymenoptera sting, so oral or topical antibiotics are not indicated.\nAntihistamines such as diphenhydramine are useful for pruritus but are not a treatment\nfor the reaction.\nReference\nHerness J, Snyder MJ, Newman RS. Arthropod bites and stings. Am Fam Physician.\n2022;106(2):137-147."},{"n":192,"q":"A 39-year-old female presents with a sudden onset of palpitations. Her vital signs include a blood pressure of 114/68 mm Hg and a pulse rate of 166 beats/min. She is cooperative and alert. An EKG shows regular narrow complex tachycardia with normal intervals. She has tried vagal maneuvers with no improvement. Which one of the following would be the most appropriate treatment at this time?","o":[{"l":"A","t":"Adenosine"},{"l":"B","t":"Atropine"},{"l":"C","t":"Diltiazem (Cardizem)"},{"l":"D","t":"Metoprolol"},{"l":"E","t":"Synchronized cardioversion  Item #191 Item #191"}],"a":"A","e":"If vagal maneuvers are not effective in the management of stable supraventricular\ntachycardia (SVT), the most appropriate next step is treatment with intravenous\nadenosine at an initial dose of 6 mg. Atropine is a treatment option for bradycardia,\nparticularly in the setting of heart block. Diltiazem or metoprolol may be used acutely in\natrial fibrillation or in the prevention of SVT. Synchronized cardioversion is indicated in\npatients with SVT who become hypotensive or unresponsive.\nReference\nPage RL, Joglar JA, Caldwell MA, et al. 2015 ACC/AHA/HRS guideline for the\nmanagement of adult patients with supraventricular tachycardia: executive summary: a\nreport of the American College of Cardiology/American Heart Association Task Force on\nClinical Practice Guidelines and the Heart Rhythm Society. Circulation.\n2016;133(14):e471-e505."},{"n":193,"q":"A 29-year-old female presents with low back pain that began after giving birth 3 months ago. She reports pain on her right side when climbing and descending stairs and when lying on her right side. On examination she has mild lumbar paraspinal muscle tightness on the left and moderate tenderness inferomedial to the posterior superior iliac spine on the right. Muscle strength testing and lower extremity reflexes are normal. Which one of the following conditions is the most likely cause of this patient\u2019s pain?","o":[{"l":"A","t":"Lumbar strain"},{"l":"B","t":"Piriformis syndrome"},{"l":"C","t":"Pudendal nerve entrapment"},{"l":"D","t":"Sacroiliac joint dysfunction"},{"l":"E","t":"Spondyloarthropathy"}],"a":"D","e":"Sacroiliac joint dysfunction is commonly seen in primary care and is an important\nconsideration in the evaluation of low back pain. It often occurs during pregnancy and\npost partum. Other inciting incidents include a motor vehicle accident or a mechanical\nfall onto the buttocks. It can be associated with ankylosing spondylitis and other\nspondyloarthropathies; however, the etiology in this case is more likely to be childbirth.\nSymptoms often include pain at the sacroiliac joint that worsens with climbing stairs,\nlying on the affected side, prolonged standing and sitting, and weight-bearing on the\nleg of the affected side. Examination findings include tenderness that is inferomedial to\nthe posterior superior iliac spine. A number of provocation tests for sacroiliac joint\ndysfunction can help to confirm the diagnosis. NSAIDs, physical therapy, and joint\nmanipulation are first-line treatments. Pelvic belts, corticosteroid injections, and\nsacroiliac joint fusion are used for refractory cases.\nLumbar strain is in the differential diagnosis, but sacroiliac joint dysfunction is more\nlikely given this patient\u2019s history and the duration and location of tenderness. Piriformis\nsyndrome is usually unilateral and causes sciatic-like symptoms. Pudendal nerve\nentrapment would cause perineal pain or labial numbness. Spondyloarthropathies are\nassociated with sacroiliac joint inflammation but are not as likely in this postpartum\npatient.\n\nReferences\nNejati P, Safarcherati A, Karimi F. Effectiveness of exercise therapy and manipulation on\nsacroiliac joint dysfunction: a randomized controlled trial. Pain Physician.\n2019;22(1):53-61.\nNewman DP, Soto AT. Sacroiliac joint dysfunction: diagnosis and treatment. Am Fam\nPhysician. 2022;105(3):239-245.\nTelli H, Telli S, Topal M. The validity and reliability of provocation tests in the diagnosis\nof sacroiliac joint dysfunction. Pain Physician. 2018;21(4):E367-E376."},{"n":194,"q":"Most elder abuse is perpetrated by","o":[{"l":"A","t":"family members"},{"l":"B","t":"friends"},{"l":"C","t":"nurses"},{"l":"D","t":"paid caregivers"},{"l":"E","t":"physicians"}],"a":"A","e":"Most elder abuse occurs in the home and is perpetrated by family members (90% of all\ncases). A small proportion of older adults live in nursing homes, with only 4% of abuse\nperpetrated by paid caregivers.\nRisk factors for elder abuse include shared living arrangements, increased age,\ndecreased physical health, cognitive impairment, disruptive behaviors, alcohol misuse,\nand social isolation. Caregiver characteristics associated with abuse include mental\nillness, substance abuse, and dependence on the victim (often financially).\nThere are validated screening instruments available, notably the Elder Abuse Suspicion\nIndex, but the U.S. Preventive Services Task Force has found insufficient evidence for\nscreening older adults for abuse and neglect when there are no recognized signs and\nsymptoms of abuse. Identification of elder abuse is a professional responsibility of\nfamily physicians. However, physicians report a very small number of elder abuse cases\n(1.4%). Family members, social service workers, friends, and law enforcement most\ncommonly report abuse. Most states mandate reporting of elder abuse but there is a\ndearth of training for physicians in recognizing elder abuse. Signs are often subtle and\nphysical findings are not always evident.\nReferences\nHoover RM, Polson M. Detecting elder abuse and neglect: assessment and intervention.\nAm Fam Physician. 2014;89(6):453-460.\nUS Preventive Services Task Force. Final recommendation statement: intimate partner\nviolence, elder abuse, and abuse of vulnerable adults: screening. October 23, 2018."},{"n":195,"q":"A 52-year-old male presents to the emergency department with a sudden onset of what he describes as the worst headache of his life. You are concerned about the possibility of an intracranial hemorrhage. After performing an examination to rule out neurologic deficits, which one of the following would be the most appropriate next step in evaluation?","o":[{"l":"A","t":"CT of the head without contrast"},{"l":"B","t":"CT of the head with contrast"},{"l":"C","t":"MRI of the head with and without contrast"},{"l":"D","t":"A lumbar puncture"}],"a":"A","e":"A patient describing a headache as the worst headache of their life can be a red-flag\nsymptom of an intracranial hemorrhage, and CT of the head without contrast is the\nrecommended next step in evaluation. Contrast should not be used because it can\nobscure the signs of bleeding. If a subarachnoid hemorrhage is suspected, CT of the\nhead should be completed before performing a lumbar puncture to ensure there is no\nevidence of intracranial hemorrhage or midline shift.\nReferences\nHainer BL, Matheson EM. Approach to acute headache in adults. Am Fam Physician.\n2013;87(10):682-687.\nViera AJ, Antono B. Acute headache in adults: a diagnostic approach. Am Fam\nPhysician. 2022;106(3):260-268."},{"n":196,"q":"A 45-year-old male with a history of hypertension and poorly controlled anxiety and depression presents to your office to establish care. He requests refills of his current medications, which include the following: Alprazolam (Xanax), 0.5 mg nightly Buspirone, 10 mg 3 times daily Gabapentin (Neurontin), 600 mg 3 times daily Lorazepam (Ativan), 1 mg twice daily Losartan (Cozaar), 50 mg daily Sertraline (Zoloft), 200 mg daily You tell the patient that you will provide refills for buspirone, gabapentin, losartan, and sertraline without dosage adjustments; however, he will need to taper and ultimately discontinue the alprazolam and lorazepam. You both agree hospitalization is not necessary. After discussion, the patient agrees with your approach. In addition to cognitive behavioral therapy, which one of the following strategies would be most appropriate for this patient?","o":[{"l":"A","t":"Discontinuing both benzodiazepines and initiating buprenorphine maintenance therapy"},{"l":"B","t":"Discontinuing both benzodiazepines and initiating flumazenil maintenance therapy"},{"l":"C","t":"Discontinuing lorazepam now and gradually decreasing alprazolam over 6 months"},{"l":"D","t":"Tapering the alprazolam and lorazepam dosages simultaneously over 6 months"},{"l":"E","t":"Switching both alprazolam and lorazepam to diazepam (Valium), and then decreasing the diazepam dosage over 6 months"}],"a":"E","e":"Benzodiazepine prescriptions and overdoses have increased over the last 15 years and\nlong-term benzodiazepine use is rarely recommended. Current recommendations\ninclude the following: substitution of multiple benzodiazepines for a single longer-acting\nbenzodiazepine such as diazepam, tapering of medication over weeks to months, and\nuse of cognitive behavioral therapy. Buprenorphine is indicated for patients with opioid\nuse disorder and can be helpful for patients who are taking both opioids and\nbenzodiazepines. Flumazenil is an intravenous injection that is used for benzodiazepine\noverdoses and reversing benzodiazepine sedation. It is not used in maintenance\ntherapy for benzodiazepine cessation.\nReferences\nGuaiana G, Barbui C. Discontinuing benzodiazepines: best practices. Epidemiol Psychiatr\nSci. 2016;25(3):214-216.\nOgbonna CI, Lembke A. Tapering patients off of benzodiazepines. Am Fam Physician.\n2017;96(9):606-610.\nRobertson S, Peacock EE, Scott R. Benzodiazepine use disorder: common questions and\nanswers. Am Fam Physician. 2023;108(3):260-266.\nSoyka M. Treatment of benzodiazepine dependence. N Engl J Med. 2017;376(12):11471157."},{"n":197,"q":"A 15-year-old female is brought to your office in May with a 3-week history of nasal congestion, sneezing, and itchy eyes. She reports that these episodes occur every spring and last about 6 weeks. She has been taking oral cetirizine (Zyrtec) with no improvement. You initiate an intranasal corticosteroid. The patient returns for follow-up 4 weeks later and says that she has seen some improvement but is dissatisfied with her progress. The patient and her parent ask about further steps in diagnosis. Which one of the following would be the most appropriate next step in diagnosis?","o":[{"l":"A","t":"A CBC"},{"l":"B","t":"Skin allergen testing"},{"l":"C","t":"Serum allergy testing"},{"l":"D","t":"Chest radiography"},{"l":"E","t":"Sinus CT"}],"a":"B","e":"This patient most likely has seasonal allergic rhinitis that has not responded to empiric\ntreatment. The most appropriate next step in diagnosis is skin allergen testing. Serum\nallergy testing is more expensive and less specific than skin allergen testing. It also\ndoes not provide the immediate results of skin allergen testing.\nA CBC will likely show eosinophilia, given the patient\u2019s likely diagnosis of allergic rhinitis.\nHowever, this is a nonspecific finding. This patient likely does not have a true\nrespiratory illness such as pneumonia, so a chest x-ray would not be appropriate. Sinus\nCT likely will not lead to actionable management. It is also expensive and carries the\nrisk for radiation exposure, which needs to be weighed carefully in a pediatric patient.\nReferences\nSavard DJ, Ursua FG, Gaddey HL. Smell and taste disorders in primary care. Am Fam\nPhysician. 2023;108(3):240-248.\nSiddiqui ZA, Walker A, Pirwani MM, Tahiri M, Syed I. Allergic rhinitis: diagnosis and\nmanagement. Br J Hosp Med (Lond). 2022;83(2):1-9.\nWeaver-Agostoni J, Kosak Z, Bartlett S. Allergic rhinitis: rapid evidence review. Am Fam\nPhysician. 2023;107(5):466-473."},{"n":198,"q":"Which one of the following conditions is most likely to impair swallowing of both solids and liquids?","o":[{"l":"A","t":"Achalasia"},{"l":"B","t":"Eosinophilic esophagitis"},{"l":"C","t":"Esophageal cancer"},{"l":"D","t":"Esophageal stricture"},{"l":"E","t":"Schatzki ring"}],"a":"A","e":"Achalasia is a smooth muscle motility disorder that impairs swallowing of both solids\nand liquids. In contrast, anatomic causes of dysphagia that impede the lumen of the\nesophagus through mass effect or inflammation, such as eosinophilic esophagitis,\nesophageal cancer, esophageal stricture, and Schatzki rings, typically impair swallowing\nof solids but not liquids.\nReference\nAbdel Jalil AA, Katzka DA, Castell DO. Approach to the patient with dysphagia. Am J\nMed. 2015;128(10):1138.e17-1138.e23."},{"n":199,"q":"A 55-year-old male with a medical history of GERD and osteoarthritis presents to the emergency department 2 hours after a sudden onset of intense epigastric pain. He takes naproxen almost daily for joint pain. On examination the patient is noticeably pale. His vital signs include a blood pressure of 90/60 mm Hg and a pulse rate of 125 beats/min. He is exquisitely tender to palpation in his abdomen, particularly at the epigastrium. There is no fluid wave or hepatomegaly. You do not note any obvious stigmata of chronic liver disease. Which one of the following tests should be performed to assist in the diagnosis?","o":[{"l":"A","t":"Aortic ultrasonography"},{"l":"B","t":"Abdominal radiography"},{"l":"C","t":"Abdominal and pelvic CT"},{"l":"D","t":"Abdominal paracentesis"},{"l":"E","t":"Exploratory laparotomy"}],"a":"C","e":"This patient most likely has a perforated peptic ulcer and the recommended test is CT\nof the abdomen and pelvis. Aortic ultrasonography is not productive in this case, as the\npatient\u2019s symptoms are unlikely to be caused by an abdominal aortic aneurysm.\nAbdominal radiography lacks the definition to visualize a perforated peptic ulcer. This\npatient's abdomen is not distended, and it is unlikely that abdominal paracentesis will\nyield the diagnosis or be therapeutic. Exploratory laparotomy is excessive and\npremature, as CT is diagnostic and less invasive.\nReferences\nBhavsar AK, Gelner EJ, Shorma T. Common questions about the evaluation of acute\npelvic pain. Am Fam Physician. 2016;93(1):41-48.\nMorley EJ, Bracey A, Reiter M, Thode HC Jr, Singer AJ. Association of pain location with\ncomputed tomography abnormalities in emergency department patients with abdominal\npain. J Emerg Med. 2020;59(4):485-490.\nYew KS, George MK, Allred HB. Acute abdominal pain in adults: evaluation and\ndiagnosis. Am Fam Physician. 2023;107(6):585-596."},{"n":200,"q":"A 55-year-old male presents for evaluation of recent-onset tinnitus that has adversely affected his sleep and concentration. A physical examination including otoscopy is unremarkable. Which one of the following additional findings, if present, would be an indication for head imaging?","o":[{"l":"A","t":"Associated development of major depressive disorder"},{"l":"B","t":"Bilateral hearing loss on audiometry"},{"l":"C","t":"Lack of improvement with a trial of a tricyclic antidepressant"},{"l":"D","t":"A pulsatile quality of the tinnitus"},{"l":"E","t":"Symptom duration >6 months"}],"a":"D","e":"Tinnitus is a common problem that is experienced by up to 25% of adults, although\n<10% of affected individuals report bothersome symptoms that impair sleep, focus,\nemotions, or general quality of life. Audiometry should be performed for patients with\nsevere or persistent symptoms, as hearing loss is a common comorbid finding.\nEvaluation for potential structural causes with MRI or CT of the temporal bone is\nindicated for any of the following: a pulsatile quality of the tinnitus, unilateral tinnitus,\nasymmetric hearing loss, or focal neurologic findings. Of the options given in this clinical\nscenario, only pulsatile tinnitus would provide an indication for head imaging.\nWhile patients with tinnitus may be more susceptible to mood disturbances due to the\nadverse impact on quality of life and functioning that their symptoms may cause, an\nassociated onset of major depression would not provide a reason to order diagnostic\nhead imaging. Bilateral hearing loss on audiometry is often noted in the setting of\ntinnitus and does not suggest the presence of a structural lesion. No medication\nstrategies have proven effective to treat tinnitus; thus, prescribing a tricyclic\nantidepressant would not be expected to provide benefit. Symptoms often persist for\nmonths to years; the duration of symptoms alone does not provide a reason to order\nhead imaging.\n\nReference\nBauer CA. Tinnitus. N Engl J Med. 2018;378(13):1224-1231."}];

const ALL_EXAMS = {
  "2024": EXAM_2024
};

export default function App() {
  const [screen, setScreen] = useState("home");
  const [selectedYear, setSelectedYear] = useState(null);
  const [rangeStart, setRangeStart] = useState("");
  const [rangeEnd, setRangeEnd] = useState("");
  const [rangeError, setRangeError] = useState("");
  const [questions, setQuestions] = useState([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState(null);
  const [submitted, setSubmitted] = useState(false);
  const [results, setResults] = useState([]);
  const [showSummary, setShowSummary] = useState(false);
  const [displayRange, setDisplayRange] = useState("");

  const maxQ = selectedYear ? ALL_EXAMS[selectedYear]?.length || 0 : 0;

  const validateAndStart = () => {
    const s = parseInt(rangeStart);
    const e = parseInt(rangeEnd);
    if (isNaN(s) || isNaN(e)) {
      setRangeError("Enter valid numbers.");
      return;
    }
    if (s < 1 || e > maxQ || s > e) {
      setRangeError(`Enter a range between 1 and ${maxQ} where start ≤ end.`);
      return;
    }
    setRangeError("");
    const exam = ALL_EXAMS[selectedYear];
    const qs = exam.filter(q => q.n >= s && q.n <= e);
    if (qs.length === 0) {
      setRangeError("No questions found in that range.");
      return;
    }
    setDisplayRange(`Q${s}–${e}`);
    setQuestions(qs);
    setCurrentIdx(0);
    setSelectedAnswer(null);
    setSubmitted(false);
    setResults([]);
    setShowSummary(false);
    setScreen("quiz");
  };

  const handleSubmit = () => {
    if (selectedAnswer === null) return;
    setSubmitted(true);
    const q = questions[currentIdx];
    setResults(prev => [...prev, {
      num: q.n,
      selected: selectedAnswer,
      correct: q.a,
      isCorrect: selectedAnswer === q.a
    }]);
  };

  const handleNext = () => {
    if (currentIdx + 1 < questions.length) {
      setCurrentIdx(prev => prev + 1);
      setSelectedAnswer(null);
      setSubmitted(false);
    } else {
      setShowSummary(true);
    }
  };

  const goHome = () => {
    setScreen("home");
    setQuestions([]);
    setCurrentIdx(0);
    setSelectedAnswer(null);
    setSubmitted(false);
    setResults([]);
    setShowSummary(false);
  };

  // HOME SCREEN
  if (screen === "home") {
    const years = Object.keys(ALL_EXAMS);
    return (
      <div style={S.shell}>
        <div style={S.headerBar}/>
        <div style={S.heroWrap}>
          <h1 style={S.heroTitle}>ABFM Board Prep</h1>
          <p style={S.heroSub}>In-Training Examination Question Bank</p>
        </div>
        <div style={S.main}>
          {/* Year selection */}
          <label style={S.fieldLabel}>Exam Year</label>
          <div style={S.yearRow}>
            {years.map(y => (
              <button
                key={y}
                onClick={() => { setSelectedYear(y); setRangeError(""); }}
                style={selectedYear === y ? {...S.yearChip, ...S.yearChipOn} : S.yearChip}
              >
                {y}
                <span style={S.yearChipSub}>{ALL_EXAMS[y].length} Qs</span>
              </button>
            ))}
          </div>

          {/* Range selection */}
          {selectedYear && (
            <>
              <label style={{...S.fieldLabel, marginTop: 28}}>
                Question Range <span style={S.fieldHint}>(1–{maxQ})</span>
              </label>
              <div style={S.rangeRow}>
                <input
                  type="number"
                  min={1}
                  max={maxQ}
                  placeholder="Start"
                  value={rangeStart}
                  onChange={e => { setRangeStart(e.target.value); setRangeError(""); }}
                  style={S.rangeInput}
                />
                <span style={S.rangeDash}>to</span>
                <input
                  type="number"
                  min={1}
                  max={maxQ}
                  placeholder="End"
                  value={rangeEnd}
                  onChange={e => { setRangeEnd(e.target.value); setRangeError(""); }}
                  style={S.rangeInput}
                />
              </div>
              {rangeError && <p style={S.errorText}>{rangeError}</p>}

              {/* Quick-pick shortcuts */}
              <div style={S.quickRow}>
                {[[1,10],[11,20],[21,30],[31,40],[41,50],[51,60],[61,70],[71,80],[81,90],[91,100],
                  [101,110],[111,120],[121,130],[131,140],[141,150],[151,160],[161,170],[171,180],[181,190],[191,200]
                ].map(([a,b]) => (
                  <button
                    key={a}
                    style={S.quickChip}
                    onClick={() => { setRangeStart(String(a)); setRangeEnd(String(b)); setRangeError(""); }}
                  >
                    {a}–{b}
                  </button>
                ))}
              </div>

              <button style={S.goBtn} onClick={validateAndStart}>
                Start Questions
              </button>
            </>
          )}
        </div>
      </div>
    );
  }

  // SUMMARY SCREEN
  if (showSummary) {
    const correct = results.filter(r => r.isCorrect).length;
    const total = results.length;
    const pct = total > 0 ? Math.round((correct / total) * 100) : 0;
    return (
      <div style={S.shell}>
        <div style={S.headerBar}/>
        <div style={S.heroWrap}>
          <h1 style={S.heroTitle}>Session Complete</h1>
          <p style={S.heroSub}>{selectedYear} ITE — {displayRange}</p>
        </div>
        <div style={S.main}>
          <div style={S.scoreCard}>
            <div style={S.bigScore}>{pct}%</div>
            <div style={S.bigScoreSub}>{correct} of {total} correct</div>
          </div>
          <div style={S.resultsList}>
            {results.map((r, i) => (
              <div key={i} style={{
                ...S.resultRow,
                borderLeftColor: r.isCorrect ? '#22c55e' : '#ef4444'
              }}>
                <span style={S.resultQ}>Q{r.num}</span>
                <span style={{color: r.isCorrect ? '#4ade80' : '#f87171', fontWeight: 600, fontSize: 13}}>
                  {r.isCorrect ? 'Correct' : `Incorrect (${r.selected}) → ${r.correct}`}
                </span>
              </div>
            ))}
          </div>
          <button style={S.goBtn} onClick={goHome}>Back to Home</button>
        </div>
      </div>
    );
  }

  // QUIZ SCREEN
  const q = questions[currentIdx];
  if (!q) return null;
  const lastResult = results.length > 0 ? results[results.length - 1] : null;

  return (
    <div style={S.shell}>
      {/* Top bar */}
      <div style={S.quizTop}>
        <button style={S.pillBtn} onClick={goHome}>← Home</button>
        <span style={S.quizMeta}>{selectedYear} &middot; Q{q.n} &middot; {currentIdx+1}/{questions.length}</span>
        <span style={S.quizTally}>{results.filter(r=>r.isCorrect).length}/{results.length}</span>
      </div>
      <div style={S.trackOuter}>
        <div style={{...S.trackFill, width:`${((currentIdx+(submitted?1:0))/questions.length)*100}%`}}/>
      </div>

      <div style={S.quizBody}>
        {/* Question */}
        <div style={S.qLabel}>Question {q.n}</div>
        <p style={S.qText}>{q.q}</p>

        {/* Options */}
        <div style={S.optList}>
          {q.o.map(opt => {
            let st = {...S.opt};
            if (submitted) {
              if (opt.l === q.a) st = {...st, ...S.optRight};
              else if (opt.l === selectedAnswer) st = {...st, ...S.optWrong};
              else st = {...st, opacity: 0.45};
            } else if (selectedAnswer === opt.l) {
              st = {...st, ...S.optPicked};
            }
            return (
              <button key={opt.l} style={st} onClick={() => !submitted && setSelectedAnswer(opt.l)} disabled={submitted}>
                <span style={S.optLtr}>{opt.l}</span>
                <span>{opt.t}</span>
              </button>
            );
          })}
        </div>

        {/* Submit or Feedback */}
        {!submitted ? (
          <button
            style={selectedAnswer ? S.submitBtn : {...S.submitBtn, opacity: 0.35, cursor: 'default'}}
            onClick={handleSubmit}
            disabled={!selectedAnswer}
          >
            Submit Answer
          </button>
        ) : (
          <>
            <div style={{
              ...S.banner,
              background: lastResult?.isCorrect
                ? 'linear-gradient(135deg,#065f46,#047857)'
                : 'linear-gradient(135deg,#7f1d1d,#991b1b)'
            }}>
              {lastResult?.isCorrect ? '✓  Correct' : `✗  Incorrect — Answer is ${q.a}`}
            </div>
            <div style={S.critiqueBox}>
              <div style={S.critiqueHead}>Critique</div>
              {q.e.split('\n').map((ln,i) => ln.trim() ? <p key={i} style={S.critP}>{ln}</p> : null)}
            </div>
            <button style={S.nextBtn} onClick={handleNext}>
              {currentIdx+1 < questions.length ? 'Next Question →' : 'View Results'}
            </button>
          </>
        )}
      </div>
    </div>
  );
}

